def _uninstall_crash_handler(exc_type, exc_value, exc_tb):
    tb_str = ''.join(traceback.format_exception(exc_type, exc_value, exc_tb))
    try:
        os.makedirs(BACKUP_DIR, exist_ok=True)
        ts = _dt.datetime.now().strftime('%Y%m%d_%H%M%S')
        crash_path = os.path.join(BACKUP_DIR, f'uninstall_crash_{{ts}}.txt')
        with open(crash_path, 'w', encoding='utf-8') as _cf:
            _cf.write('V0RTEX Uninstall Crash \u2014 ' + ts + '\\n\\n' + tb_str)
    except Exception:
        crash_path = None
    try:
        _cw = tk.Toplevel()
        _cw.title('V0RTEX Uninstall — Crash')
        _cw.configure(bg='#0a0a12')
        _cw.resizable(True, True)
        _cw.geometry('700x420')
        _cw.attributes('-topmost', True)
        tk.Label(_cw, text='⚠  UNINSTALL CRASH', font=('Consolas',13,'bold'),
                 bg='#0a0a12', fg='#f38ba8').pack(pady=(16,4))
        _f = tk.Frame(_cw, bg='#11111b'); _f.pack(fill='both', expand=True, padx=14, pady=6)
        _sc = tk.Scrollbar(_f); _sc.pack(side='right', fill='y')
        _tx = tk.Text(_f, bg='#11111b', fg='#cdd6f4', font=('Consolas',8),
                      relief='flat', bd=0, padx=8, pady=6,
                      yscrollcommand=_sc.set, wrap='word')
        _sc.config(command=_tx.yview)
        _tx.pack(fill='both', expand=True)
        _tx.insert('1.0', tb_str)
        _tx.config(state='disabled')
        _bf = tk.Frame(_cw, bg='#0a0a12'); _bf.pack(fill='x', padx=14, pady=8)
        if crash_path:
            tk.Label(_bf, text=f'Log: {{os.path.basename(crash_path)}}',
                     font=('Consolas',7), bg='#0a0a12', fg='#6c7086').pack(side='left')
        tk.Button(_bf, text='  Close  ', command=_cw.destroy,
                  bg='#313244', fg='#cdd6f4', font=('Consolas',9),
                  relief='flat', bd=0, padx=10, pady=5, cursor='hand2').pack(side='right')
        try:
            _cw.grab_set()
        except Exception:
            pass
    except Exception:
        tmb.showerror('Uninstall Crash', tb_str[:800])

sys.excepthook = _uninstall_crash_handler

def _tk_error_handler(exc, val, tb):
    _uninstall_crash_handler(exc, val, tb)
try:
    root.report_callback_exception = _tk_error_handler
except Exception:
    pass

root.mainloop()
'''


def _build_reinstall_script(install_dir, python_exe, trampoline_code):
    T = repr(trampoline_code)
    return f'''
import tkinter as tk, tkinter.ttk as ttk, tkinter.filedialog as tfd, tkinter.messagebox as tmb
import os, sys, threading, subprocess, zipfile, tempfile, shutil, platform, traceback
import datetime as _dt

if sys.platform == "win32":
    try:
        import ctypes
        ctypes.windll.kernel32.FreeConsole()
    except Exception:
        pass

import subprocess as _subprocess_orig
_NW_FLAGS = {{"creationflags": 0x08000000}} if __import__("sys").platform == "win32" else {{}}
class _SubprocessSilencer:
    def __getattr__(self, name):
        orig = getattr(_subprocess_orig, name)
        if name in ("run", "check_output", "check_call"):
            def _wrap(*a, **kw):
                if "creationflags" not in kw: kw.update(_NW_FLAGS)
                return orig(*a, **kw)
            return _wrap
        if name == "Popen":
            def _popen_wrap(*a, **kw):
                if "creationflags" not in kw: kw.update(_NW_FLAGS)
                return orig(*a, **kw)
            return _popen_wrap
        return orig
    def __dir__(self): return dir(_subprocess_orig)
    PIPE = _subprocess_orig.PIPE
    DEVNULL = _subprocess_orig.DEVNULL
    STDOUT = _subprocess_orig.STDOUT
    TimeoutExpired = _subprocess_orig.TimeoutExpired
    CalledProcessError = _subprocess_orig.CalledProcessError
subprocess = _SubprocessSilencer()


try: sys.stdout.reconfigure(encoding='utf-8', errors='replace')
except Exception: pass

INSTALL_DIR  = r"{install_dir}"
PYTHON_EXE   = r"{python_exe}"
MEDIA_DIR    = os.path.join(os.path.dirname(INSTALL_DIR), 'installation_media')
SYSTEM_DIR   = os.path.dirname(INSTALL_DIR)
BACKUP_DIR   = os.path.join(os.path.dirname(SYSTEM_DIR), 'V0rtex_backups')
_TEMP        = tempfile.gettempdir()
_LOG_FILE    = os.path.join(BACKUP_DIR, 'v0rtex_reinstall.log')

C = dict(
    bg='#0a0a12', panel='#10101c', card='#16162a', border='#2a2a45',
    accent='#fbbf24', accent2='#fde68a',
    green='#22d3a0', yellow='#fbbf24', red='#f87171',
    muted='#4a4a6a', text='#e2e8f0', subtext='#94a3b8', dim='#4a4a6a',
)
TAG = dict(
    HEAD=(C['accent2'], None), OK=(C['green'], None),
    WARN=(C['yellow'], None), ERR=(C['red'], None),
    INFO=(C['subtext'], None), DIM=(C['dim'], None),
    NORM=(C['text'], None),
)

def _ts(): return _dt.datetime.now().strftime('%H:%M:%S.%f')
def _write_log(line):
    try:
        os.makedirs(BACKUP_DIR, exist_ok=True)
        with open(_LOG_FILE, 'a', encoding='utf-8') as _f: _f.write(line + '\\n')
    except Exception: pass

root = tk.Tk()
root.title('V0RTEX — Reinstall')
root.configure(bg=C['bg'])
root.resizable(False, False)
W, H = 720, 560
sw, sh = root.winfo_screenwidth(), root.winfo_screenheight()
root.geometry(f'{{W}}x{{H}}+{{(sw-W)//2}}+{{max((sh-H)//3, 20)}}')
root.protocol('WM_DELETE_WINDOW', lambda: sys.exit(0))

sty = ttk.Style(); sty.theme_use('default')
sty.configure('R.Horizontal.TProgressbar',
    troughcolor=C['card'], background=C['accent'],
    lightcolor=C['accent2'], darkcolor='#d97706', bordercolor=C['border'], thickness=6)
sty.configure('R.Green.Horizontal.TProgressbar',
    troughcolor=C['card'], background=C['green'],
    lightcolor=C['green'], darkcolor='#1aaf82', bordercolor=C['border'], thickness=5)

status_var   = tk.StringVar(value='Ready')
pct_var      = tk.StringVar(value='')
step_var     = tk.StringVar(value='')
step_pct     = tk.StringVar(value='')
v_backup          = tk.BooleanVar(value=True)
v_packages        = tk.BooleanVar(value=False)
v_buildtools      = tk.BooleanVar(value=False)
v_wipe_data       = tk.BooleanVar(value=False)
v_github_download = tk.BooleanVar(value=False)
log_w = [None]; dbg_w = [None]; bar_w = [None]; sbar_w = [None]; btn_start = [None]
_v0rtex_src  = [None]

import time as _anim_time
spinner_var   = tk.StringVar(value="")
elapsed_var   = tk.StringVar(value="")
heartbeat_var = tk.StringVar(value="")
activity_var  = tk.StringVar(value="")
_anim_active  = [False]
_anim_start_t = [0.0]
_anim_frame   = [0]
_pulse_dir    = [1]
_pulse_val    = [0.0]
_last_log_t   = [0.0]
_last_log_msg = [""]
_hb_lbl       = [None]
_SPINNER_FRAMES = ["\u280b","\u2819","\u2839","\u2838","\u283c","\u2834","\u2826","\u2827","\u2807","\u280f"]
_STALL_SECS   = 30

def _anim_tick():
    if not _anim_active[0]: return
    _anim_frame[0] = (_anim_frame[0] + 1) % len(_SPINNER_FRAMES)
    spinner_var.set(_SPINNER_FRAMES[_anim_frame[0]])
    elapsed = _anim_time.time() - _anim_start_t[0]
    m, s = divmod(int(elapsed), 60)
    elapsed_var.set(f"{{m:02d}}:{{s:02d}}")
    sb = sbar_w[0]
    if sb and float(sb["value"]) < 1.0:
        _pulse_val[0] += 0.7 * _pulse_dir[0]
        if _pulse_val[0] >= 18: _pulse_dir[0] = -1
        elif _pulse_val[0] <= 0: _pulse_dir[0] = 1; _pulse_val[0] = 0
        try: sb["value"] = _pulse_val[0]
        except Exception: pass
    else:
        _pulse_val[0] = 0.0; _pulse_dir[0] = 1
    if _last_log_t[0] > 0:
        since = _anim_time.time() - _last_log_t[0]
        if since < _STALL_SECS:
            heartbeat_var.set("\u25cf LIVE")
            if _hb_lbl[0]:
                try: _hb_lbl[0].config(fg=C["green"])
                except Exception: pass
        else:
            sm, ss = divmod(int(since), 60)
            heartbeat_var.set(f"\u26a0 NO ACTIVITY  {{sm:02d}}:{{ss:02d}}")
            if _hb_lbl[0]:
                try: _hb_lbl[0].config(fg=C["yellow"])
                except Exception: pass
        if _last_log_msg[0]:
            activity_var.set(f"last: {{_last_log_msg[0]}}")
    root.after(100, _anim_tick)

def _anim_start():
    _anim_active[0] = True
    _anim_start_t[0] = _anim_time.time()
    _last_log_t[0]   = _anim_time.time()
    _anim_frame[0] = 0
    root.after(100, _anim_tick)

def _anim_stop():
    _anim_active[0] = False
    spinner_var.set("\u2713")
    heartbeat_var.set("\u25cf DONE")
    if _hb_lbl[0]:
        try: _hb_lbl[0].config(fg=C["green"])
        except Exception: pass


def _log(msg, tag='NORM'):
    if _anim_active[0] and msg.strip():
        _last_log_t[0] = _anim_time.time()
        _last_log_msg[0] = msg.strip()[:60]
    def _do():
        w = log_w[0]
        if not w: return
        w.config(state='normal'); w.insert('end', msg + '\\n', tag)
        w.see('end'); w.config(state='disabled'); _write_log(msg)
    try: root.after(0, _do)
    except Exception: pass

def _dlog(msg):
    def _do():
        w = dbg_w[0]
        if not w: return
        line = f'[{{_ts()}}] {{msg}}'
        w.config(state='normal'); w.insert('end', line + '\\n', 'DIM')
        w.see('end'); w.config(state='disabled'); _write_log(f'[DBG] {{msg}}')
    try: root.after(0, _do)
    except Exception: pass

def _prog(pct, st=None):
    def _do():
        b = bar_w[0]
        if b: b['value'] = pct
        if st: status_var.set(st)
        pct_var.set(f'{{int(pct)}}%' if pct else '')
    try: root.after(0, _do)
    except Exception: pass

def _sprog(pct, st=None):
    def _do():
        b = sbar_w[0]
        if b: b['value'] = pct
        if st: step_var.set(st)
        step_pct.set(f'{{int(pct)}}%' if pct else '')
    try: root.after(0, _do)
    except Exception: pass

def _set_done(ok, close_after=3000):
    _anim_stop()
    def _do():
        b = btn_start[0]
        if not b: return
        b.config(text='  ✓  Reinstall started — closing…  ' if ok else '  ✗  Failed  ',
                 bg=C['green'] if ok else C['red'], fg=C['bg'], state='disabled')
        if ok: root.after(close_after, lambda: sys.exit(0))
    try: root.after(0, _do)
    except Exception: pass

def _rmdir(path, tag):
    import time as _rt, gc as _gc
    if not os.path.exists(path):
        _dlog(f'~ Already gone: {{path}}'); return True
    _gc.collect()
    if sys.platform == 'win32':
        try:
            import psutil as _psu
            cur = os.getpid()
            for _p in _psu.process_iter(['pid','exe','open_files']):
                try:
                    if _p.pid == cur: continue
                    for _of in (_p.open_files() or []):
                        if _of.path.startswith(path):
                            _p.kill(); break
                except Exception: pass
        except Exception: pass
    for _attempt in range(4):
        try:
            shutil.rmtree(path, ignore_errors=True)
        except Exception: pass
        if not os.path.exists(path):
            _log(f'  ✓ Removed {{tag}}', 'OK'); return True
        if sys.platform == 'win32':
            try:
                subprocess.run(['cmd', '/c', 'rmdir', '/s', '/q', path],
                               capture_output=True, timeout=30)
            except Exception: pass
            if not os.path.exists(path):
                _log(f'  ✓ Removed {{tag}} (cmd)', 'OK'); return True
        if _attempt < 3:
            _dlog(f'rmdir attempt {{_attempt+1}} failed — retrying in 600ms…')
            _rt.sleep(0.6)
    _log(f'  ~ Could not fully remove {{tag}} — some files may be locked', 'WARN')
    return False

def _resolve_v0rtex_src():
    candidates = [
        os.path.join(INSTALL_DIR, 'v0rtex.py'),
        os.path.join(os.path.dirname(INSTALL_DIR), 'v0rtex.py'),
        os.path.join(os.path.dirname(os.path.dirname(INSTALL_DIR)), 'v0rtex.py'),
        os.path.join(os.path.dirname(os.path.abspath(sys.argv[0])), 'v0rtex.py'),
    ]
    for c in candidates:
        try:
            if os.path.isfile(c):
                _v0rtex_src[0] = c
                _dlog(f'v0rtex.py found at: {{c}}')
                return True
        except Exception:
            pass
    searched = '\\n'.join(f'  - {{c}}' for c in candidates)
    ans = tmb.askyesno(
        'v0rtex.py not found',
        'Could not locate v0rtex.py automatically.\\n\\nSearched:\\n' + searched + '\\n\\nBrowse manually?',
        parent=root)
    if not ans:
        tmb.showwarning('Reinstall cancelled',
            'Reinstall aborted.\\n\\nTo fix: copy v0rtex.py into the V0rtex_System folder, then retry.',
            parent=root)
        return False
    p = tfd.askopenfilename(
        title='Locate v0rtex.py',
        parent=root,
        filetypes=[('Python script', '*.py'), ('All files', '*.*')])
    if p and os.path.isfile(p):
        _v0rtex_src[0] = p
        _dlog(f'v0rtex.py manually selected: {{p}}')
        return True
    tmb.showerror('Reinstall', 'No valid v0rtex.py selected — reinstall cancelled.', parent=root)
    return False

def _do_reinstall():
    do_bk   = v_backup.get()
    do_pkg  = v_packages.get()
    do_bt   = v_buildtools.get()
    do_wipe = v_wipe_data.get()
    src    = _v0rtex_src[0]
    if not src or not os.path.isfile(src):
        root.after(0, lambda: tmb.showerror('Reinstall',
            'v0rtex.py not found:\\n' + str(src) + '\\n\\nCannot proceed.', parent=root))
        root.after(0, lambda: btn_start[0].config(state='normal', text='  ♻  REINSTALL  '))
        return
    root.after(0, lambda: [w.config(state='disabled') for w in _opts_widgets])
    root.after(0, lambda: btn_start[0].config(state='disabled', text='  Working…  '))

    _dlog(f'Reinstall started — v0rtex.py={{src}}')
    _dlog(f'BACKUP_DIR={{BACKUP_DIR}}')
    try: os.makedirs(BACKUP_DIR, exist_ok=True)
    except Exception as e: _dlog(f'BACKUP_DIR create error: {{e}}')

    steps = 4 + (1 if do_bk else 0) + (1 if do_bt else 0) + (1 if do_pkg else 0) + (1 if do_wipe else 0)
    n = [1]

    _log(f'\\n[ {{n[0]}} / {{steps}} ]  Backup', 'HEAD'); n[0] += 1
    _prog(8, 'Backup…')
    if do_bk and os.path.exists(INSTALL_DIR):
        _sprog(0, 'creating ZIP…')
        try:
            ts  = _dt.datetime.now().strftime('%Y%m%d_%H%M%S')
            bk  = os.path.join(BACKUP_DIR, f'v0rtex_pre_reinstall_{{ts}}.zip')
            added = 0
            with zipfile.ZipFile(bk, 'w', zipfile.ZIP_DEFLATED) as zf:
                for dp, dirs, files in os.walk(INSTALL_DIR):
                    dirs[:] = [d for d in dirs if d not in {{'__pycache__', '.git'}}]
                    for fn in files:
                        fp = os.path.join(dp, fn)
                        try: zf.write(fp, os.path.relpath(fp, INSTALL_DIR)); added += 1
                        except Exception: pass
            _log(f'  ✓ {{os.path.basename(bk)}}  ({{added}} files)', 'OK')
            _dlog(f'Backup OK: {{bk}}')
            _sprog(100, '')
        except Exception as e:
            _log(f'  ✗ Backup failed: {{e}}', 'ERR'); _dlog(f'Backup error: {{e}}')
    else:
        _log('  ~ Backup skipped', 'DIM'); _sprog(100, '')

    _log(f'\\n[ {{n[0]}} / {{steps}} ]  Python packages', 'HEAD'); n[0] += 1
    _prog(20, 'Packages…')
    if do_pkg:
        _req = os.path.join(INSTALL_DIR, 'requirements.txt')
        if os.path.exists(_req):
            _pkgs = [l.strip() for l in open(_req, encoding='utf-8', errors='replace')
                     if l.strip() and not l.startswith('#')]
            _dlog(f'{{len(_pkgs)}} packages to remove')
            for i, _pkg in enumerate(_pkgs):
                _sprog(int(i / max(len(_pkgs),1) * 100), f'removing {{_pkg[:20]}}…')
                try:
                    _r = subprocess.run([PYTHON_EXE, '-m', 'pip', 'uninstall', '-y', _pkg],
                                        capture_output=True, text=True, timeout=60)
                    _dlog(f'  {{_pkg}} exit={{_r.returncode}}')
                except Exception as _pe: _dlog(f'  {{_pkg}} error: {{_pe}}')
            _log(f'  ✓ {{len(_pkgs)}} package(s) removed', 'OK')
        else:
            _log('  ~ requirements.txt not found', 'WARN')
        _sprog(100, '')
    else:
        _log('  ~ Package removal skipped', 'DIM')

    _log(f'\\n[ {{n[0]}} / {{steps}} ]  VS Build Tools', 'HEAD'); n[0] += 1
    _prog(35, 'Build tools…')
    if do_bt:
        _sprog(0, 'removing…')
        try:
            if shutil.which('winget'):
                _r = subprocess.run(['winget', 'uninstall', '--id',
                    'Microsoft.VisualStudio.2022.BuildTools',
                    '--silent', '--accept-source-agreements'],
                    capture_output=True, text=True, timeout=300)
                _dlog(f'winget exit={{_r.returncode}}')
                if _r.returncode in (0, -1978335189):
                    _log('  ✓ VS Build Tools uninstalled', 'OK')
                else:
                    _log(f'  ~ winget exit {{_r.returncode}} — Apps & Features', 'WARN')
            else:
                _log('  ~ winget not found — remove via Apps & Features', 'WARN')
        except Exception as e:
            _log(f'  ✗ Build tools error: {{e}}', 'ERR')
        _sprog(100, '')
    else:
        _log('  ~ Build tools removal skipped', 'DIM')

    _log(f'\\n[ {{n[0]}} / {{steps}} ]  Preparing v0rtex.py', 'HEAD'); n[0] += 1
    _prog(50, 'Preparing v0rtex.py…')
    v0tmp = os.path.join(_TEMP, 'v0rtex_fresh_install.py')
    _downloaded = False

    if v_github_download.get():
        try:
            _dlog('GitHub download enabled — fetching latest…')
            _log('  → Downloading latest from GitHub…', 'INFO')
            import urllib.request as _ur
            _req2 = _ur.Request('https://raw.githubusercontent.com/Vider06/V0RTEX/main/v0rtex.py', headers={{'User-Agent': 'V0RTEX-Reinstall/1.0'}})
            with _ur.urlopen(_req2, timeout=30) as _resp:
                _remote = _resp.read().decode('utf-8', 'replace')
            if len(_remote) < 10000:
                raise ValueError(f'Download too small ({{len(_remote)}} bytes) — likely an error page')
            with open(v0tmp, 'w', encoding='utf-8') as _vf:
                _vf.write(_remote)
            _log(f'  ✓ Downloaded latest from GitHub ({{len(_remote):,}} bytes)', 'OK')
            _dlog(f'GitHub download OK → {{v0tmp}}')
            _downloaded = True
        except Exception as _de:
            _log(f'  ✗ GitHub download failed: {{_de}}', 'ERR')
            _log('  → Falling back to current local file…', 'WARN')
            _dlog(f'Download error: {{_de}}')

    if not _downloaded:
        try:
            import shutil as _shu_cp
            _current = os.path.abspath(sys.argv[0])
            _dlog(f'Copying current file: {{_current}} → {{v0tmp}}')
            _shu_cp.copy2(_current, v0tmp)
            _log(f'  ✓ Current v0rtex.py copied to TEMP', 'OK')
            _dlog(f'Local copy OK → {{v0tmp}}')
        except Exception as e:
            _log(f'  ✗ Could not copy current file: {{e}} — aborting', 'ERR')
            _dlog(f'ABORT: {{e}}'); _set_done(False)
            root.after(0, lambda: btn_start[0].config(state='normal', text='  ♻  REINSTALL  '))
            return
    _log(f'\\n[ {{n[0]}} / {{steps}} ]  Removing old installation', 'HEAD'); n[0] += 1
    _prog(65, 'Removing folders…')
    _sprog(0, 'removing app folder…')
    _rmdir(INSTALL_DIR, 'app folder')
    _sprog(50, 'removing media folder…')
    _rmdir(MEDIA_DIR, 'media folder')
    _sprog(100, '')

    if do_wipe:
        _log(f'\\n[ {{n[0]}} / {{steps}} ]  Wiping user data', 'HEAD'); n[0] += 1
        _prog(78, 'Wiping user data…')
        _system_dir = os.path.dirname(INSTALL_DIR)
        _wipe_targets = [
            os.path.join(_system_dir, 'scan_history.db'),
            os.path.join(_system_dir, 'config.json'),
            os.path.join(_system_dir, 'whitelist.txt'),
            os.path.join(_system_dir, 'notes.txt'),
            os.path.join(_system_dir, 'reports'),
            os.path.join(_system_dir, 'rules'),
            os.path.join(_system_dir, 'quarantine'),
            os.path.join(_system_dir, 'debug_log'),
        ]
        for _wt in _wipe_targets:
            try:
                if os.path.isdir(_wt):
                    shutil.rmtree(_wt, ignore_errors=True)
                    _log(f'  ✓ wiped dir: {{os.path.basename(_wt)}}', 'OK')
                elif os.path.isfile(_wt):
                    os.remove(_wt)
                    _log(f'  ✓ wiped file: {{os.path.basename(_wt)}}', 'OK')
            except Exception as _we:
                _log(f'  ~ could not wipe {{os.path.basename(_wt)}}: {{_we}}', 'WARN')
        _sprog(100, '')


    _log(f'\\n[ {{n[0]}} / {{steps}} ]  Launching fresh setup', 'HEAD'); n[0] += 1
    _prog(88, 'Launching V0RTEX…')
    _dlog(f'Launching: {{PYTHON_EXE}} {{v0tmp}}')
    try:
        if sys.platform == 'win32':
            subprocess.Popen(
                ['cmd', '/c', 'start', '', PYTHON_EXE, v0tmp],
                creationflags=0x08000000,
                close_fds=True,
            )
        else:
            subprocess.Popen([PYTHON_EXE, v0tmp])
        _log('  ✓ V0RTEX setup wizard launched', 'OK')
        _dlog('Launch OK')
    except Exception as e:
        _log(f'  ✗ Launch failed: {{e}}', 'ERR')
        _log(f'  → Run manually: {{PYTHON_EXE}} "{{v0tmp}}"', 'WARN')
        _dlog(f'Launch error: {{e}}')

    import time as _wait_launch; _wait_launch.sleep(2.0)
    try:
        if os.path.exists(v0tmp):
            os.remove(v0tmp)
            _dlog('Temp copy deleted')
    except Exception as _rme:
        _dlog(f'Could not delete temp copy: {{_rme}}')

    _prog(100, 'Reinstall complete!')
    _log('', 'NORM')
    _log('━' * 38, 'HEAD')
    _log('  ✓  Reinstall complete', 'OK')
    _log(f'  Backup → {{BACKUP_DIR}}', 'INFO')
    _log('  This window closes in 3 seconds', 'DIM')
    _log('━' * 38, 'HEAD')
    _dlog('Reinstall worker done')
    _set_done(True, close_after=3000)

