    script_dir   = os.path.dirname(os.path.abspath(sys.argv[0]))
    dir_var.set(os.path.join(script_dir, "V0rtex_System", "V0RTEX_v0.9.7.X2"))

    log_widget           = [None]
    dbg_widget           = [None]
    bar_widget           = [None]
    step_bar             = [None]
    btn_install          = [None]
    btn_launch           = [None]
    install_path         = [None]
    step_pct_var         = tk.StringVar(value="")
    step_status_var      = tk.StringVar(value="")
    import_backup_var    = tk.BooleanVar(value=False)
    import_backup_path   = tk.StringVar(value="")

    spinner_var      = tk.StringVar(value="")
    elapsed_var      = tk.StringVar(value="")
    heartbeat_var    = tk.StringVar(value="")
    activity_var     = tk.StringVar(value="")
    _anim_active     = [False]
    _anim_start_t    = [0.0]
    _anim_frame      = [0]
    _pulse_dir       = [1]
    _pulse_val       = [0.0]
    _last_act_t      = [0.0]
    _last_act_msg    = [""]
    _ops_queue       = []
    _OPS_MAX         = 8
    _SPINNER_FRAMES  = ["⠋", "⠙", "⠹", "⠸", "⠼", "⠴", "⠦", "⠧", "⠇", "⠏"]
    _STALL_SECS      = 45
    _ops_text        = [None]

    def _record_activity(msg=""):
        """Call this from any helper that means the setup is doing something."""
        if not _anim_active[0]:
            return
        _last_act_t[0] = time.time()
        if msg:
            clean = msg.strip()
            if clean:
                _last_act_msg[0] = clean[:70]
                _ops_queue.append(clean)
                if len(_ops_queue) > _OPS_MAX * 3:
                    _ops_queue.pop(0)

    def _anim_tick():
        if not _anim_active[0]:
            return
        _anim_frame[0] = (_anim_frame[0] + 1) % len(_SPINNER_FRAMES)
        spinner_var.set(_SPINNER_FRAMES[_anim_frame[0]])
        elapsed = time.time() - _anim_start_t[0]
        m, s = divmod(int(elapsed), 60)
        elapsed_var.set(f"{m:02d}:{s:02d}")

        sb = step_bar[0]
        if sb and float(sb["value"]) < 1.0:
            _pulse_val[0] += 0.7 * _pulse_dir[0]
            if _pulse_val[0] >= 18: _pulse_dir[0] = -1
            elif _pulse_val[0] <= 0: _pulse_dir[0] = 1; _pulse_val[0] = 0
            try: sb["value"] = _pulse_val[0]
            except Exception: pass
        else:
            _pulse_val[0] = 0.0; _pulse_dir[0] = 1

        if _last_act_t[0] > 0:
            since = time.time() - _last_act_t[0]
            if since < _STALL_SECS:
                heartbeat_var.set("● LIVE")
                if _hb_lbl[0]:
                    try: _hb_lbl[0].config(fg=C["green"])
                    except Exception: pass
            else:
                sm, ss = divmod(int(since), 60)
                heartbeat_var.set(f"⚠ NO ACTIVITY  {sm:02d}:{ss:02d}")
                if _hb_lbl[0]:
                    try: _hb_lbl[0].config(fg=C["yellow"])
                    except Exception: pass
            if _last_act_msg[0]:
                activity_var.set(f"↳ {_last_act_msg[0]}")

        _ops_w = _ops_text[0]
        if _ops_w and _ops_queue:
            try:
                visible = _ops_queue[-_OPS_MAX:]
                _ops_w.config(state="normal")
                _ops_w.delete("1.0", "end")
                for _ol in visible:
                    _ops_w.insert("end", _ol + "\n")
                _ops_w.see("end")
                _ops_w.config(state="disabled")
            except Exception:
                pass

        root.after(150, _anim_tick)

    def _anim_start_fn():
        _anim_active[0] = True
        _anim_start_t[0] = time.time()
        _last_act_t[0]   = time.time()
        _anim_frame[0] = 0
        root.after(150, _anim_tick)

    def _anim_stop_fn():
        _anim_active[0] = False
        spinner_var.set("✓")
        heartbeat_var.set("● DONE")
        if _hb_lbl[0]:
            try: _hb_lbl[0].config(fg=C["green"])
            except Exception: pass

    _hb_lbl = [None]

    _TAG_COLORS = dict(
        HEAD=(C["accent2"], None), OK=(C["green"], None),
        WARN=(C["yellow"], None), ERR=(C["red"], None),
        INFO=(C["subtext"], None), DIM=(C["dim"], None),
        NORM=(C["text"], None),
    )

    def _log(msg, tag="NORM"):
        w = log_widget[0]
        if not w:
            return
        _record_activity(msg)
        def _push():
            w.config(state="normal")
            w.insert("end", msg + "\n", tag)
            w.see("end")
            w.config(state="disabled")
        root.after(0, _push)

    def _prog(pct, status=""):
        _record_activity(status)
        def _push():
            try:
                if bar_widget[0]:
                    bar_widget[0]["value"] = pct
                pct_var.set(f"{int(pct)}%")
                if status:
                    status_var.set(status)
            except Exception:
                pass
        root.after(0, _push)

    def _wf(path, data, binary=False):
        os.makedirs(os.path.dirname(path) or ".", exist_ok=True)
        if binary:
            with open(path, "wb") as f: f.write(data)
        else:
            with open(path, "w", encoding="utf-8") as f: f.write(data)

    def _scan_existing(base):
        _check = {
            "config.json":                  os.path.join(base, "config.json"),
            "scan_history.db":              os.path.join(base, "scan_history.db"),
            "requirements.txt":             os.path.join(base, "requirements.txt"),
            "whitelist.txt":                os.path.join(base, "whitelist.txt"),
            "modules/__init__.py":          os.path.join(base, "modules", "__init__.py"),
            "modules/pe_analysis.py":       os.path.join(base, "modules", "pe_analysis.py"),
            "modules/wireshark.py":         os.path.join(base, "modules", "wireshark.py"),
            "rules/rules_state.json":       os.path.join(base, "rules", "rules_state.json"),
            "v0rtex.py":                    os.path.join(base, "v0rtex.py"),
        }
        return {k: os.path.exists(v) for k, v in _check.items()}

    def _find_existing_base():
        script_dir = os.path.dirname(os.path.abspath(sys.argv[0]))
        _SKIP = {".git", "__pycache__", "node_modules"}
        _MARKERS = ["config.json", "scan_history.db",
                    os.path.join("modules", "pe_analysis.py")]
        for dirpath, dirs, _ in os.walk(script_dir):
            dirs[:] = [d for d in dirs if d not in _SKIP]
            if sum(1 for m in _MARKERS if os.path.exists(os.path.join(dirpath, m))) >= 2:
                return dirpath
        return None

    def _dlog(msg, tag="NORM"):
        """Write a line to the debug log panel (right side)."""
        _record_activity(msg)
        w = dbg_widget[0]
        if not w:
            return
        def _push():
            w.config(state="normal")
            w.insert("end", msg + "\n", tag)
            w.see("end")
            w.config(state="disabled")
        root.after(0, _push)

    def _step_prog(pct, status=""):
        """Update the green per-step progress bar."""
        _record_activity(status)
        def _push():
            if step_bar[0]:
                step_bar[0]["value"] = pct
            if step_status_var:
                step_status_var.set(status)
            if step_pct_var:
                step_pct_var.set(f"{int(pct)}%" if pct else "")
        root.after(0, _push)

    def _install(base):
        import traceback as _tb
                                                                      
        _NW = ({"creationflags": 0x08000000, "close_fds": True}
               if sys.platform == "win32" else {})
        def _sp_run(*a, **kw):
            if sys.platform == "win32" and "creationflags" not in kw:
                kw.setdefault("creationflags", 0x08000000)
            return subprocess.run(*a, **kw)
        def _sp_popen(*a, **kw):
            if sys.platform == "win32" and "creationflags" not in kw:
                kw.setdefault("creationflags", 0x08000000)
            return subprocess.Popen(*a, **kw)
        def _sp_check_output(*a, **kw):
            if sys.platform == "win32" and "creationflags" not in kw:
                kw.setdefault("creationflags", 0x08000000)
            return subprocess.check_output(*a, **kw)

        try:
            _log(f">_ Target: {base}", "DIM")
            _dlog(f"Python: {sys.version}", "DIM")
            _dlog(f"Executable: {sys.executable}", "DIM")
            _dlog(f"Platform: {platform.system()} {platform.release()}", "DIM")
            _dlog(f"Install path: {base}", "DIM")
            _log("", "NORM")

            _manifest = {
                "install_dir":      base,
                "python_exe":       sys.executable,
                "platform":         platform.system(),
                "pkgs_installed":   [],
                "vs_build_tools":   False,
                "defender_exclusions": {
                    "paths": [], "processes": [], "cfa": []
                },
                "files_created":    [],
                "dirs_created":     [],
            }

            _outer_makedirs = os.makedirs

            def _wf_track(path, data, binary=False):
                """Write a file AND record it in the manifest."""
                _wf(path, data, binary)
                if path not in _manifest["files_created"]:
                    _manifest["files_created"].append(path)

            def _tracked_makedirs(path, mode=0o777, exist_ok=False, _om=_outer_makedirs):
                existed = os.path.isdir(path)
                _om(path, mode=mode, exist_ok=exist_ok)
                if not existed and path not in _manifest["dirs_created"]:
                    _manifest["dirs_created"].append(path)
            os.makedirs = _tracked_makedirs

            _log("[ 0 / 8 ]  Updating pip & checking packages", "HEAD")
            _step_prog(0, "checking pip…")
            _dlog("─── pip bootstrap ───", "INFO")

            _TRUSTED = [
                "--trusted-host", "pypi.org",
                "--trusted-host", "files.pythonhosted.org",
                "--trusted-host", "pypi.python.org",
            ]

            _pip_check = _sp_run(
                [sys.executable, "-m", "pip", "--version"],
                capture_output=True, text=True)
            _pip_missing = (_pip_check.returncode != 0 or
                            "No module named pip" in (_pip_check.stderr + _pip_check.stdout))

            if _pip_missing:
                _log("  ~ pip not found — bootstrapping…", "WARN")
                _dlog("pip missing — trying ensurepip", "WARN")
                _pip_bootstrapped = False

                _step_prog(15, "ensurepip bootstrap…")
                try:
                    import ensurepip as _ep
                    _ep.bootstrap(upgrade=True)
                    _ck2 = _sp_run(
                        [sys.executable, "-m", "pip", "--version"],
                        capture_output=True, text=True)
                    if _ck2.returncode == 0:
                        _log("  ✓ pip bootstrapped via ensurepip", "OK")
                        _dlog("ensurepip OK", "OK")
                        _pip_bootstrapped = True
                except Exception as _epe:
                    _dlog(f"ensurepip failed: {_epe}", "WARN")

                if not _pip_bootstrapped:
                    _step_prog(30, "ensurepip subprocess…")
                    _res_ep = _sp_run(
                        [sys.executable, "-m", "ensurepip", "--upgrade"],
                        capture_output=True, text=True)
                    _ck3 = _sp_run(
                        [sys.executable, "-m", "pip", "--version"],
                        capture_output=True, text=True)
                    if _ck3.returncode == 0:
                        _log("  ✓ pip bootstrapped via ensurepip (subprocess)", "OK")
                        _dlog("ensurepip subprocess OK", "OK")
                        _pip_bootstrapped = True
                    else:
                        _dlog(f"ensurepip subprocess: {_res_ep.stderr.strip()[-200:]}", "WARN")

                if not _pip_bootstrapped:
                    _step_prog(50, "downloading get-pip.py…")
                    _log("  ~ ensurepip unavailable — downloading get-pip.py…", "WARN")
                    _dlog("trying get-pip.py download", "WARN")
                    import tempfile as _tmp, os as _tos
                    _getpip_path = _tos.path.join(
                        _tmp.gettempdir(), "get-pip.py")
                    _downloaded = False
                    for _getpip_url in [
                        "https://bootstrap.pypa.io/get-pip.py",
                        "https://bootstrap.pypa.io/pip/get-pip.py",
                    ]:
                        try:
                            import urllib.request as _ur
                            _ur.urlretrieve(_getpip_url, _getpip_path)
                            if _tos.path.getsize(_getpip_path) > 1000:
                                _downloaded = True
                                _dlog(f"get-pip.py downloaded from {_getpip_url}", "OK")
                                break
                        except Exception as _de:
                            _dlog(f"download {_getpip_url}: {_de}", "WARN")

                    if _downloaded:
                        _step_prog(65, "running get-pip.py…")
                        _rg = _sp_run(
                            [sys.executable, _getpip_path, "--no-warn-script-location",
                             "--quiet"] + _TRUSTED,
                            capture_output=True, text=True)
                        _ck4 = _sp_run(
                            [sys.executable, "-m", "pip", "--version"],
                            capture_output=True, text=True)
                        if _ck4.returncode == 0:
                            _log("  ✓ pip installed via get-pip.py", "OK")
                            _dlog("get-pip.py OK", "OK")
                            _pip_bootstrapped = True
                        else:
                            _dlog(f"get-pip.py failed: {_rg.stderr.strip()[-200:]}", "WARN")
                    else:
                        _dlog("get-pip.py download failed (offline?)", "WARN")

                if not _pip_bootstrapped:
                    _log("  ✗ Could not install pip — packages will be unavailable.", "ERR")
                    _dlog("pip bootstrap FAILED — all package installs will fail", "ERR")
                else:
                    _pip_missing = False

            if not _pip_missing:
                _step_prog(75, "upgrading pip…")
                _dlog("─── pip self-upgrade ───", "INFO")
                _r0 = _sp_run(
                    [sys.executable, "-m", "pip", "install", "--upgrade", "pip",
                     "--no-cache-dir", "--quiet"] + _TRUSTED,
                    capture_output=True, text=True)
                if _r0.returncode == 0:
                    _log("  ✓ pip up to date", "OK")
                    _dlog("pip upgrade: OK", "OK")
                else:
                    _log("  ~ pip upgrade skipped", "DIM")
                    _err_msg = (_r0.stderr or _r0.stdout or "").strip()
                    _dlog(f"pip upgrade warn: {_err_msg[-300:]}", "WARN")

            _step_prog(40, "checking outdated packages…")

            _dlog("─── outdated check ───", "INFO")
            _r_out = _sp_run(
                [sys.executable, "-m", "pip", "list", "--outdated", "--format=columns"],
                capture_output=True, text=True)
            if _r_out.returncode == 0 and _r_out.stdout.strip():
                lines = _r_out.stdout.strip().splitlines()
                outdated = [l for l in lines[2:] if l.strip()]
                if outdated:
                    _log(f"  ↑ {len(outdated)} package(s) have updates available", "INFO")
                    for ol in outdated[:12]:
                        _dlog(f"  outdated: {ol}", "WARN")
                else:
                    _log("  ✓ all installed packages are current", "OK")
                    _dlog("no outdated packages found", "DIM")
            else:
                _dlog(f"outdated check skipped: {_r_out.stderr.strip()[-100:]}", "DIM")
            _step_prog(100, "pip ready")
            _prog(5, "pip updated")
            _log("", "NORM")

            existing_base = _find_existing_base()
            existing      = _scan_existing(base)
            found_count   = sum(existing.values())
            total_markers = len(existing)
            already_done  = found_count >= (total_markers - 2)

            if already_done:
                _log("━"*52, "HEAD")
                _log("  ✓  Installation already found!", "OK")
                _log(f"  ✓  Location: {existing_base or base}", "OK")
                _log("", "NORM")
                _log("  Detected components:", "INFO")
                for rel, found in existing.items():
                    tag = "OK" if found else "WARN"
                    sym = "✓" if found else "✗ missing"
                    _log(f"    {sym}  {rel}", tag)
                _log("", "NORM")
                _prog(40, "Integrating existing installation…")

                _dlog("sentinel deferred — will be written after Defender step", "DIM")

                _log("", "NORM")
                _log("  Filling in any missing pieces…", "INFO")
                _prog(50, "Checking missing components…")

            if not already_done:
                _log("[ 1 / 8 ]  Creating directory tree", "HEAD")
            else:
                _log("[ 1 / 8 ]  Verifying directory tree", "HEAD")
            _step_prog(0, "creating dirs…")
            os.makedirs(base, exist_ok=True)
            for sub in _SUBDIRS:
                p = os.path.join(base, sub.replace("/", os.sep))
                os.makedirs(p, exist_ok=True)
            for sub in ("rules","rules/external","quarantine","reports",
                        "debug_log","backups","_recovery","sandbox_env/drop"):
                kp = os.path.join(base, sub.replace("/",os.sep), ".keep")
                if not os.path.exists(kp):
                    open(kp, "w").close()
            _log("  ✓ Directory tree OK", "OK")
            _dlog(f"dirs OK: {len(_SUBDIRS)} subdirs under {base}", "DIM")
            _prog(12 if not already_done else 58, "Checking embedded files…")

            _log("", "NORM")
            _log("[ 2 / 8 ]  Embedded files", "HEAD")
            _step_prog(0, "writing embedded files…")
            _dlog(f"─── {len(_EMBED)} embedded assets ───", "INFO")
            for rel, b64 in _EMBED.items():
                dst = os.path.join(base, rel.replace("/", os.sep))
                if os.path.exists(dst):
                    _log(f"  ~ {rel}  (already present, kept)", "DIM")
                    _dlog(f"skip: {rel}", "DIM")
                else:
                    _data = base64.b64decode(b64)
                    _wf_track(dst, _data, binary=True)
                    _log(f"  ✓ {rel}  (written)", "OK")
                    _dlog(f"wrote: {rel} ({len(_data)} bytes)", "OK")
            for rel_path, content in [
                (os.path.join("modules", "__init__.py"), ""),
                ("whitelist.txt",                        ""),
                ("notes.txt",                            ""),
                ("requirements.txt",                     _REQUIREMENTS),
            ]:
                dst = os.path.join(base, rel_path)
                if os.path.exists(dst):
                    _log(f"  ~ {rel_path}  (already present, kept)", "DIM")
                else:
                    _wf_track(dst, content)
                    _log(f"  ✓ {rel_path}  (written)", "OK")
            _prog(22 if not already_done else 62, "Checking config & DB…")

            _log("", "NORM")
            _log("[ 3 / 8 ]  config.json", "HEAD")
            cfg_path = os.path.join(base, "config.json")
            _dlog(f"config: {cfg_path}", "DIM")
            if os.path.exists(cfg_path):
                _log("  ~ config.json  (user config preserved)", "DIM")
                _dlog("config.json kept (user data)", "DIM")
            else:
                _cfg_str = json.dumps(_DEFAULT_CONFIG, indent=2)
                _wf_track(cfg_path, _cfg_str)
                _log("  ✓ config.json  (factory defaults written)", "OK")
                _dlog(f"config.json written ({len(_cfg_str)} bytes)", "OK")
            rs_path = os.path.join(base, "rules", "rules_state.json")
            if not os.path.exists(rs_path):
                _wf_track(rs_path, "{}")
                _log("  ✓ rules_state.json  (written)", "OK")
            _prog(28 if not already_done else 65, "Checking database…")

            _log("", "NORM")
            _log("[ 4 / 8 ]  scan_history.db", "HEAD")
            db = os.path.join(base, "scan_history.db")
            db_existed = os.path.exists(db)
            _dlog(f"db path: {db}", "DIM")
            _dlog(f"db exists: {db_existed}", "DIM")
            conn = sqlite3.connect(db)
            conn.execute("""CREATE TABLE IF NOT EXISTS scans(
                file TEXT, md5 TEXT, sha1 TEXT, sha256 TEXT,
                malicious INTEGER DEFAULT 0, suspicious INTEGER DEFAULT 0,
                undetected INTEGER DEFAULT 0,
                yara_hits TEXT DEFAULT '[]', pe_info TEXT DEFAULT '{}',
                iocs TEXT DEFAULT '{}', entropy REAL DEFAULT 0.0,
                filetype TEXT DEFAULT 'Unknown', timestamp TEXT DEFAULT '')""")
            count = conn.execute("SELECT COUNT(*) FROM scans").fetchone()[0]
            conn.commit(); conn.close()
            if db_existed:
                _log(f"  ~ scan_history.db  (existing DB preserved — {count} records)", "DIM")
                _dlog(f"db preserved: {count} records", "DIM")
            else:
                _log("  ✓ scan_history.db  (schema created, 0 records)", "OK")
                _dlog("db created fresh", "OK")
            _step_prog(100, "DB OK")
            _prog(34 if not already_done else 68, "Checking v0rtex.py…")

            _log("", "NORM")
            _log("[ 5 / 8 ]  v0rtex.py", "HEAD")
            src_py = os.path.abspath(sys.argv[0])
            dst_py = os.path.join(base, "v0rtex.py")
            _dlog(f"src: {src_py}", "DIM")
            _dlog(f"dst: {dst_py}", "DIM")
            if os.path.abspath(src_py) == os.path.abspath(dst_py):
                _log("  ~ v0rtex.py  (running from install dir, no copy needed)", "DIM")
                _dlog("same path, no copy", "DIM")
            elif os.path.exists(dst_py):
                _log("  ~ v0rtex.py  (already present, kept)", "DIM")
                _dlog("dst already exists, kept", "DIM")
            else:
                with open(src_py,"rb") as sf:
                    _py_data = sf.read()
                with open(dst_py,"wb") as df:
                    df.write(_py_data)
                _log(f"  ✓ v0rtex.py → {dst_py}", "OK")
                _dlog(f"copied {len(_py_data):,} bytes", "OK")
            _prog(40 if not already_done else 72, "Checking launcher…")

            _log("", "NORM")
            _log("[ 6 / 8 ]  Launcher", "HEAD")
            if platform.system() == "Windows":
                lpath = os.path.join(base,"launch.bat")
                if os.path.exists(lpath):
                    _log("  ~ launch.bat  (already present, kept)", "DIM")
                else:
                    _bat = '@echo off\r\ncd /d "%~dp0"\r\npython v0rtex.py\r\nif errorlevel 1 pause\r\n'
                    _wf_track(lpath, _bat)
                    _log("  ✓ launch.bat  (written)", "OK")
            else:
                sh_path = os.path.join(base,"launch.sh")
                if os.path.exists(sh_path):
                    _log("  ~ launch.sh  (already present, kept)", "DIM")
                else:
                    _wf_track(sh_path, '#!/bin/bash\ncd "$(dirname "$0")"\npython3 v0rtex.py\n')
                    try: os.chmod(sh_path, 0o755)
                    except Exception: pass
                    _log("  ✓ launch.sh  (written)", "OK")
            _prog(46 if not already_done else 76, "Checking Python packages…")

            _log("", "NORM")
            _log("[ 7 / 8 ]  Python packages", "HEAD")
            _step_prog(0, "preparing pip install…")
            _dlog("─── pip install requirements ───", "INFO")
            req_path = os.path.join(base, "requirements.txt")
            flags    = ["--break-system-packages"] if platform.system() != "Windows" else []
            flags   += _TRUSTED
            pkgs     = [p.strip() for p in _REQUIREMENTS.strip().splitlines() if p.strip()]
            YARA_PKG    = "yara-python"
            OPTIONAL    = {YARA_PKG}
            main_pkgs   = [p for p in pkgs if YARA_PKG not in p]
            _dlog(f"packages: {len(pkgs)} total ({len(main_pkgs)} required, 1 optional)", "DIM")

            _COMPILE_SIGNALS = (
                "error: command", "cl.exe", "gcc", "g++",
                "failed building", "build failed", "error: microsoft",
                "cannot find compiler", "distutils", "setuptools",
                "no module named 'distutils'",
            )

            def _run_pip(cmd_to_use, label="pip"):
                """Stream pip, return (returncode, installed, satisfied, error_lines)."""
                _dlog(f"cmd: {' '.join(cmd_to_use)}", "DIM")
                try:
                    _no_win = {"creationflags": 0x08000000} if sys.platform == "win32" else {}
                    proc = _sp_popen(cmd_to_use, stdout=subprocess.PIPE,
                                            stderr=subprocess.STDOUT, text=True, bufsize=1,
                                            **_no_win)
                except FileNotFoundError:
                    return 127, 0, 0, [f"{cmd_to_use[0]!r} not found"]
                inst = sat = 0
                err_lines = []
                for line in iter(proc.stdout.readline, ""):
                    line = line.rstrip()
                    if not line: continue
                    if "Successfully installed" in line:
                        inst += 1
                        names = line.replace("Successfully installed", "").strip()
                        _log(f"  ✓ Installed: {names[:80]}", "OK")
                        _dlog(f"installed: {names}", "OK")
                        _step_prog(90, f"installed {inst} pkg(s)")
                        for _pn in names.split():
                            _base_name = _pn.rsplit("-", 1)[0] if "-" in _pn else _pn
                            if _base_name and _base_name not in _manifest["pkgs_installed"]:
                                _manifest["pkgs_installed"].append(_base_name)
                    elif "Requirement already satisfied" in line:
                        sat += 1
                        pkg = line.split(":")[1].strip().split()[0] if ":" in line else line
                        _dlog(f"already ok: {pkg}", "DIM")
                        _step_prog(50 + min(sat, 40), f"checking {pkg[:20]}…")
                    elif line.startswith("Collecting"):
                        name = line.split()[1] if len(line.split()) > 1 else ""
                        _log(f"  ↓ {name}", "INFO")
                        _dlog(f"collecting: {name}", "INFO")
                    elif line.startswith("Downloading"):
                        _dlog(f"downloading: {line[10:60]}", "DIM")
                    elif line.startswith("Installing collected"):
                        _dlog(f"installing: {line[:60]}", "DIM")
                    elif "error" in line.lower() or "ERROR" in line or line.startswith("WARNING"):
                        err_lines.append(line)
                        _dlog(f"{label}: {line[:140]}", "WARN")
                proc.wait()
                return proc.returncode, inst, sat, err_lines

            def _pip_one(exe, pkg, extra_flags=None, timeout=300):
                """
                Install one package. Returns (ok, is_compile_error).
                is_compile_error=True only if the error looks like missing C compiler.
                """
                cmd = [exe, "-m", "pip", "install", pkg,
                       "--no-cache-dir", "--quiet"] + flags + (extra_flags or [])
                try:
                    r = _sp_run(cmd, capture_output=True, text=True, timeout=timeout)
                    if r.returncode == 0:
                        return True, False
                    combined = (r.stdout + r.stderr).lower()
                    is_compile = any(s in combined for s in _COMPILE_SIGNALS)
                    _dlog(f"pip {pkg} exit {r.returncode} "
                          f"{'[compile error]' if is_compile else ''}: "
                          f"{(r.stderr or r.stdout)[:120].strip()}", "WARN")
                    return False, is_compile
                except subprocess.TimeoutExpired:
                    _dlog(f"pip {pkg} timed out", "WARN")
                    return False, False
                except Exception as _e:
                    _dlog(f"pip {pkg} exception: {_e}", "WARN")
                    return False, False

            try:
                installed_count = satisfied_count = 0
                fail_required = []
                fail_optional = []

                def _try_install_build_tools():
                    """
                    Try to install the minimum C/C++ build toolchain on Windows.
                    First checks if VS Build Tools / compiler is already present via:
                      1. cl.exe / gcc / clang on PATH
                      2. vswhere.exe (VS locator, shipped with Build Tools)
                      3. Windows registry (HKLM Visual Studio installer records)
                    Strategy A: winget  (Win10 1809+ / Win11, no download needed)
                    Strategy B: direct download of vs_BuildTools bootstrapper
                    Returns True if install succeeded (or compiler was already present).
                    """
                    import shutil as _sh, threading as _thr
                    if platform.system() != "Windows":
                        return False

                                                               
                    if _sh.which("cl") or _sh.which("gcc") or _sh.which("clang"):
                        _dlog("build tools: compiler already on PATH — skipping install", "OK")
                        return True

                                                                                           
                    _vswhere_paths = [
                        os.path.join(os.environ.get("ProgramFiles(x86)", ""),
                                     "Microsoft Visual Studio", "Installer", "vswhere.exe"),
                        os.path.join(os.environ.get("ProgramFiles", ""),
                                     "Microsoft Visual Studio", "Installer", "vswhere.exe"),
                    ]
                    for _vsw in _vswhere_paths:
                        if os.path.isfile(_vsw):
                            try:
                                _vsw_out = _sp_check_output(
                                    [_vsw, "-products", "*",
                                     "-requires", "Microsoft.VisualStudio.Component.VC.Tools.x86.x64",
                                     "-property", "installationPath"],
                                    stderr=subprocess.DEVNULL, timeout=10
                                ).decode(errors="replace").strip()
                                if _vsw_out:
                                    _dlog(f"build tools: already installed at {_vsw_out[:80]} — skipping install", "OK")
                                    _log("  ✓ VS Build Tools already installed — skipping", "OK")
                                    return True
                            except Exception as _vswe:
                                _dlog(f"build tools: vswhere check failed: {_vswe}", "WARN")

                                                                                  
                    try:
                        import winreg as _wreg
                                                              
                        _reg_checks = [
                                                                               
                            (r"SOFTWARE\Microsoft\VisualStudio\Setup\Enterprise",         None),
                            (r"SOFTWARE\Microsoft\VisualStudio\Setup\BuildTools",         None),
                            (r"SOFTWARE\WOW6432Node\Microsoft\VisualStudio\Setup\BuildTools", None),
                                                                           
                            (r"SOFTWARE\Microsoft\Windows\CurrentVersion\Uninstall",
                             "Microsoft Visual Studio Build Tools 2022"),
                            (r"SOFTWARE\WOW6432Node\Microsoft\Windows\CurrentVersion\Uninstall",
                             "Microsoft Visual Studio Build Tools 2022"),
                        ]
                        for _rk, _match in _reg_checks:
                            try:
                                with _wreg.OpenKey(_wreg.HKEY_LOCAL_MACHINE, _rk) as _k:
                                    if _match is None:
                                                                          
                                        _dlog(f"build tools: registry key found ({_rk}) — already installed", "OK")
                                        _log("  ✓ VS Build Tools already installed (registry) — skipping", "OK")
                                        return True
                                                                                     
                                    _idx = 0
                                    while True:
                                        try:
                                            _sub = _wreg.EnumKey(_k, _idx)
                                            if _match.lower() in _sub.lower():
                                                _dlog(f"build tools: uninstall entry found ({_sub}) — already installed", "OK")
                                                _log("  ✓ VS Build Tools already installed (registry) — skipping", "OK")
                                                return True
                                            _idx += 1
                                        except OSError:
                                            break
                            except FileNotFoundError:
                                pass
                    except ImportError:
                        pass

                    _log("  ~ No C compiler or VS Build Tools found — starting install…", "WARN")
                    _dlog("build tools: starting install", "WARN")

                    def _refresh_path():
                        """Refresh os.environ PATH from registry after install."""
                        try:
                            import winreg as _wr
                            with _wr.OpenKey(_wr.HKEY_LOCAL_MACHINE,
                                r"SYSTEM\CurrentControlSet\Control\Session Manager\Environment") as _k:
                                _sys_path, _ = _wr.QueryValueEx(_k, "Path")
                            _cur = os.environ.get("PATH", "")
                            for _seg in _sys_path.split(";"):
                                if _seg and _seg not in _cur:
                                    os.environ["PATH"] = _cur + ";" + _seg
                                    _cur = os.environ["PATH"]
                            _dlog("build tools: PATH refreshed from registry", "OK")
                        except Exception as _pre:
                            _dlog(f"build tools: PATH refresh skipped: {_pre}", "WARN")

                    def _bt_watchdog(proc, label, timeout_s):
                        """
                        Runs in a thread alongside the VS installer process.
                        Polls every 3 seconds — checks process is alive, reads any
                        installer log lines from %TEMP%\\dd_bootstrapper*.log, and
                        updates the step bar + dlog with live status.
                        """
                        import glob as _gl, time as _wt
                        _start = _wt.time()
                        _seen_lines = set()
                        _dot = [0]
                        _DOTS = ["   ", ".  ", ".. ", "..."]
                        _log_globs = [
                            os.path.join(os.environ.get("TEMP", ""), "dd_bootstrapper*.log"),
                            os.path.join(os.environ.get("TEMP", ""), "dd_setup*.log"),
                            os.path.join(os.environ.get("TEMP", ""), "dd_client*.log"),
                        ]

                        while proc.poll() is None:
                            elapsed = _wt.time() - _start
                            m, s = divmod(int(elapsed), 60)
                            _dot[0] = (_dot[0] + 1) % len(_DOTS)
                            pct = min(95, int(elapsed / timeout_s * 95))
                            _step_prog(pct,
                                f"{label}{_DOTS[_dot[0]]}  {m:02d}:{s:02d}")

                            for _pat in _log_globs:
                                for _lf in _gl.glob(_pat):
                                    try:
                                        with open(_lf, encoding="utf-16-le",
                                                  errors="replace") as _lh:
                                            for _line in _lh:
                                                _line = _line.strip()
                                                if not _line or _line in _seen_lines:
                                                    continue
                                                _seen_lines.add(_line)
                                                _ll = _line.lower()
                                                if any(k in _ll for k in (
                                                    "installing", "downloaded",
                                                    "applying", "error", "failed",
                                                    "success", "complete", "package"
                                                )):
                                                    _dlog(f"[vs] {_line[:120]}", "DIM")
                                    except Exception:
                                        pass

                            _wt.sleep(3)

                        elapsed = _wt.time() - _start
                        m, s = divmod(int(elapsed), 60)
                        _step_prog(100, f"{label} — done in {m:02d}:{s:02d}")

                    if _sh.which("winget"):
                        _log("  → winget: Microsoft.VisualStudio.2022.BuildTools…", "INFO")
                        _log("  ⏳ This may take 5-15 minutes — watchdog active", "INFO")
                        _dlog("build tools: winget attempt", "INFO")
                        _wg_proc = _sp_popen([
                            "winget", "install", "--id",
                            "Microsoft.VisualStudio.2022.BuildTools",
                            "--silent",
                            "--accept-package-agreements",
                            "--accept-source-agreements",
                            "--override",
                            "--quiet --wait --norestart"
                            " --add Microsoft.VisualStudio.Workload.VCTools"
                            " --includeRecommended",
                        ], stdout=subprocess.PIPE, stderr=subprocess.PIPE)

                        _wd = _thr.Thread(
                            target=_bt_watchdog,
                            args=(_wg_proc, "VS Build Tools via winget", 600),
                            daemon=True)
                        _wd.start()

                        try:
                            _wg_proc.wait(timeout=600)
                        except subprocess.TimeoutExpired:
                            _wg_proc.kill()
                            _dlog("build tools: winget timed out after 10min", "WARN")
                        _wd.join(timeout=5)

                        if _wg_proc.returncode in (0, -1978335189):
                            _log("  ✓ VS Build Tools installed via winget", "OK")
                            _dlog("build tools: winget OK", "OK")
                            _manifest["vs_build_tools"] = True
                            _refresh_path()
                            return True
                        _dlog(f"build tools: winget exit {_wg_proc.returncode}", "WARN")

                    _log("  → Downloading vs_BuildTools bootstrapper (aka.ms)…", "INFO")
                    _dlog("build tools: download bootstrapper", "INFO")
                    _bt_url = "https://aka.ms/vs/17/release/vs_buildtools.exe"
                    _bt_tmp = os.path.join(
                        os.environ.get("TEMP", os.path.expanduser("~")),
                        "vs_buildtools_setup.exe"
                    )
                    try:
                        import urllib.request as _urbt
                        _urbt.urlretrieve(_bt_url, _bt_tmp)
                        _log("  → Running installer (silent — watchdog active)…", "INFO")
                        _log("  ⏳ This may take 5-15 minutes, please wait…", "INFO")

                        _bi_proc = _sp_popen([
                            _bt_tmp,
                            "--quiet", "--wait", "--norestart",
                            "--add", "Microsoft.VisualStudio.Workload.VCTools",
                            "--includeRecommended",
                        ], stdout=subprocess.PIPE, stderr=subprocess.PIPE)

                        _wd2 = _thr.Thread(
                            target=_bt_watchdog,
                            args=(_bi_proc, "VS Build Tools bootstrapper", 900),
                            daemon=True)
                        _wd2.start()

                        try:
                            _bi_proc.wait(timeout=900)
                        except subprocess.TimeoutExpired:
                            _bi_proc.kill()
                            _dlog("build tools: bootstrapper timed out after 15min", "WARN")
                        _wd2.join(timeout=5)

                        if _bi_proc.returncode in (0, 3010):
                            _log(f"  ✓ VS Build Tools installed"
                                 f"{' (reboot recommended)' if _bi_proc.returncode == 3010 else ''}",
                                 "OK")
                            _dlog(f"build tools: bootstrapper OK (exit {_bi_proc.returncode})", "OK")
                            _manifest["vs_build_tools"] = True
                            _refresh_path()
                            return True
                        _dlog(f"build tools: bootstrapper exit {_bi_proc.returncode}", "WARN")
                    except Exception as _bte:
                        _dlog(f"build tools: download/run error: {_bte}", "WARN")

                    _log("  ~ VS Build Tools install failed — C compiler unavailable", "WARN")
                    return False

                _step_prog(5, "installing packages…")
                _dlog("phase 1: bulk --prefer-binary", "INFO")
                cmd1 = [sys.executable, "-m", "pip", "install", "-r", req_path,
                        "--prefer-binary", "--no-cache-dir",
                        "--progress-bar", "off"] + flags
                rc1, i1, s1, errs1 = _run_pip(cmd1, "pip bulk")
                installed_count += i1; satisfied_count += s1

                if rc1 == 0:
                    _dlog("phase 1 OK — all packages installed", "OK")

                    _step_prog(92, "verifying imports…")
                    _dlog("phase 1 verify: import check", "INFO")

                    _PKG_TO_MOD = {
                        "requests":        "requests",
                        "pefile":          "pefile",
                        "matplotlib":      "matplotlib",
                        "tkinterdnd2":     "tkinterdnd2",
                        "psutil":          "psutil",
                        "fpdf2":           "fpdf",
                        "watchdog":        "watchdog",
                        "pystray":         "pystray",
                        "pillow":          "PIL",
                        "cryptography":    "cryptography",
                        "reportlab":       "reportlab",
                        "yara-python":     "yara",
                    }
                    _verify_failed_req  = []
                    _verify_failed_opt  = []
                    for _vpkg in pkgs:
                        _vname = _vpkg.split(">=")[0].split("==")[0].split("[")[0].strip().lower()
                        _vmod  = _PKG_TO_MOD.get(_vname, _vname)
                        _vopt  = (YARA_PKG in _vpkg)
                        try:
                            __import__(_vmod)
                            _dlog(f"verify OK: {_vname} → import {_vmod}", "OK")
                        except ImportError:
                            _dlog(f"verify FAIL: {_vname} → import {_vmod} missing", "WARN")
                            if _vopt:
                                _verify_failed_opt.append(_vname)
                            else:
                                _verify_failed_req.append(_vname)

                    if _verify_failed_req:
                        _log(f"  ⚠ Installed but not importable: {', '.join(_verify_failed_req)}"
                             f" — falling back to per-package…", "WARN")
                        _dlog(f"verify: {len(_verify_failed_req)} required pkg(s) not importable"
                              f" → forcing phase 2", "WARN")
                        for _vf in _verify_failed_req:
                            fail_required.append(_vf)
                        rc1 = 1
                    elif _verify_failed_opt:
                        _log(f"  ~ Optional not importable after install: "
                             f"{', '.join(_verify_failed_opt)} — retrying with build tools…", "WARN")
                        _dlog(f"verify: optional {_verify_failed_opt} not importable → retry", "WARN")
                        _bt_installed = False
                        for _vf in _verify_failed_opt:
                            _orig_pkg = next((p for p in pkgs if _vf in p.lower()
                                              or p.lower().startswith(_vf)), _vf)
                            _ok_r, _ce_r = _pip_one(sys.executable, _orig_pkg, ["--prefer-binary"])
                            if not _ok_r:
                                if not _bt_installed:
                                    _bt_installed = True
                                    _try_install_build_tools()
                                _ok_r, _ = _pip_one(sys.executable, _orig_pkg, timeout=600)
                            if _ok_r:
                                try:
                                    _vmod = _PKG_TO_MOD.get(_vf, _vf)
                                    __import__(_vmod)
                                    _log(f"  ✓ {_vf} (optional — installed on retry)", "OK")
                                    _dlog(f"verify retry OK: {_vf}", "OK")
                                except ImportError:
                                    fail_optional.append(_vf)
                                    _log(f"  ~ {_vf} (optional) — installed but not importable", "WARN")
                            else:
                                fail_optional.append(_vf)
                                _log(f"  ~ {_vf} (optional) — C compiler unavailable, features disabled", "WARN")
                    else:
                        _log("  ✓ All packages verified (import check passed)", "OK")
                        _dlog("verify: all imports OK", "OK")

                else:
                    if errs1:
                        _dlog(f"phase 1 errors ({len(errs1)}):", "WARN")
                        for el in errs1[:10]:
                            _dlog(f"  {el[:140]}", "WARN")
                    _log("  ~ Bulk install incomplete — trying per-package…", "INFO")

                    _step_prog(15, "per-package install…")
                    _dlog("phase 2: per-package", "INFO")
                    needs_compile = []

                    all_pkgs_to_try = main_pkgs + [p for p in pkgs if YARA_PKG in p]
                    for idx, pkg in enumerate(all_pkgs_to_try):
                        pname = pkg.split(">=")[0].split("==")[0].split("[")[0].strip()
                        is_opt = any(o in pkg for o in OPTIONAL)
                        _step_prog(int(15 + idx / max(len(all_pkgs_to_try), 1) * 60),
                                   f"{'[opt] ' if is_opt else ''}installing {pname[:18]}…")

                        ok, compile_err = _pip_one(sys.executable, pkg, ["--prefer-binary"])
                        if ok:
                            installed_count += 1
                            _dlog(f"  ✓ {pname} (binary wheel)", "OK")
                            continue

                        ok2, _ = _pip_one(sys.executable, pkg, ["--only-binary", ":all:"])
                        if ok2:
                            installed_count += 1
                            _dlog(f"  ✓ {pname} (only-binary)", "OK")
                            continue

                        ok3, compile_err3 = _pip_one(sys.executable, pkg)
                        if ok3:
                            installed_count += 1
                            _dlog(f"  ✓ {pname} (plain install)", "OK")
                            continue

                        if compile_err or compile_err3:
                            needs_compile.append((pkg, pname, is_opt))
                            _dlog(f"  ~ {pname} → needs C compiler", "WARN")
                        else:
                            if is_opt:
                                fail_optional.append(pname)
                                _log(f"  ~ {pname} (optional) — unavailable", "WARN")
                            else:
                                fail_required.append(pname)
                                _log(f"  ✗ {pname} — install failed", "WARN")

                    if needs_compile:
                        req_compile = [(p,n) for p,n,o in needs_compile if not o]
                        opt_compile = [(p,n) for p,n,o in needs_compile if o]

                        if opt_compile:
                            _bt_ok_opt = False
                            for pkg, n in opt_compile:
                                ok_ob, _ = _pip_one(sys.executable, pkg, ["--only-binary", ":all:"])
                                if ok_ob:
                                    installed_count += 1
                                    _log(f"  ✓ {n} (optional — binary wheel found)", "OK")
                                    _dlog(f"opt_compile: {n} OK via only-binary", "OK")
                                    continue

                                _log(f"  ~ {n} (optional) — no binary wheel, trying to compile…", "WARN")
                                if not _bt_ok_opt:
                                    _bt_ok_opt = _try_install_build_tools()
                                if _bt_ok_opt:
                                    _log(f"  → Compiling {n} with VS Build Tools (may take 1-3 min)…", "INFO")
                                    _step_prog(50, f"compiling {n}…")
                                ok_comp, _ = _pip_one(sys.executable, pkg, timeout=600)
                                if ok_comp:
                                    installed_count += 1
                                    _log(f"  ✓ {n} (optional — compiled successfully)", "OK")
                                    _dlog(f"opt_compile: {n} OK after build tools", "OK")
                                else:
                                    reason = "build tools unavailable" if not _bt_ok_opt else "compile failed"
                                    _log(f"  ~ {n} (optional) — {reason}, YARA features disabled", "WARN")
                                    _dlog(f"opt_compile: {n} skipped ({reason})", "WARN")
                                    fail_optional.append(n)

                        if req_compile:
                            _log(f"  ~ {len(req_compile)} required package(s) need a C compiler", "WARN")

                            still_req = []
                            for pkg, pname in req_compile:
                                ok_b, _ = _pip_one(sys.executable, pkg, ["--only-binary", ":all:"])
                                if ok_b:
                                    installed_count += 1
                                    _log(f"  ✓ {pname} (binary wheel found)", "OK")
                                else:
                                    still_req.append((pkg, pname))

                            if still_req:
                                _bt_ok = _try_install_build_tools()
                                for pkg, pname in still_req:
                                    ok_bt, _ = _pip_one(sys.executable, pkg)
                                    if ok_bt:
                                        installed_count += 1
                                        _log(f"  ✓ {pname} (compiled after build tools install)", "OK")
                                        _dlog(f"req_compile: {pname} OK after build tools", "OK")
                                    else:
                                        fail_required.append(pname)
                                        reason = "build tools unavailable" if not _bt_ok else "compile failed"
                                        _log(f"  ✗ {pname} — could not install ({reason})", "WARN")


                    if len(fail_required) > len(main_pkgs) // 2:
                        _log("  ~ Trying system python as fallback…", "INFO")
                        _dlog("phase 4: system python fallback", "WARN")
                        for _py in ["python", "python3", "py"]:
                            fb_cmd = [_py, "-m", "pip", "install", "-r", req_path,
                                      "--prefer-binary", "--no-cache-dir", "--quiet",
                                      "--progress-bar", "off"] + _TRUSTED
                            fb_rc, fb_i, fb_s, fb_errs = _run_pip(fb_cmd, f"{_py} -m pip")
                            installed_count += fb_i; satisfied_count += fb_s
                            if fb_rc == 0:
                                _log(f"  ✓ Fallback '{_py} -m pip' succeeded", "OK")
                                _dlog(f"fallback {_py} exit 0", "OK")
                                fail_required.clear()
                                break
                            if fb_errs:
                                _dlog(f"fallback {_py} errors: "
                                      f"{' | '.join(fb_errs[:3])[:200]}", "WARN")
                            _dlog(f"fallback {_py} exit {fb_rc}", "WARN")

                if fail_required:
                    _log("  ~ Trying --user install for remaining packages…", "INFO")
                    _dlog("phase 5: --user fallback", "WARN")
                    _pkg_map = {}
                    for _p in pkgs:
                        _n = _p.split(">=")[0].split("==")[0].split("[")[0].strip()
                        _pkg_map[_n] = _p
                    _still_fail = []
                    for _pname in list(fail_required):
                        _pfull = _pkg_map.get(_pname, _pname)
                        _ok_u, _ = _pip_one(sys.executable, _pfull,
                                            ["--user", "--prefer-binary"])
                        if _ok_u:
                            fail_required.remove(_pname)
                            installed_count += 1
                            _log(f"  ✓ {_pname} (--user)", "OK")
                            _dlog(f"phase 5: {_pname} OK via --user", "OK")
                        else:
                            _ok_u2, _ = _pip_one(sys.executable, _pfull, ["--user"])
                            if _ok_u2:
                                fail_required.remove(_pname)
                                installed_count += 1
                                _log(f"  ✓ {_pname} (--user plain)", "OK")
                                _dlog(f"phase 5: {_pname} OK via --user plain", "OK")
                            else:
                                _dlog(f"phase 5: {_pname} still failed", "WARN")

                if installed_count or satisfied_count:
                    _log(f"  ✓ {installed_count} installed, {satisfied_count} already satisfied", "OK")
                if fail_optional:
                    _log(f"  ~ Optional unavailable: {', '.join(fail_optional)} "
                         f"(YARA scanning disabled)", "WARN")
                if fail_required:
                    _log(f"  ⚠ {len(fail_required)} required package(s) missing — "
                         f"some features disabled: {', '.join(fail_required[:6])}", "WARN")
                else:
                    _log("  ✓ All required packages ready", "OK")
                _dlog(f"packages: installed={installed_count} satisfied={satisfied_count} "
                      f"fail_required={fail_required} fail_optional={fail_optional}", "OK")

                _step_prog(98, "final import check…")
                _dlog("final import check", "INFO")
                _PKG_TO_MOD_FINAL = {
                    "requests":     "requests",
                    "pefile":       "pefile",
                    "matplotlib":   "matplotlib",
                    "tkinterdnd2":  "tkinterdnd2",
                    "psutil":       "psutil",
                    "fpdf2":        "fpdf",
                    "watchdog":     "watchdog",
                    "pystray":      "pystray",
                    "pillow":       "PIL",
                    "cryptography": "cryptography",
                    "reportlab":    "reportlab",
                    "yara-python":  "yara",
                }
                _final_ok = []; _final_miss_req = []; _final_miss_opt = []
                for _fpkg in pkgs:
                    _fname = _fpkg.split(">=")[0].split("==")[0].split("[")[0].strip()
                    _fmod  = _PKG_TO_MOD_FINAL.get(_fname.lower(), _fname)
                    _fopt  = (YARA_PKG in _fpkg)
                    try:
                        __import__(_fmod)
                        _final_ok.append(_fname)
                    except ImportError:
                        if _fopt:
                            _final_miss_opt.append(_fname)
                        else:
                            _final_miss_req.append(_fname)

                _log("", "NORM")
                _log("  ── Final import check ──", "HEAD")
                for _fn in _final_ok:
                    _log(f"    ✓ {_fn}", "OK")
                for _fn in _final_miss_opt:
                    _log(f"    ~ {_fn}  (optional — YARA disabled)", "WARN")
                for _fn in _final_miss_req:
                    _log(f"    ✗ {_fn}  (MISSING — feature disabled)", "ERR")
                if not _final_miss_req and not _final_miss_opt:
                    _log("  ✓ All packages importable — setup complete.", "OK")
                elif not _final_miss_req:
                    _log(f"  ✓ All required packages OK  "
                         f"({len(_final_miss_opt)} optional missing)", "OK")
                else:
                    _log(f"  ⚠ {len(_final_miss_req)} required package(s) NOT importable: "
                         f"{', '.join(_final_miss_req)}", "ERR")
                _dlog(f"final check: ok={_final_ok} miss_req={_final_miss_req} "
                      f"miss_opt={_final_miss_opt}", "OK")

                _step_prog(100, "packages done")

            except Exception as _pe:
                _log(f"  ✗ pip error: {_pe}", "ERR")
                _dlog(f"pip exception: {_pe}", "ERR")
                _step_prog(100, "pip error (see log)")
            _prog(76, "Checking Wireshark…")

            _log("", "NORM")
            _log("[ 8 / 8 ]  Wireshark / tshark", "HEAD")
            if ws_var.get():
                tshark_installed = False
                installed_ver    = ""
                tshark_exe       = "tshark"

                _candidates = ["tshark"]
                if platform.system() == "Windows":
                    _candidates += [
                        r"C:\Program Files\Wireshark\tshark.exe",
                        r"C:\Program Files (x86)\Wireshark\tshark.exe",
                    ]
                    try:
                        import winreg as _wr
                        for _hive in (_wr.HKEY_LOCAL_MACHINE, _wr.HKEY_CURRENT_USER):
                            for _sub in (
                                r"SOFTWARE\Wireshark",
                                r"SOFTWARE\WOW6432Node\Wireshark",
                            ):
                                try:
                                    with _wr.OpenKey(_hive, _sub) as _k:
                                        _loc = _wr.QueryValueEx(_k, "InstallDir")[0]
                                        _candidates.append(
                                            os.path.join(_loc, "tshark.exe"))
                                except Exception:
                                    pass
                    except Exception:
                        pass
                elif platform.system() == "Darwin":
                    _candidates += [
                        "/Applications/Wireshark.app/Contents/MacOS/tshark",
                        "/usr/local/bin/tshark",
                        "/opt/homebrew/bin/tshark",
                    ]
                else:
                    _candidates += ["/usr/bin/tshark", "/usr/local/bin/tshark"]

                for _cand in _candidates:
                    try:
                        r = _sp_run(
                            [_cand, "--version"],
                            capture_output=True, timeout=5
                        )
                        if r.returncode == 0:
                            ver_line      = r.stdout.decode(errors="replace").splitlines()[0]
                            installed_ver = ver_line
                            tshark_exe    = _cand
                            tshark_installed = True
                            break
                    except Exception:
                        pass

                if tshark_installed:
                    _log(f"  ✓ tshark found: {installed_ver}", "OK")
                    if tshark_exe != "tshark":
                        _log(f"  ~ path: {tshark_exe}", "DIM")
                    _log("  → Checking for updates…", "INFO")
                    try:
                        import urllib.request as _ur
                        with _ur.urlopen(
                            "https://www.wireshark.org/download.html",
                            timeout=8
                        ) as _resp:
                            _html = _resp.read().decode(errors="replace")
                        import re as _re
                        _m = _re.search(r'Wireshark[\s\-]+([\d]+\.[\d]+\.[\d]+)', _html)
                        if _m:
                            latest = _m.group(1)
                            _mv = _re.search(r'([\d]+\.[\d]+\.[\d]+)', installed_ver)
                            inst_v = _mv.group(1) if _mv else ""
                            if inst_v and inst_v == latest:
                                _log(f"  ✓ Up to date  (v{latest})", "OK")
                            elif inst_v:
                                _log(f"  ⚠ Update available: {inst_v} → {latest}", "WARN")
                                _log("    → Download from: https://www.wireshark.org/download.html", "DIM")
                            else:
                                _log(f"  ~ Latest on wireshark.org: v{latest}", "DIM")
                        else:
                            _log("  ~ Could not parse latest version from wireshark.org", "DIM")
                    except Exception as _ue:
                        _log(f"  ~ Update check skipped ({_ue})", "DIM")
                else:
                    sys_ = platform.system()
                    if sys_ == "Windows":
                        _log("  ↓ Downloading Wireshark installer…", "INFO")
                        try:
                            import urllib.request as ur
                            url  = "https://www.wireshark.org/download/win64/Wireshark-latest-x64.exe"
                            inst = os.path.join(base, "_recovery", "WiresharkSetup.exe")
                            ur.urlretrieve(url, inst)
                            _sp_popen([inst, "/desktopicon=no"])
                            _log("  ✓ Wireshark installer opened — follow the on-screen steps", "OK")
                            _log("  ⚠ Make sure to tick 'TShark' during install!", "WARN")
                        except Exception as _we:
                            _log(f"  ⚠ Auto-download failed: {_we}", "WARN")
                            _log("    → Install manually from https://www.wireshark.org", "DIM")
                    elif sys_ == "Linux":
                        try:
                            _sp_run(["sudo","apt-get","install","-y","tshark"],
                                           check=False, timeout=120)
                            _log("  ✓ tshark installed via apt", "OK")
                        except Exception as _le:
                            _log(f"  ⚠ {_le}", "WARN")
                    elif sys_ == "Darwin":
                        try:
                            _sp_run(["brew","install","--cask","wireshark"],
                                           check=False, timeout=300)
                            _log("  ✓ Wireshark installed via brew", "OK")
                        except Exception as _me:
                            _log(f"  ⚠ {_me}", "WARN")
            else:
                _log("  — skipped (checkbox unchecked)", "DIM")

            if platform.system() == "Windows":
                _log("", "NORM")
                _log("[ + ]  Windows Defender — Adding exclusions", "HEAD")
                _py  = sys.executable
                _pyw = _py.replace("python.exe", "pythonw.exe")

                def _ps(cmd):
                    """Run a PowerShell command, return (ok, msg)."""
                    try:
                        r = _sp_run(
                            ["powershell", "-NoProfile", "-NonInteractive",
                             "-WindowStyle", "Hidden",
                             "-Command", cmd],
                            capture_output=True, text=True, timeout=20
                        )
                        ok = r.returncode == 0
                        msg = ((r.stderr or r.stdout) or "").strip().splitlines()
                        return ok, (msg[0][:120] if msg else "")
                    except Exception as _pe:
                        return False, str(_pe)

                ok, msg = _ps(f'Add-MpPreference -ExclusionPath "{base}"')
                if ok:
                    _log(f"  ✓ Folder excluded from AV scan: {base}", "OK")
                    _manifest["defender_exclusions"]["paths"].append(base)
                else:
                    _log(f"  ~ Folder exclusion: {msg or 'skipped'}", "WARN")

                for _exe in dict.fromkeys([_py, _pyw]):
                    if not os.path.exists(_exe):
                        continue
                    ok, msg = _ps(f'Add-MpPreference -ExclusionProcess "{_exe}"')
                    if ok:
                        _log(f"  ✓ Process excluded: {os.path.basename(_exe)}", "OK")
                        _manifest["defender_exclusions"]["processes"].append(_exe)
                    else:
                        _log(f"  ~ Process exclusion ({os.path.basename(_exe)}): {msg or 'skipped'}", "WARN")

                for _exe in dict.fromkeys([_py, _pyw]):
                    if not os.path.exists(_exe):
                        continue
                    ok, msg = _ps(
                        f'Add-MpPreference -ControlledFolderAccessAllowedApplications "{_exe}"'
                    )
                    if ok:
                        _log(f"  ✓ CFA allowed: {os.path.basename(_exe)}", "OK")
                        _manifest["defender_exclusions"]["cfa"].append(_exe)
                    else:
                        _log(f"  ~ CFA ({os.path.basename(_exe)}): {msg or 'skipped'}", "WARN")

                for _f in [os.path.join(base, "v0rtex.py"),
                           os.path.abspath(sys.argv[0])]:
                    if not os.path.exists(_f):
                        continue
                    try:
                        ads = _f + ":Zone.Identifier"
                        if os.path.exists(ads):
                            os.remove(ads)
                            _log(f"  ✓ Removed Zone.Identifier from {os.path.basename(_f)}", "OK")
                        else:
                            _ps(f'Unblock-File -Path "{_f}"')
                            _log(f"  ✓ Unblocked: {os.path.basename(_f)}", "OK")
                    except Exception as _ze:
                        _log(f"  ~ Zone.Identifier removal: {_ze}", "WARN")

            if import_backup_var.get():
                bk_zip = import_backup_path.get().strip()
                _log("", "NORM")
                _log("[ + ]  Importing backup", "HEAD")
                _step_prog(0, "importing backup…")
                if bk_zip and os.path.isfile(bk_zip):
                    _dlog(f"backup zip: {bk_zip}", "DIM")
                    _RESTORE_ITEMS = {
                        "config.json", "scan_history.db",
                        "whitelist.txt", "notes.txt",
                        "app_integrity_baseline.json",
                    }
                    try:
                        import zipfile as _zf_bk
                        restored_bk = 0
                        with _zf_bk.ZipFile(bk_zip, "r") as _z:
                            names_bk = _z.namelist()
                            _dlog(f"  ZIP members: {len(names_bk)}", "DIM")
                            for member in names_bk:
                                                                             
                                if member.endswith("/") or member.startswith("_"):
                                    continue
                                                                            
                                                                                                   
                                parts = member.replace("\\", "/").split("/")
                                                                                                    
                                fname  = parts[-1]
                                parent = parts[-2] if len(parts) >= 2 else ""
                                                                            
                                if fname in _RESTORE_ITEMS:
                                    rel_dest = fname
                                elif parent == "rules" or (len(parts) >= 2 and parts[-2] == "rules"):
                                                                                      
                                    rules_idx = next((i for i, p in enumerate(parts) if p == "rules"), None)
                                    if rules_idx is not None:
                                        rel_dest = os.path.join("rules", *parts[rules_idx+1:])
                                    else:
                                        continue
                                else:
                                    continue
                                dest_bk = os.path.join(base, rel_dest)
                                try:
                                    os.makedirs(os.path.dirname(dest_bk) if os.path.dirname(dest_bk) else base, exist_ok=True)
                                    with _z.open(member) as _sf, open(dest_bk, "wb") as _df:
                                        _df.write(_sf.read())
                                    _log(f"  ✓ restored: {rel_dest}", "OK")
                                    _dlog(f"restored: {rel_dest} ← {member}", "OK")
                                    restored_bk += 1
                                except Exception as _re:
                                    _log(f"  ✗ {rel_dest}: {_re}", "WARN")
                        _log(f"  ✓ Backup import complete — {restored_bk} files restored", "OK")
                        _step_prog(100, "backup imported")
                                                                                                      
                        _log("  ✓ All restored files will be active on first launch", "OK")
                    except Exception as _be:
                        _log(f"  ✗ Backup import failed: {_be}", "ERR")
                        _dlog(f"backup import exception: {_be}", "ERR")
                elif bk_zip:
                    _log(f"  ✗ Backup file not found: {bk_zip}", "ERR")
                else:
                    _log("  ~ No backup path set, skipping", "DIM")
                _prog(96, "Finalizing…")

            _sentinel_path = os.path.join(base, "_setup_complete")
            os.makedirs = _outer_makedirs
            _outer_makedirs(os.path.dirname(_sentinel_path), exist_ok=True)
            open(_sentinel_path, "w").close()
            _dlog(f"sentinel written: {_sentinel_path}", "DIM")
            import json as _json_m
            _manifest_path = os.path.join(base, "_setup_manifest.json")
            try:
                with open(_manifest_path, "w", encoding="utf-8") as _mf:
                    _json_m.dump(_manifest, _mf, indent=2)
                _dlog(f"manifest written: {_manifest_path}", "DIM")
            except Exception as _me:
                _dlog(f"manifest write failed: {_me}", "WARN")

            _log("", "NORM")
            _log("[ ✎ ]  Writing installation log", "HEAD")
            try:
                import datetime as _dti
                _system_dir = os.path.dirname(base)
                _ilog_dir   = os.path.join(_system_dir, "installation_media", "debug_log")
                os.makedirs(_ilog_dir, exist_ok=True)
                _ilog_ts    = _dti.datetime.now().strftime("%Y%m%d_%H%M%S")
                _ilog_path  = os.path.join(_ilog_dir, f"install_{_ilog_ts}.txt")
                _ilog_lines = [
                    "=" * 72,
                    f"  V0RTEX v0.9.7.X2 — INSTALLATION LOG",
                    f"  Timestamp  : {_dti.datetime.now().strftime('%Y-%m-%d %H:%M:%S')}",
                    f"  Python     : {sys.version}",
                    f"  Platform   : {platform.system()} {platform.release()} ({sys.platform})",
                    f"  Executable : {sys.executable}",
                    f"  Install dir: {base}",
                    f"  Wireshark  : {'requested' if ws_var.get() else 'skipped'}",
                    f"  Backup imp : {'yes — ' + import_backup_path.get() if import_backup_var.get() else 'no'}",
                    f"  Sentinel   : {_sentinel_path}",
                    "=" * 72,
                    "",
                    "  SETUP LOG DUMP:",
                    "  " + "-" * 68,
                ]
                try:
                    _log_content = log_widget[0].get("1.0", "end") if log_widget[0] else ""
                except Exception:
                    _log_content = ""
                for _il in _log_content.splitlines():
                    _ilog_lines.append("  " + _il)
                _ilog_lines += ["", "=" * 72]
                with open(_ilog_path, "w", encoding="utf-8", errors="replace") as _ilf:
                    _ilf.write("\n".join(_ilog_lines))
                _log(f"  ✓ Install log → debug_log/{os.path.basename(_ilog_path)}", "OK")
                _dlog(f"install log written: {_ilog_path}", "OK")
            except Exception as _ile:
                _log(f"  ~ Install log failed: {_ile}", "WARN")
                _dlog(f"install log error: {_ile}", "WARN")

            _system_dir    = os.path.dirname(base)
            _media_dir      = os.path.join(_system_dir, "installation_media")
            _sys_log_dir    = os.path.join(_media_dir, "debug_log")
            _sys_backup_dir = os.path.join(_media_dir, "backups")
            for _d in (_media_dir, _sys_log_dir, _sys_backup_dir):
                try:
                    _existed = os.path.isdir(_d)
                    os.makedirs(_d, exist_ok=True)
                    if not _existed:
                        _manifest["dirs_created"].append(_d)
                except Exception: pass
            _tram_code_setup = _build_trampoline_script()
            for _sname, _sfn in [
                ("v0rtex_uninstall.py", _build_uninstall_script),
                ("v0rtex_reinstall.py", _build_reinstall_script),
            ]:
                _spath = os.path.join(_media_dir, _sname)
                try:
                    with open(_spath, "w", encoding="utf-8") as _sf:
                        _sf.write(_sfn(base, sys.executable, _tram_code_setup))
                    _manifest["files_created"].append(_spath)
                    _log(f"  ✓ {_sname} → installation_media/", "OK")
                    _dlog(f"{_sname} written OK", "DIM")
                except Exception as _se:
                    _log(f"  ~ {_sname}: {_se}", "WARN")

            _prog(100, "Setup complete!")
            _log("", "NORM")
            _log("━"*52, "HEAD")
            _log("  ✓  V0RTEX v0.9.7.X2 is ready", "OK")
            _log(f"  ✓  Installed to: {base}", "OK")
            _log("  →  Click  LAUNCH  to start", "INFO")
            _log("━"*52, "HEAD")
            done_evt.set()
            root.after(0, _unlock_launch)

        except Exception as _ex:
            try: os.makedirs = _outer_makedirs
            except Exception: pass
            _log(f"\n  ✗ FATAL: {_ex}", "ERR")
            _log(_tb.format_exc(), "DIM")
            root.after(0, lambda: _setup_panic(
                "Setup Fatal Error", str(_ex), _tb.format_exc(), setup_root=root))

    def _unlock_launch():
        try:
            btn_launch[0].config(state="normal", bg=C["green"],
                                 fg=C["bg"], text="  ✓  LAUNCH V0RTEX  →  ")
            btn_install[0].config(state="disabled", text=" Fatto ")
        except Exception: pass
        _anim_stop_fn()

    topbar = tk.Frame(root, bg=C["panel"], height=38)
    topbar.pack(fill="x")
    topbar.pack_propagate(False)

    tk.Label(topbar, text="⬡", font=("Consolas", 16, "bold"),
             bg=C["panel"], fg=C["accent"]).pack(side="left", padx=(14,4), pady=6)
    tk.Label(topbar, text="V0RTEX", font=("Consolas", 12, "bold"),
             bg=C["panel"], fg=C["text"]).pack(side="left")
    tk.Label(topbar, text="v0.9.7.X2", font=("Consolas", 8),
             bg=C["panel"], fg=C["muted"]).pack(side="left", padx=(4,0), pady=(10,0))
    tk.Label(topbar, text="FIRST-RUN SETUP", font=("Consolas", 8),
             bg=C["panel"], fg=C["muted"]).pack(side="right", padx=14)

    tk.Frame(root, bg=C["accent"], height=2).pack(fill="x")

