def _pip_install(pkg):
    _ck0 = subprocess.run([sys.executable, "-m", "pip", "--version"],
                          capture_output=True, text=True)
    if _ck0.returncode != 0 or "No module named pip" in (_ck0.stderr + _ck0.stdout):
        try:
            import ensurepip as _ep0; _ep0.bootstrap(upgrade=True)
        except Exception:
            subprocess.run([sys.executable, "-m", "ensurepip", "--upgrade"],
                           capture_output=True, text=True)
        _ck1 = subprocess.run([sys.executable, "-m", "pip", "--version"],
                              capture_output=True, text=True)
        if _ck1.returncode != 0:
            try:
                import urllib.request as _ur0, tempfile as _tmp0, os as _tos0
                _gp0 = _tos0.path.join(_tmp0.gettempdir(), "get-pip.py")
                _ur0.urlretrieve("https://bootstrap.pypa.io/get-pip.py", _gp0)
                if _tos0.path.getsize(_gp0) > 1000:
                    subprocess.run([sys.executable, _gp0, "--quiet"],
                                   capture_output=True, text=True)
            except Exception:
                pass

    _th = ["--trusted-host", "pypi.org",
           "--trusted-host", "files.pythonhosted.org",
           "--trusted-host", "pypi.python.org"]
    strategies = [
        [sys.executable, "-m", "pip", "install", pkg, "--break-system-packages",
         "--no-cache-dir", "-q"] + _th,
        [sys.executable, "-m", "pip", "install", pkg, "--user",
         "--no-cache-dir", "-q"] + _th,
        [sys.executable, "-m", "pip", "install", pkg,
         "--no-cache-dir", "-q"] + _th,
        [sys.executable, "-m", "pip", "install", pkg],
    ]
    for cmd in strategies:
        try:
            subprocess.check_call(cmd, stdout=subprocess.DEVNULL, stderr=subprocess.DEVNULL)
            return True
        except Exception:
            continue
    return False

