import gc as _gc

_gc_last_run   = [0.0]
_gc_run_count  = [0]

def _auto_gc(label: str = ""):
    """Run Python GC if enabled in settings. Thread-safe, never raises."""
    try:
        if not CONFIG.get("auto_gc_enabled", True):
            return
        cooldown = float(CONFIG.get("auto_gc_cooldown_sec", 2.0))
        import time as _t
        now = _t.monotonic()
        if now - _gc_last_run[0] < cooldown:
            return
        _gc_last_run[0] = now

        mode = CONFIG.get("auto_gc_mode", "gen0")
        if mode == "full":
            n = _gc.collect(2)
        elif mode == "gen1":
            n = _gc.collect(1)
        else:
            n = _gc.collect(0)

        _gc_run_count[0] += 1
        if CONFIG.get("debug_mode", False) and n:
            _checkpoint("GC", f"[{label}] freed {n} object(s)  mode={mode}  run#{_gc_run_count[0]}")
    except Exception:
        pass

def _check_admin_startup():
    if not CONFIG.get("require_admin_start", False):
        _checkpoint("INIT", f"Admin check: require_admin_start=False — proceeding as normal user  platform: {sys.platform}")
        return
    if sys.platform == "win32":
        try:
            import ctypes
            if ctypes.windll.shell32.IsUserAnAdmin():
                _checkpoint("INIT", "Admin check: running as ADMINISTRATOR on Windows — OK")
                return

            _checkpoint("INIT", "Admin check: NOT admin on Windows — requesting UAC elevation")
            params = " ".join(f'"{a}"' for a in sys.argv)
            ctypes.windll.shell32.ShellExecuteW(
                None, "runas", sys.executable, params, None, 1
            )
            sys.exit(0)
        except SystemExit:
            raise
        except Exception as _ae:
            _checkpoint("WARN", f"Admin check: UAC elevation failed — {_ae}")
            print(f"[ADMIN] Failed to request elevated privileges: {_ae}")
    else:
        if os.getuid() != 0:
            _checkpoint("WARN", "Admin check: require_admin_start=True but running as non-root on Unix — some features may be limited")
            print("[ADMIN] Warning: app is configured to require root privileges "
                  "but was started as a normal user.")
        else:
            _checkpoint("INIT", "Admin check: running as root on Unix — OK")

_check_admin_startup()

def _is_admin():
    try:
        if sys.platform == "win32":
            import ctypes as _ct
            return bool(_ct.windll.shell32.IsUserAnAdmin())
        else:
            return os.getuid() == 0
    except Exception:
        return False

