import base64 as _b64, struct as _struct, hashlib as _hl

_QUAR_MAGIC   = b"SOCQUAR\x01"
_QUAR_LOCK    = threading.Lock()
_quar_refresh_callbacks = []

def _quar_path_for(filename: str) -> str:
    safe = _b64.urlsafe_b64encode(filename.encode()).decode().rstrip("=")[:64]
    ts   = _time_crash.strftime("%Y%m%d_%H%M%S")
    return os.path.join(QUARANTINE_DIR, f"{safe}_{ts}.quar")

def _quar_quarantine(src_path: str, reason: str = "manual") -> bool:
    if not os.path.isfile(src_path):
        return False
    try:
        with open(src_path, "rb") as f:
            data = f.read()
        md5  = _hl.md5(data).hexdigest()
        sha2 = _hl.sha256(data).hexdigest()

        xor_key = b"SOCQUARANTINE2024"
        obf = bytes(b ^ xor_key[i % len(xor_key)] for i, b in enumerate(data))
        fname_b   = src_path.encode("utf-8")
        reason_b  = reason.encode("utf-8")
        ts_b      = _time_crash.strftime("%Y-%m-%d %H:%M:%S").encode()
        md5_b     = md5.encode(); sha2_b = sha2.encode()

        header = (
            _QUAR_MAGIC
            + _struct.pack(">HHHHH",
                           len(fname_b), len(reason_b),
                           len(ts_b), len(md5_b), len(sha2_b))
            + fname_b + reason_b + ts_b + md5_b + sha2_b
        )
        qpath = _quar_path_for(os.path.basename(src_path))
        with _QUAR_LOCK:
            with open(qpath, "wb") as f:
                f.write(header + obf)
            try:
                os.remove(src_path)
            except PermissionError:
                os.remove(qpath); return False
        _session_log(f"[QUARANTINE] Quarantined: {src_path} → {os.path.basename(qpath)}", "INFO")
        _checkpoint("QUAR", f"Quarantined: {os.path.basename(src_path)} → {os.path.basename(qpath)}  reason: {reason}  md5: {md5[:16]}…")
        _notify("Quarantine", f"In quarantena: {os.path.basename(src_path)}")
        for cb in _quar_refresh_callbacks:
            try: root.after(0, cb)
            except Exception: pass
        return True
    except Exception as e:
        _session_log(f"[QUARANTINE] FAIL quarantine {src_path}: {e}", "ERROR")
        _checkpoint("QUAR", f"Quarantine FAILED: {os.path.basename(src_path)} — {e}")
        return False

def _quar_restore(quar_path: str) -> bool:
    try:
        with _QUAR_LOCK:
            with open(quar_path, "rb") as f:
                raw = f.read()
        if not raw.startswith(_QUAR_MAGIC):
            return False
        offset = len(_QUAR_MAGIC)
        fn_l, re_l, ts_l, md5_l, sha2_l = _struct.unpack(">HHHHH", raw[offset:offset+10])
        offset += 10
        orig_path = raw[offset:offset+fn_l].decode("utf-8"); offset += fn_l
        offset += re_l + ts_l + md5_l + sha2_l
        obf = raw[offset:]
        xor_key = b"SOCQUARANTINE2024"
        data = bytes(b ^ xor_key[i % len(xor_key)] for i, b in enumerate(obf))
        os.makedirs(os.path.dirname(orig_path) if os.path.dirname(orig_path) else ".", exist_ok=True)
        with open(orig_path, "wb") as f:
            f.write(data)
        os.remove(quar_path)
        _session_log(f"[QUARANTINE] Restored: {orig_path}", "INFO")
        for cb in _quar_refresh_callbacks:
            try: root.after(0, cb)
            except Exception: pass
        return True
    except Exception as e:
        _session_log(f"[QUARANTINE] FAIL restore {quar_path}: {e}", "ERROR")
        return False

def _quar_delete(quar_path: str) -> bool:
    try:
        os.remove(quar_path)
        _session_log(f"[QUARANTINE] Deleted (permanent): {quar_path}", "INFO")
        for cb in _quar_refresh_callbacks:
            try: root.after(0, cb)
            except Exception: pass
        return True
    except Exception as e:
        _session_log(f"[QUARANTINE] FAIL delete {quar_path}: {e}", "ERROR")
        return False

def _quar_read_meta(quar_path: str) -> dict:
    try:
        with open(quar_path, "rb") as f:
            raw = f.read(512)
        if not raw.startswith(_QUAR_MAGIC):
            return {}
        offset = len(_QUAR_MAGIC)
        fn_l, re_l, ts_l, md5_l, sha2_l = _struct.unpack(">HHHHH", raw[offset:offset+10])
        offset += 10
        orig_path = raw[offset:offset+fn_l].decode("utf-8",errors="replace"); offset += fn_l
        reason    = raw[offset:offset+re_l].decode("utf-8",errors="replace"); offset += re_l
        ts        = raw[offset:offset+ts_l].decode("utf-8",errors="replace"); offset += ts_l
        md5       = raw[offset:offset+md5_l].decode("utf-8",errors="replace"); offset += md5_l
        sha256    = raw[offset:offset+sha2_l].decode("utf-8",errors="replace")
        fsize     = os.path.getsize(quar_path)
        return {"orig_path": orig_path, "reason": reason, "ts": ts,
                "md5": md5, "sha256": sha256, "quar_file": quar_path,
                "quar_size": fsize}
    except Exception:
        return {"orig_path": "?", "reason": "?", "ts": "?",
                "md5": "?", "sha256": "?", "quar_file": quar_path, "quar_size": 0}

def _quar_list() -> list:
    try:
        return [_quar_read_meta(os.path.join(QUARANTINE_DIR, f))
                for f in sorted(os.listdir(QUARANTINE_DIR))
                if f.endswith(".quar")]
    except Exception:
        return []

def _quar_pe_repair(quar_path: str) -> bool:
    try:
        with open(quar_path, "rb") as f:
            raw = f.read()
        if not raw.startswith(_QUAR_MAGIC):
            return False
        offset = len(_QUAR_MAGIC)
        fn_l, re_l, ts_l, md5_l, sha2_l = _struct.unpack(">HHHHH", raw[offset:offset+10])
        offset += 10
        orig_path = raw[offset:offset+fn_l].decode("utf-8"); offset += fn_l
        offset += re_l + ts_l + md5_l + sha2_l
        obf = raw[offset:]
        xor_key = b"SOCQUARANTINE2024"
        data = bytes(b ^ xor_key[i % len(xor_key)] for i, b in enumerate(obf))

        repaired = data
        if data[:2] == b"MZ" and len(data) > 0x40:
            try:
                import pefile as _pef
                pe = _pef.PE(data=data)
                si = pe.OPTIONAL_HEADER.SizeOfImage
                if si and si < len(data):
                    repaired = data[:si]
                    _session_log(f"[REPAIR] PE trimmed {len(data)} → {si} bytes", "INFO")
            except Exception:
                pass
        repair_path = orig_path + ".repaired"
        with open(repair_path, "wb") as f:
            f.write(repaired)
        os.remove(quar_path)
        _session_log(f"[REPAIR] Saved repaired: {repair_path}", "INFO")
        for cb in _quar_refresh_callbacks:
            try: root.after(0, cb)
            except Exception: pass
        return True
    except Exception as e:
        _session_log(f"[REPAIR] FAIL: {e}", "ERROR")
        return False


