import zipfile, shutil as _shutil

BACKUP_DIR  = os.path.join(BASE_DIR, "_recovery")
BACKUPS_DIR = os.path.join(BASE_DIR, "backups")
BACKUP_FILE = os.path.join(BACKUP_DIR, "soc_backup.zip")
CRITICAL_FILES = [
    "config.json",
    "rules/rules_state.json",
]


_REQUIRED_DIRS = [
    os.path.join(BASE_DIR, "debug_log"),
    os.path.join(BASE_DIR, "reports"),
    os.path.join(BASE_DIR, "quarantine"),
    os.path.join(BASE_DIR, "rules"),
    os.path.join(BASE_DIR, "rules", "external"),
    os.path.join(BASE_DIR, "backups"),
    os.path.join(BASE_DIR, "_recovery"),
]
for _d in _REQUIRED_DIRS:
    try: os.makedirs(_d, exist_ok=True)
    except Exception: pass


def _create_backup():
    os.makedirs(BACKUP_DIR, exist_ok=True)
    try:
        with zipfile.ZipFile(BACKUP_FILE, "w", zipfile.ZIP_DEFLATED) as zf:
            for rel in CRITICAL_FILES:
                fp = os.path.join(BASE_DIR, rel.replace("/", os.sep))
                if os.path.exists(fp):
                    zf.write(fp, rel)
            import json as _json
            manifest = {
                "version": "0.8",
                "timestamp": time.strftime("%Y-%m-%d %H:%M:%S"),
                "files": CRITICAL_FILES,
                "type": "critical_snapshot",
            }
            zf.writestr("_manifest.json", _json.dumps(manifest, indent=2))
        return True
    except Exception as _e:
        print(f"[BACKUP] Warning: {_e}")
        return False


def _create_full_backup(log_fn=None):
    def _log(msg, tag="DIM"):
        if log_fn:
            try: log_fn(msg, tag)
            except Exception: pass
        print(f"[FULL_BACKUP] {msg}")

    os.makedirs(BACKUPS_DIR, exist_ok=True)
    ts = time.strftime("%Y%m%d_%H%M%S")
    bk_path = os.path.join(BACKUPS_DIR, f"backup_{ts}.zip")
    _log(f">_ Creating full backup → {os.path.basename(bk_path)}", "HEAD")


    include_items = []


    main_script = os.path.abspath(sys.argv[0])
    if os.path.isfile(main_script):
        include_items.append((main_script, os.path.basename(main_script)))
        _log(f"  + script: {os.path.basename(main_script)}", "DIM")


    cfg_path = os.path.join(BASE_DIR, "config.json")
    if os.path.isfile(cfg_path):
        include_items.append((cfg_path, "config.json"))
        _log(f"  + config.json", "DIM")


    rules_dir = os.path.join(BASE_DIR, "rules")
    if os.path.isdir(rules_dir):
        count_r = 0
        for root_r, _, files_r in os.walk(rules_dir):
            for fn_r in files_r:
                fp_r = os.path.join(root_r, fn_r)
                rel_r = "rules/" + os.path.relpath(fp_r, rules_dir).replace(os.sep, "/")
                include_items.append((fp_r, rel_r))
                count_r += 1
        _log(f"  + rules/  ({count_r} file(s))", "DIM")


    db_path = os.path.join(BASE_DIR, "scan_history.db")
    if os.path.isfile(db_path):
        include_items.append((db_path, "scan_history.db"))
        _log(f"  + scan_history.db", "DIM")


    bl_path = os.path.join(BASE_DIR, "app_integrity_baseline.json")
    if os.path.isfile(bl_path):
        include_items.append((bl_path, "app_integrity_baseline.json"))
        _log(f"  + app_integrity_baseline.json", "DIM")


    debug_dir_bk = os.path.join(BASE_DIR, "debug_log")
    if os.path.isdir(debug_dir_bk):
        logs_bk = sorted([f for f in os.listdir(debug_dir_bk) if f.endswith(".txt")], reverse=True)
        if logs_bk:
            lp = os.path.join(debug_dir_bk, logs_bk[0])
            include_items.append((lp, f"debug_log/{logs_bk[0]}"))
            _log(f"  + debug_log/{logs_bk[0]}", "DIM")


    wl_path = os.path.join(BASE_DIR, "whitelist.txt")
    if os.path.isfile(wl_path):
        include_items.append((wl_path, "whitelist.txt"))
        _log(f"  + whitelist.txt", "DIM")


    nt_path = os.path.join(BASE_DIR, "notes.txt")
    if os.path.isfile(nt_path):
        include_items.append((nt_path, "notes.txt"))
        _log(f"  + notes.txt", "DIM")


    rs_path = os.path.join(BASE_DIR, "rules", "rules_state.json")
    if os.path.isfile(rs_path):
        pass

    _log(f"  Total items: {len(include_items)}", "DIM")


    try:
        import json as _json_bk
        with zipfile.ZipFile(bk_path, "w", zipfile.ZIP_DEFLATED) as zf:
            for src_path, arc_name in include_items:
                try:
                    zf.write(src_path, arc_name)
                except Exception as _we:
                    _log(f"  SKIP {arc_name}: {_we}", "WARN")
            manifest_bk = {
                "type":      "full_backup",
                "version":   "0.9",
                "timestamp": time.strftime("%Y-%m-%d %H:%M:%S"),
                "base_dir":  BASE_DIR,
                "file_count": len(include_items),
                "platform":  sys.platform,
            }
            zf.writestr("_backup_manifest.json", _json_bk.dumps(manifest_bk, indent=2))
        size_kb = os.path.getsize(bk_path) // 1024
        _log(f">_ Backup completed: {os.path.basename(bk_path)}  ({size_kb} KB)", "OK")
        _log(f"   Path: {bk_path}", "DIM")
        _checkpoint("BACKUP", f"Full backup OK — {os.path.basename(bk_path)}  {size_kb} KB  {len(include_items)} items")


        try:
            all_bk = sorted([f for f in os.listdir(BACKUPS_DIR)
                              if f.startswith("backup_") and f.endswith(".zip")])
            while len(all_bk) > 10:
                old = os.path.join(BACKUPS_DIR, all_bk.pop(0))
                os.remove(old)
                _log(f"  Old backup removed: {os.path.basename(old)}", "DIM")
        except Exception: pass

        return True, bk_path
    except Exception as _e:
        _log(f">_ Backup FAILED: {_e}", "FAIL")
        _checkpoint("BACKUP", f"Full backup FAILED: {_e}")
        return False, str(_e)


def _restore_full_backup(zip_path, log_fn=None):
    def _log(msg, tag="DIM"):
        if log_fn:
            try: log_fn(msg, tag)
            except Exception: pass
        print(f"[RESTORE] {msg}")


    if not zip_path:

        if os.path.isdir(BACKUPS_DIR):
            candidates = sorted([
                os.path.join(BACKUPS_DIR, f)
                for f in os.listdir(BACKUPS_DIR)
                if f.startswith("backup_") and f.endswith(".zip")
            ])
            if candidates:
                zip_path = candidates[-1]
                _log(f">_ Found backup: {os.path.basename(zip_path)}", "OK")

        if not zip_path or not os.path.exists(zip_path):
            src_zips = [
                f for f in os.listdir(BASE_DIR)
                if f.endswith(".zip") and ("vt" in f.lower() or "soc" in f.lower() or "lab" in f.lower())
            ]
            if src_zips:
                src_zips.sort(key=lambda f: os.path.getmtime(os.path.join(BASE_DIR, f)), reverse=True)
                zip_path = os.path.join(BASE_DIR, src_zips[0])
                _log(f">_ Found source ZIP: {src_zips[0]}", "WARN")

    if not zip_path or not os.path.exists(zip_path):
        _log(">_ No backup or source ZIP found.", "FAIL")
        return False, "No backup found"

    _log(f">_ Restoring from: {os.path.basename(zip_path)}", "HEAD")

    try:
        with zipfile.ZipFile(zip_path, "r") as zf:
            names = zf.namelist()
            _log(f"  Contents: {len(names)} file", "DIM")
            restored = 0
            for member in names:
                if member.startswith("_"):
                    continue
                dest = os.path.join(BASE_DIR, member.replace("/", os.sep))
                try:
                    os.makedirs(os.path.dirname(dest) or BASE_DIR, exist_ok=True)
                    with zf.open(member) as src_f, open(dest, "wb") as dst_f:
                        dst_f.write(src_f.read())
                    _log(f"  ✓ {member}", "OK")
                    restored += 1
                except Exception as _me:
                    _log(f"  ✗ {member}: {_me}", "WARN")


        for _dd in _REQUIRED_DIRS:
            try: os.makedirs(_dd, exist_ok=True)
            except Exception: pass

        _log(f">_ Restore completed: {restored} files extracted", "OK")
        _log(f"   Restart the application to apply.", "WARN")
        _checkpoint("RESTORE", f"Full restore OK — {restored} file(s) from {os.path.basename(zip_path)} — restart required")
        return True, f"{restored} files restored"
    except Exception as _e:
        _log(f">_ Restore FAILED: {_e}", "FAIL")
        _checkpoint("RESTORE", f"Full restore FAILED from {os.path.basename(zip_path) if zip_path else 'unknown'}: {_e}")
        return False, str(_e)


def _backup_create_ui(log_fn=None):
    def _worker():
        _create_full_backup(log_fn)
    threading.Thread(target=_worker, daemon=True).start()


def _backup_restore_ui(log_fn=None):
    import tkinter as _tk2
    import tkinter.filedialog as _fd2

    latest = None
    if os.path.isdir(BACKUPS_DIR):
        candidates = sorted([
            os.path.join(BACKUPS_DIR, f)
            for f in os.listdir(BACKUPS_DIR)
            if f.startswith("backup_") and f.endswith(".zip")
        ])
        if candidates:
            latest = candidates[-1]

    def _ask():
        init = BACKUPS_DIR if os.path.isdir(BACKUPS_DIR) else BASE_DIR
        chosen = _fd2.askopenfilename(
            title="Select backup ZIP to restore",
            initialdir=init,
            filetypes=[("ZIP backup", "*.zip"), ("All files", "*.*")]
        )
        if chosen:
            def _worker():
                _restore_full_backup(chosen, log_fn)
            threading.Thread(target=_worker, daemon=True).start()
        elif latest:
            if log_fn:
                log_fn(f">_ No file selected — using latest backup: {os.path.basename(latest)}", "WARN")
            def _worker2():
                _restore_full_backup(latest, log_fn)
            threading.Thread(target=_worker2, daemon=True).start()

    try:
        root.after(0, _ask)
    except Exception:
        _ask()


def _check_critical_files():
    missing = []
    for rel in CRITICAL_FILES:
        fp = os.path.join(BASE_DIR, rel.replace("/", os.sep))
        if not os.path.exists(fp):
            missing.append(rel)
    return missing


def _restore_from_backup():
    if not os.path.exists(BACKUP_FILE):
        return False, "Backup file not found"
    try:
        with zipfile.ZipFile(BACKUP_FILE, "r") as zf:
            for member in zf.namelist():
                if member.startswith("_"): continue
                dest = os.path.join(BASE_DIR, member.replace("/", os.sep))
                os.makedirs(os.path.dirname(dest), exist_ok=True)
                with zf.open(member) as src_f, open(dest, "wb") as dst_f:
                    dst_f.write(src_f.read())
        return True, "OK"
    except Exception as _e:
        return False, str(_e)


