def _log_panel(parent, title, title_color):
    _BLK = "#0a0a10"
    f = tk.Frame(parent, bg=_BLK)

    hdr = tk.Frame(f, bg="#11111b", pady=5, padx=10); hdr.pack(fill=tk.X)
    tk.Label(hdr, text="  ● ● ●", font=("Consolas",8), bg="#11111b", fg=C["overlay0"]).pack(side=tk.LEFT)
    tk.Label(hdr, text=f"  {title}", font=("Consolas",9,"bold"), bg="#11111b", fg=title_color).pack(side=tk.LEFT, padx=6)
    tk.Frame(f, bg=title_color, height=1).pack(fill=tk.X)
    inner = tk.Frame(f, bg=_BLK); inner.pack(fill=tk.BOTH, expand=True)
    sc = tk.Scrollbar(inner, bg=C["surface1"], troughcolor=_BLK,
                      activebackground=C["surface2"], relief="flat", bd=0, width=7)
    txt = tk.Text(inner, bg=_BLK, fg=C["text"], font=("Consolas",9),
                  yscrollcommand=sc.set, relief="flat", bd=0, padx=10, pady=8,
                  wrap="word", cursor="arrow", selectbackground=C["surface2"],
                  insertbackground=C["text"])
    sc.config(command=txt.yview); sc.pack(side=tk.RIGHT, fill=tk.Y); txt.pack(fill=tk.BOTH, expand=True)

    txt.config(state="normal")
    txt.insert(tk.END, f">_ {title.strip()}\n\n", "PROMPT_HDR")
