def _make_scrolled_frame(parent):
    """Return (inner_frame, canvas) for a vertically scrollable area."""
    outer = tk.Frame(parent, bg=C["base"]); outer.pack(fill=tk.BOTH, expand=True)
    sc = tk.Scrollbar(outer, orient="vertical", bg=C["surface1"],
                      troughcolor=C["base"], relief="flat", width=7)
    cv = tk.Canvas(outer, bg=C["base"], bd=0, highlightthickness=0, yscrollcommand=sc.set)
    sc.config(command=cv.yview)
    sc.pack(side=tk.RIGHT, fill=tk.Y); cv.pack(side=tk.LEFT, fill=tk.BOTH, expand=True)
    inner = tk.Frame(cv, bg=C["base"])
    win = cv.create_window((0,0), window=inner, anchor="nw")
    cv.bind("<Configure>", lambda e: cv.itemconfig(win, width=e.width))
    inner.bind("<Configure>", lambda e: cv.configure(scrollregion=cv.bbox("all")))
    return inner, cv

                                                                               
