def _info_refresh():
    try:
        _db_p = os.path.join(BASE_DIR, "scan_history.db")
        _info_sv_db.set(f"{os.path.getsize(_db_p)//1024} KB" if os.path.isfile(_db_p) else "not found")
    except Exception: pass
    try:
        import sqlite3 as _sq
        _con = _sq.connect(os.path.join(BASE_DIR,"scan_history.db"), timeout=2)
        _cur = _con.cursor()
        _cur.execute("SELECT COUNT(*) FROM scans")
        _cnt = _cur.fetchone()
        _info_sv_scans.set(str(_cnt[0]) if _cnt else "0")
        _cur.execute("SELECT timestamp FROM scans ORDER BY id DESC LIMIT 1")
        _last = _cur.fetchone()
        _info_sv_last.set(_last[0] if _last else "—")
        _con.close()
    except Exception: _info_sv_scans.set("—")
    try:
        if _psutil:
            _info_sv_cpu.set(f"{_psutil.cpu_percent(interval=None):.1f}%  ({_psutil.cpu_count()} cores)")
            _vm = _psutil.virtual_memory()
            _info_sv_ram.set(f"{_vm.used//1048576} MB / {_vm.total//1048576} MB  ({_vm.percent:.1f}%)")
    except Exception: pass
    try:
        _keys_ok = [k for k, v in API_KEYS.items() if v and str(v).strip()]
        _info_sv_keys.set(f"{len(_keys_ok)} configured  ·  {', '.join(_keys_ok[:4]) or 'none'}")
    except Exception: pass
    try:
        _rules_d = os.path.join(BASE_DIR, "rules")
        if os.path.isdir(_rules_d):
            _yc = sum(1 for _r,_,_ff in os.walk(_rules_d)
                      for _fn in _ff if _fn.endswith((".yar",".yara")))
            _info_sv_yara.set(f"{_yc} rule file(s)  ·  {_rules_d}")
        else:
            _info_sv_yara.set("rules/ dir not found")
    except Exception: pass

                                                                                
