    if _ls.startswith("## ") or _ls.startswith("# "):
        _readme_txt.tag_add("heading", _start, _end)
    elif _ls.startswith("| ") or _ls.startswith("├") or _ls.startswith("└") or _ls.startswith("│"):
        _readme_txt.tag_add("code", _start, _end)
    elif _ls.startswith("- ") or _ls.startswith("1. "):
        pass
    elif "http" in _ls:
        _readme_txt.tag_add("url", _start, _end)
