def _smart_nav(ref):
    """Navigate to any tab by variable name, handling parent notebooks."""
    tab = globals().get(ref)
    if tab is None:
        return
    _SUB_MAP = {
        "_tab_charts":   (_nb, "_tab_chrt_host",  _chrt_nb),
        "_tab_entropy":  (_nb, "_tab_chrt_host",  _chrt_nb),
        "_tab_ioc":      (_nb, "_tab_ioc_host",   _ioc_nb),
        "_lu_ioc_tab":   (_nb, "_tab_ioc_host",   _ioc_nb),
        "_tab_reput":    (_nb, "_tab_ioc_host",   _ioc_nb),
        "_tab_mitre":    (_nb, "_tab_ioc_host",   _ioc_nb),
        "_tab_feeds":    (_nb, "_tab_ioc_host",   _ioc_nb),
        "_tab_secrets":  (_nb, "_tab_ioc_host",   _ioc_nb),
        "_tab_yara":     (_nb, "_tab_yara_host",  _yara_nb),
        "_tab_deobf":    (_nb, "_tab_yara_host",  _yara_nb),
        "_tab_sandbox":  (_nb, "_tab_sb_host",    _sb_host_nb),
        "_tab_cuckoo":   (_nb, "_tab_sb_host",    _sb_host_nb),
        "_tab_lookup":   (_nb, "_tab_look_host",  _look_nb),
        "_tab_hex":      (_nb, "_tab_look_host",  _look_nb),
        "_tab_regex":    (_nb, "_tab_look_host",  _look_nb),
        "_tab_sig":      (_nb, "_tab_look_host",  _look_nb),
        "_tab_doc":      (_nb, "_tab_look_host",  _look_nb),
        "_tab_macro":    (_nb, "_tab_look_host",  _look_nb),
        "_tab_archive":  (_nb, "_tab_look_host",  _look_nb),
        "_tab_batch":    (_nb, "_tab_look_host",  _look_nb),
        "_tab_diff":     (_nb, "_tab_look_host",  _look_nb),
        "_tab_proc":     (_nb, "_tab_proc_host",  _proc_nb),
        "_tab_reg":      (_nb, "_tab_proc_host",  _proc_nb),
        "_tab_portscan": (None, None,             _net_nb),
        "_tab_pcap":     (None, None,             _net_nb),
    }
    if ref in _SUB_MAP:
        top_nb, parent_ref, sub_nb = _SUB_MAP[ref]
        if top_nb and parent_ref:
            parent = globals().get(parent_ref)
            if parent:
                top_nb.select(parent)
        root.after(30, lambda nb=sub_nb, t=tab: nb.select(t))
    else:
        try:
            _nb.select(tab)
        except Exception:
            pass

