def _dash_populate_recent():
    try:
        for row in _dash_tree.get_children(): _dash_tree.delete(row)
        rows = _db_query(
            "SELECT file, malicious, suspicious, yara_hits, entropy, filetype, timestamp "
            "FROM scans ORDER BY timestamp DESC LIMIT 20")
        for r in rows:
            fp, mal, sus, yara_raw, ent, ftype, ts = r
            fname = os.path.basename(fp or "?")
            try: yara_hits = json.loads(yara_raw or "[]")
            except Exception: yara_hits = []
            if mal and int(mal) > 0:   verdict, tag = f"⚠ {mal} MAL", "MAL"
            elif sus and int(sus) > 0: verdict, tag = f"~ {sus} SUSP", "SUSP"
            elif yara_hits:            verdict, tag = "⚡ YARA", "YARA"
            else:                      verdict, tag = "✓ CLEAN", "OK"
            ent_s = f"{float(ent):.2f}" if ent else "—"
            ts_s  = (ts or "")[-8:] if ts else "—"
            _dash_tree.insert("", tk.END, values=(fname, verdict, ent_s, ftype or "—", ts_s), tags=(tag,))
    except Exception: pass

def _dash_health_tick():
    try:
        if _psutil:
            _dash_sv_cpu.set(f"{_psutil.cpu_percent(interval=None):.0f}%")
            mb = _psutil.Process(os.getpid()).memory_info().rss / 1048576
            _dash_sv_ram.set(f"{mb:.0f} MB")
        else:
            _dash_sv_cpu.set("N/A"); _dash_sv_ram.set("N/A")
        db_sz = os.path.getsize(DB_PATH) / 1024 if os.path.exists(DB_PATH) else 0
        _dash_sv_db.set(f"{db_sz:.1f} KB")
        _dash_sv_thr.set(str(threading.active_count()))
        _dash_keys_sv.set(str(len(API_KEYS)))
        _dash_sv_keys2.set(f"{len(API_KEYS)} key(s)" if API_KEYS else "⚠ None!")
        yr = globals().get("_yara_rules")
        _dash_sv_yara.set("Loaded ✓" if yr else "Not loaded")
    except Exception: pass
    root.after(4000, _dash_health_tick)

