def _ym_tree_dblclick(event):
    for iid in _ym_tree.selection():

        if _ym_tree.parent(iid) == "": continue
        fn = _ym_tree.item(iid, "text").strip()
        with _rules_state_lock:
            cur = _rules_state.get(fn, {})
        new_enabled = not cur.get("enabled", True)
        cat = cur.get("category", "local")
        _state_set(fn, new_enabled, cat)
    _ym_library_refresh()

_ym_tree.bind("<Double-1>", _ym_tree_dblclick)


_ym_search_var.trace_add("write", lambda *a: _ym_library_refresh())
_ym_cat_var.trace_add("write",    lambda *a: _ym_library_refresh())

def _ym_library_refresh():
    for _ch in _ym_tree.get_children(): _ym_tree.delete(_ch)
    search  = _ym_search_var.get().lower().strip()
    cat_flt = _ym_cat_var.get()


    with _rules_state_lock:
        state_snap = dict(_rules_state)
    all_rules = []
    for folder, prefix in [(RULES_DIR, ""), (RULES_EXTERN_DIR, "")]:
        for fn in sorted(os.listdir(folder)):
            if not fn.lower().endswith((".yar", ".yara")): continue
            full    = os.path.join(folder, fn)
            size_b  = os.path.getsize(full)
            size_s  = f"{size_b//1024}KB" if size_b >= 1024 else f"{size_b}B"
            state   = state_snap.get(fn, {})
            cat_key = state.get("category", "local")
            cat_lbl = CAT_LABELS.get(cat_key, cat_key)
            enabled = state.get("enabled", True)
            all_rules.append((fn, cat_key, cat_lbl, enabled, size_s))


    filtered = []
    for fn, cat_key, cat_lbl, enabled, size_s in all_rules:
        if search and search not in fn.lower(): continue
        if cat_flt != "ALL" and cat_lbl != cat_flt: continue
        filtered.append((fn, cat_key, cat_lbl, enabled, size_s))


    cats = {}
    for fn, cat_key, cat_lbl, enabled, size_s in filtered:
        cats.setdefault(cat_lbl, []).append((fn, enabled, size_s))

    n_enabled = n_disabled = 0
    for cat_lbl, rules in sorted(cats.items()):
        en_in_cat = sum(1 for _,e,_ in rules if e)
        cat_id = _ym_tree.insert("", tk.END,
            text=f"  {cat_lbl}",
            values=(f"{en_in_cat}/{len(rules)} enabled", "", ""),
            tags=("cat_hdr",), open=True)
        for fn, enabled, size_s in rules:
            status  = "● ON" if enabled else "○ OFF"
            tag     = "enabled" if enabled else "disabled"
            _ym_tree.insert(cat_id, tk.END,
                text=f"  {fn}",
                values=(cat_lbl, status, size_s),
                tags=(tag,))
            if enabled: n_enabled += 1
            else: n_disabled += 1

    total = n_enabled + n_disabled
    _ym_stats_var.set(f"{n_enabled} enabled  /  {n_disabled} disabled  /  {total} total")

def _ym_toggle_all(enabled: bool):
    with _rules_state_lock:
        snapshot = dict(_rules_state)
    updates = {}
    for fn, meta in snapshot.items():
        cat = meta.get("category", "local")
        updates[fn] = {"enabled": enabled, "category": cat}
    for folder in (RULES_DIR, RULES_EXTERN_DIR):
        try:
            for fn in os.listdir(folder):
                if fn.lower().endswith((".yar",".yara")):
                    cat = updates.get(fn, {}).get("category", "local")
                    updates[fn] = {"enabled": enabled, "category": cat}
        except Exception:
            pass
    with _rules_state_lock:
        _rules_state.update(updates)
        _state_save(dict(_rules_state))
    _ym_library_refresh()

def _ym_toggle_cat(enabled: bool):
    cat_flt = _ym_cat_var.get()
    if cat_flt == "ALL": _ym_toggle_all(enabled); return

    rev = {v:k for k,v in CAT_LABELS.items()}
    cat_key = rev.get(cat_flt, cat_flt)
    with _rules_state_lock:
        snapshot = dict(_rules_state)
    for fn, meta in snapshot.items():
        if meta.get("category","local") == cat_key:
            _state_set(fn, enabled, cat_key)
    _ym_library_refresh()

def _ym_delete_selected():
    to_del = []
    for iid in _ym_tree.selection():
        if _ym_tree.parent(iid) == "": continue
        fn = _ym_tree.item(iid, "text").strip()
        to_del.append(fn)
    if not to_del: return
    if not messagebox.askyesno("Delete Rules",
            f"Delete {len(to_del)} rule file(s)?\nThis cannot be undone."):
        return
    for fn in to_del:
        for folder in (RULES_DIR, RULES_EXTERN_DIR):
            fp = os.path.join(folder, fn)
            if os.path.exists(fp):
                try: os.remove(fp)
                except Exception as e: _yara_log(f"Delete {fn}: {e}", "WARNING")
        with _rules_state_lock:
            _rules_state.pop(fn, None)
    with _rules_state_lock:
        _state_save(dict(_rules_state))
    _yara_log(f"Deleted {len(to_del)} rule(s)", "INFO")
    _ym_library_refresh()

def _ym_recompile():
    _yara_log("Recompiling enabled rules...", "INFO")
    _checkpoint("RULES", "Manual YARA recompile triggered")
    def _do():
        global _yara_rules
        new = _compile_all_rules()
        def _upd():
            global _yara_rules
            _yara_rules = new
            if new:
                _yara_log("Rules active!", "INFO")
                _checkpoint("RULES", "YARA recompile OK — rules loaded and active")
                _ym_library_refresh()
            else:
                _yara_log("No valid rules enabled", "WARNING")
                _checkpoint("RULES", "YARA recompile done — no valid rules loaded")
        root.after(0, _upd)
    threading.Thread(target=_do, daemon=True).start()


