_TI_TIMEOUT = 12

def _ti_abuseipdb(ip: str) -> dict:
    try:
        r = requests.get(
            "https://api.abuseipdb.com/api/v2/check",
            params={"ipAddress": ip, "maxAgeInDays": 90},
            headers={"Accept": "application/json",
                     "Key": CONFIG.get("abuseipdb_key","")},
            timeout=_TI_TIMEOUT)
        if r.status_code == 200:
            d = r.json().get("data", {})
            return {
                "score":      d.get("abuseConfidenceScore", 0),
                "country":    d.get("countryCode", "?"),
                "reports":    d.get("totalReports", 0),
                "isp":        d.get("isp", ""),
                "domain":     d.get("domain", ""),
            }
    except Exception: pass
    return {}

def _ti_malwarebazaar_hash(sha256: str) -> dict:
    try:
        r = requests.post(
            "https://mb-api.abuse.ch/api/v1/",
            data={"query": "get_info", "hash": sha256},
            timeout=_TI_TIMEOUT)
        if r.status_code == 200:
            j = r.json()
            if j.get("query_status") == "hash_not_found":
                return {"found": False}
            data = j.get("data", [{}])[0]
            return {
                "found":       True,
                "file_name":   data.get("file_name", ""),
                "file_type":   data.get("file_type_mime", ""),
                "tags":        data.get("tags", []),
                "signature":   data.get("signature", ""),
                "first_seen":  data.get("first_seen", ""),
                "origin":      data.get("origin_country", ""),
            }
    except Exception: pass
    return {}

def _ti_otx_hash(sha256: str) -> dict:
    try:
        r = requests.get(
            f"https://otx.alienvault.com/api/v1/indicators/file/{sha256}/general",
            headers={"Accept": "application/json"},
            timeout=_TI_TIMEOUT)
        if r.status_code == 200:
            j = r.json()
            pulses = j.get("pulse_info", {}).get("pulses", [])
            return {
                "pulse_count": len(pulses),
                "pulse_names": [p.get("name","") for p in pulses[:5]],
                "malware_families": list({
                    t for p in pulses for t in p.get("tags",[]) if t
                })[:10],
            }
    except Exception: pass
    return {}

def _ti_otx_ip(ip: str) -> dict:
    try:
        r = requests.get(
            f"https://otx.alienvault.com/api/v1/indicators/IPv4/{ip}/general",
            headers={"Accept": "application/json"},
            timeout=_TI_TIMEOUT)
        if r.status_code == 200:
            j = r.json()
            pulses = j.get("pulse_info", {}).get("pulses", [])
            rep = j.get("reputation", 0)
            return {
                "reputation":  rep,
                "pulse_count": len(pulses),
                "country":     j.get("country_name",""),
                "asn":         j.get("asn",""),
            }
    except Exception: pass
    return {}

def _ti_run_all(sha256, ips, log_fn) -> dict:
    results = {"mb": {}, "otx_hash": {}, "ip_reports": {}}
    _checkpoint("TI", f"Threat Intelligence lookup started — SHA256: {sha256[:24]}…  IPs to check: {len(list(ips)[:5])}")
    threads = []
    def _do_mb():
        results["mb"] = _ti_malwarebazaar_hash(sha256)
    def _do_otx():
        results["otx_hash"] = _ti_otx_hash(sha256)
    def _do_ip(ip):
        abuse = _ti_abuseipdb(ip)
        otx   = _ti_otx_ip(ip)
        results["ip_reports"][ip] = {"abuse": abuse, "otx": otx}
    threads.append(threading.Thread(target=_do_mb,  daemon=True))
    threads.append(threading.Thread(target=_do_otx, daemon=True))
    for ip in list(ips)[:5]:
        threads.append(threading.Thread(target=_do_ip, args=(ip,), daemon=True))
    for t in threads: t.start()
    for t in threads: t.join(timeout=15)


    mb = results["mb"]
    if mb.get("found"):
        log_fn(f"MalwareBazaar: KNOWN MALWARE  sig={mb.get('signature','')}  "
               f"tags={mb.get('tags',[])}  first_seen={mb.get('first_seen','')}", "WARNING")
        _checkpoint("TI", f"MalwareBazaar HIT — signature: {mb.get('signature','')}  tags: {mb.get('tags',[])}")
    else:
        log_fn("MalwareBazaar: Not found (clean or unknown)", "DEBUG")
    otx = results["otx_hash"]
    if otx.get("pulse_count",0) > 0:
        log_fn(f"OTX: {otx['pulse_count']} threat pulses  "
               f"families={otx.get('malware_families',[])[:3]}", "WARNING")
        _checkpoint("TI", f"OTX HIT — {otx['pulse_count']} pulses  families: {otx.get('malware_families',[])[:3]}")
    ip_hits = [(ip, rep["abuse"].get("score",0)) for ip, rep in results["ip_reports"].items() if rep["abuse"].get("score",0)>20]
    if ip_hits:
        _checkpoint("TI", f"AbuseIPDB hits — {len(ip_hits)} suspicious IP(s): {', '.join(f'{ip}(score={s})' for ip,s in ip_hits[:3])}")
    _checkpoint("TI", f"TI lookup complete — MB: {'HIT' if mb.get('found') else 'clean'}  OTX_pulses: {otx.get('pulse_count',0)}  IP_reports: {len(results['ip_reports'])}")
    for ip, rep in results["ip_reports"].items():
        score = rep["abuse"].get("score",0)
        if score > 20:
            log_fn(f"AbuseIPDB: {ip}  score={score}  country={rep['abuse'].get('country','?')}  "
                   f"reports={rep['abuse'].get('reports',0)}", "WARNING")
    return results


def _sandbox_run(exe_path, log_fn, duration=10):
    if not _psutil:
        log_fn("psutil required for sandbox", "WARNING"); return {}
    results = {"new_procs":[], "new_conns":[]}
    before_pids  = {p.pid for p in _psutil.process_iter(["pid"])}
    before_conns = set()
    try: before_conns = {(str(c.laddr), str(c.raddr)) for c in _psutil.net_connections() if c.raddr}
    except Exception: pass
    proc = None
    try:
        proc = subprocess.Popen([exe_path],
            creationflags=0x08000000 if sys.platform=="win32" else 0)
        time.sleep(duration)
    except Exception as e: log_fn(f"Launch error: {e}", "ERROR"); return results
    for pid in ({p.pid for p in _psutil.process_iter(["pid"])} - before_pids):
        try:
            p = _psutil.Process(pid)
            results["new_procs"].append({"pid":pid,"name":p.name(),"exe":p.exe()})
            log_fn(f"New process: {p.name()} (PID={pid})", "WARNING")
        except Exception: pass
    try:
        for c in ({(str(c.laddr),str(c.raddr)) for c in _psutil.net_connections() if c.raddr} - before_conns):
            results["new_conns"].append(str(c)); log_fn(f"New connection: {c}", "WARNING")
    except Exception: pass
    for p_info in results["new_procs"]:
        try: _psutil.Process(p_info["pid"]).kill()
        except Exception: pass
    if proc:
        try: proc.kill()
        except Exception: pass
    log_fn(f"Sandbox done: {len(results['new_procs'])} new procs, {len(results['new_conns'])} conns", "INFO")
    return results

def _sandbox_dialog():
    path = filedialog.askopenfilename(title="Choose file to sandbox",
        filetypes=[("Executables","*.exe *.bat *.ps1 *.cmd"),("All","*.*")])
    if not path: return
    if not messagebox.askyesno("SANDBOX WARNING",
        f"This will EXECUTE the file on this machine:\n{path}\n\nUse a VM for safety!\n\nProceed?"):
        return
    _q.put(("SANDBOX:" + path, REPORTS_DIR))
    _log_ops(f"Sandbox queued: {path}", "WARN")


_q       = queue.Queue()
_q_items = []; _q_lk = threading.Lock()

def _sidebar_add(n):
    with _q_lk: _q_items.append(n)
    root.after(0, _sidebar_sync)

def _sidebar_rem(n):
    with _q_lk:
        if n in _q_items: _q_items.remove(n)
    root.after(0, _sidebar_sync)

def _sidebar_sync():
    with _q_lk: items = list(_q_items)
    _qlist.delete(0, tk.END)
    for itm in items:
        s = itm if len(itm)<=24 else "..."+itm[-21:]
        _qlist.insert(tk.END, f"  {s}")
    _sv_queue.set(str(len(items)))

def _worker():
    while True:
        item = _q.get()
        if item is None: break
        path, fbase = (item if isinstance(item,tuple) else (item, REPORTS_DIR))


        if isinstance(path, str) and path.startswith("URL:"):
            url_str = path[4:]
            ts_str  = time.strftime("%Y-%m-%d %H:%M:%S")

            fname = re.sub(r"[^a-zA-Z0-9._-]", "_", url_str)[:60]
            _sidebar_add(fname); _set_status("SCANNING URL", C["mauve"])
            _file_log = []
            redirect_chain = []
            ioc_urls = [url_str]; ioc_ips = []; ioc_domains = []

            def lf_u(msg, cat="DEBUG"):
                _file_log.append(f"[{cat}] {msg}"); _log_debug(f"[URL] {msg}", cat)
            def lo_u(msg, tag="NORM"):
                _file_log.append(f"[INFO] {msg}"); _log_ops(msg, tag); _log_debug(f"[URL] {msg}", "INFO")

            lo_u(f"Scanning URL: {url_str}", "HEAD")


            vt_stats = _vt_scan_url(url_str, lf_u)
            mal = vt_stats.get("malicious", 0); sus = vt_stats.get("suspicious", 0)
            harmless = vt_stats.get("harmless", 0); timeout = vt_stats.get("timeout", 0)
            _tag = "BAD" if mal > 0 else ("WARN" if sus > 0 else "GOOD")
            lo_u(f"VT: malicious={mal}  suspicious={sus}  harmless={harmless}  timeout={timeout}", _tag)
            verdict = "MALICIOUS" if mal > 0 else ("SUSPICIOUS" if sus > 0 else "CLEAN")


            try:
                import urllib.request, ipaddress
                req  = urllib.request.Request(url_str, method="GET",
                           headers={"User-Agent": "Mozilla/5.0 (Windows NT 10.0; Win64; x64)"})
                resp = urllib.request.urlopen(req, timeout=10)
                final_url = resp.geturl()
                if final_url != url_str:
                    redirect_chain.append(final_url)
                    lo_u(f"REDIRECT: {url_str}  ->  {final_url}", "WARN")
                    ioc_urls.append(final_url)
                    host = re.sub(r"https?://([^/:]+).*", r"\1", final_url)
                    ioc_domains.append(host)
                    try:
                        ipaddress.ip_address(host)
                        lo_u(f"REDIRECT TO DIRECT IP: {host}  (suspicious!)", "BAD")
                        ioc_ips.append(host)
                    except ValueError: pass
                else:
                    lo_u("No redirect detected", "DEBUG")
            except Exception as _re:
                lf_u(f"Redirect check: {_re}", "DEBUG")


            try:
                import socket, ipaddress
                host = re.sub(r"https?://([^/:]+).*", r"\1", url_str)
                ioc_domains.append(host)
                resolved = socket.gethostbyname(host)
                ioc_ips.append(resolved)
                try:
                    ip = ipaddress.ip_address(resolved)
                    lo_u(f"DNS: {host}  ->  {resolved}" +
                         ("  (private)" if ip.is_private else ""), "DEBUG")
                except Exception: pass
            except Exception as _de:
                lf_u(f"DNS: {_de}", "DEBUG")


            folder_path = os.path.join(fbase, "URL_" + fname)
            os.makedirs(folder_path, exist_ok=True)
            pcap_path = os.path.join(folder_path, "network_capture.pcap")
            _capture_traffic(pcap_path, lf_u)


            perf = _get_perf()


            txt_path = os.path.join(folder_path, "report.txt")
            try:
                lines = []
                lines.append("=" * 70)
                lines.append("  URL SCAN REPORT")
                lines.append("  " + ts_str)
                lines.append("=" * 70)
                lines.append("")
                lines.append("URL      : " + url_str)
                lines.append("Verdict  : " + verdict)
                lines.append("")
                lines.append("VIRUSTOTAL:")
                lines.append(json.dumps(vt_stats, indent=2))
                lines.append("")
                lines.append("REDIRECT CHAIN:")
                if redirect_chain:
                    for r in redirect_chain: lines.append("  -> " + r)
                else:
                    lines.append("  None")
                lines.append("")
                lines.append("IOCs:")
                if ioc_ips:     lines.append("  IPs:     " + ", ".join(set(ioc_ips)))
                if ioc_domains: lines.append("  Domains: " + ", ".join(set(ioc_domains)))
                if ioc_urls:    lines.append("  URLs:    " + ", ".join(set(ioc_urls)))
                if perf:
                    lines.append("")
                    lines.append("PERFORMANCE:")
                    lines.append("  CPU:    " + str(round(perf.get("cpu_pct",0),1)) + "%")
                    lines.append("  RAM:    " + str(round(perf.get("ram_mb",0),1)) + " MB")
                    lines.append("  SysRAM: " + str(round(perf.get("ram_sys",0),1)) + "%")
                lines.append("")
                lines.append("-" * 70)
                lines.append("SESSION LOG")
                lines.append("-" * 70)
                lines.extend(_file_log)
                with open(txt_path, "w", encoding="utf-8") as rf:
                    rf.write("\n".join(lines))
            except Exception as e:
                lf_u(f"TXT report: {e}", "ERROR")


            html_path = os.path.join(folder_path, "report.html")
            try:
                vc = "#f38ba8" if mal>0 else ("#fab387" if sus>0 else "#a6e3a1")
                rd_rows = "".join(
                    f"<tr><td style='color:#fab387'>{i+1}</td><td>{r}</td></tr>"
                    for i, r in enumerate(redirect_chain)
                ) or "<tr><td colspan='2' style='color:#45475a'>None</td></tr>"
                ioc_rows = ""
                for lbl, items in [("IP", ioc_ips), ("Domain", ioc_domains), ("URL", ioc_urls)]:
                    for v in set(items):
                        ioc_rows += f"<tr><td style='color:#cba6f7'>{lbl}</td><td>{v}</td></tr>"
                vt_rows = "".join(
                    f"<tr><td style='color:#a6adc8'>{k}</td>"
                    f"<td style='color:{"#f38ba8" if k=="malicious" and v>0 else "#a6e3a1"}'>{v}</td></tr>"
                    for k,v in vt_stats.items()
                )
                html = [
                    "<!DOCTYPE html><html lang='en'><head><meta charset='UTF-8'>",
                    "<title>URL Scan - " + url_str[:60] + "</title>",
                    "<style>",
                    "@import url('https://fonts.googleapis.com/css2?family=JetBrains+Mono:wght@400;700&display=swap');",
                    "*{box-sizing:border-box;margin:0;padding:0}",
                    "body{font-family:'JetBrains Mono',monospace;background:#0d0d14;color:#cdd6f4;padding:32px;line-height:1.6}",
                    "h1{font-size:.85rem;color:#89b4fa;letter-spacing:.1em;margin-bottom:4px}",
                    ".url{font-size:1rem;font-weight:700;margin-bottom:8px;word-break:break-all;color:#cdd6f4}",
                    ".verdict{display:inline-block;padding:6px 18px;border-radius:6px;font-weight:700;font-size:1.1rem;margin-bottom:20px}",
                    ".grid{display:grid;grid-template-columns:1fr 1fr;gap:16px;margin-bottom:20px}",
                    ".card{background:#1e1e2e;border-radius:10px;padding:16px}",
                    ".card h2{font-size:.8rem;color:#a6adc8;text-transform:uppercase;letter-spacing:.08em;margin-bottom:10px}",
                    "table{width:100%;border-collapse:collapse}",
                    "td{padding:6px 10px;font-size:.82rem;border-bottom:1px solid #181825}",
                    "tr:last-child td{border:none}",
                    "footer{margin-top:20px;font-size:.7rem;color:#45475a;text-align:right}",
                    "</style></head><body>",
                    "<h1>V0RTEX · URL SCAN REPORT</h1>",
                    "<div class='url'>🌐 " + url_str + "</div>",
                    "<div class='verdict' style='background:" + vc + "20;color:" + vc + "'>" + verdict + "</div>",
                    "<div class='grid'>",
                    "  <div class='card'><h2>VirusTotal</h2><table>" + vt_rows + "</table></div>",
                    "  <div class='card'><h2>Redirects</h2><table>" + rd_rows + "</table></div>",
                    "  <div class='card'><h2>IOCs</h2><table>" + (ioc_rows or "<tr><td style='color:#45475a'>None</td></tr>") + "</table></div>",
                    "</div>",
                    "<footer>Generated " + ts_str + " · V0RTEX v0.9.7.X2 by Vider_06</footer>",
                    "</body></html>",
                ]
                with open(html_path, "w", encoding="utf-8") as hf:
                    hf.write("\n".join(html))
            except Exception as e:
                lf_u(f"HTML report: {e}", "ERROR")

            lo_u(f"URL report saved: {folder_path}", "GOOD")
            root.after(0, _refresh_stats)
            root.after(0, _rep_refresh)
            _sidebar_rem(fname); _set_status("READY", C["green"])
            _q.task_done(); continue


        if isinstance(path, str) and path.startswith("SANDBOX:"):
            exe_path = path[8:]
            bname = os.path.basename(exe_path)
            _sidebar_add(bname); _set_status("SANDBOX", C["peach"])
            sb_log = []
            def lf_sb(msg, cat="DEBUG"):
                sb_log.append(f"[{cat}] {msg}"); _log_debug(f"[SB] {msg}", cat)
            def lo_sb(msg, tag="NORM"):
                sb_log.append(f"[INFO] {msg}"); _log_ops(msg, tag)
            lo_sb(f"Sandbox: {bname}", "WARN")
            sb_results = _sandbox_run(exe_path, lf_sb, duration=10)
            folder_path = os.path.join(fbase, "SANDBOX_" + re.sub(r"[^a-zA-Z0-9._-]","_",bname))
            os.makedirs(folder_path, exist_ok=True)
            with open(os.path.join(folder_path,"report.txt"),"w",encoding="utf-8") as rf:
                rf.write("="*70 + "\n  SANDBOX REPORT\n  " + bname + "\n  " +
                         time.strftime("%Y-%m-%d %H:%M:%S") + "\n" + "="*70 + "\n\n")
                rf.write("NEW PROCESSES:\n")
                for p in sb_results.get("new_procs",[]): rf.write(f"  {p}\n")
                rf.write("\nNEW CONNECTIONS:\n")
                for c in sb_results.get("new_conns",[]): rf.write(f"  {c}\n")
                rf.write("\nSESSION LOG:\n"); rf.write("\n".join(sb_log))
            lo_sb(f"Sandbox report: {folder_path}", "GOOD")
            root.after(0, _rep_refresh)
            _sidebar_rem(bname); _set_status("READY", C["green"])
            _q.task_done(); continue


        fname = os.path.basename(path)

        try:
            _wl_md5 = hashlib.md5(open(path,"rb").read()).hexdigest()
            if path.lower() in _whitelist_set or _wl_md5 in _whitelist_set:
                _log_ops(f"[WHITELIST] Skipped: {fname}", "DIM")
                _checkpoint("SCAN", f"SKIPPED (whitelist): {fname}")
                _q.task_done(); continue
        except Exception: pass
        _sidebar_add(fname); _set_status("SCANNING", C["yellow"])
        _scan_step("HASH", fname)
        _checkpoint("SCAN", f"START — file: {fname}  path: {path}")
        _file_log = []

        def lf(msg, cat="DEBUG"):
            _file_log.append(f"[{cat}] {msg}"); _log_debug(f"[{fname}] {msg}", cat)

        def lo(msg, tag="NORM"):
            _file_log.append(f"[INFO] {msg}"); _log_ops(msg, tag); _log_debug(f"[{fname}] {msg}", "INFO")

        _log_ops("─"*60, "DIM"); _log_ops(f"  {fname}", "HEAD"); _log_ops(f"  {path}", "DIM")


        try:
            md5, sha1, sha256 = _hash_file(path)
            _log_ops(f"MD5     {md5}", "HASH")
            _log_ops(f"SHA1    {sha1}", "HASH")
            _log_ops(f"SHA256  {sha256}", "HASH")
            _checkpoint("HASH", f"{fname} — MD5: {md5[:16]}…  SHA256: {sha256[:24]}…")
        except Exception as e:
            _checkpoint("ERROR", f"Hash FAILED for {fname}: {e}")
            lo(f"Hash failed: {e}", "BAD"); _scan_step(""); _sidebar_rem(fname); _q.task_done(); continue


        ftype   = _magic_type(path)
        try:
            raw_data = open(path,"rb").read()
            ent = _entropy(raw_data)
        except Exception:
            ent = 0.0
        ent_col = "BAD" if ent>7.0 else ("WARN" if ent>6.0 else "GOOD")
        lo(f"Type: {ftype}   Entropy: {ent:.3f}/8.0", ent_col)
        _checkpoint("ENTROPY", f"{fname} — type: {ftype}  entropy: {ent:.4f}/8.0  {'⚠ HIGH' if ent>7.0 else ('~ MED' if ent>6.0 else '✓ LOW')}")


        _scan_step("YARA", fname)
        yara_hits = []
        if _yara_rules:
            try:
                yara_hits = [m.rule for m in _yara_rules.match(path)]
                if yara_hits:
                    lo(f"YARA hits: {', '.join(yara_hits)}", "WARN")
                    _checkpoint("YARA", f"{fname} — {len(yara_hits)} hit(s): {', '.join(yara_hits[:5])}")
                else:
                    lf("No YARA matches", "DEBUG")
                    _checkpoint("YARA", f"{fname} — no matches")
            except Exception as e:
                lf(f"YARA: {e}", "ERROR")
                _checkpoint("YARA", f"{fname} — match ERROR: {e}")
        else:
            _checkpoint("YARA", f"{fname} — no compiled rules loaded, step skipped")


        _scan_step("IOC", fname)
        iocs      = _extract_iocs(path)
        total_ioc = sum(len(v) for v in iocs.values())
        if total_ioc:
            lo(f"IOCs found: {total_ioc} (IPs:{len(iocs['ips'])} Domains:{len(iocs['domains'])} URLs:{len(iocs['urls'])})", "WARN")
        _checkpoint("IOC", f"{fname} — total: {total_ioc}  IPs: {len(iocs.get('ips',[]))}  domains: {len(iocs.get('domains',[]))}  URLs: {len(iocs.get('urls',[]))}")

        _scan_step("VT", fname)
        lo("Uploading to VirusTotal …", "NORM")
        _checkpoint("VT", f"{fname} — submitting to VirusTotal (hash lookup first)")
        vt_stats, _ = _vt_scan(path, lf)
        mal = vt_stats.get("malicious",0); sus = vt_stats.get("suspicious",0); cln = vt_stats.get("undetected",0)
        _tag = "BAD" if mal>0 else ("WARN" if sus>0 else "GOOD")
        lo(f"VT  malicious={mal}  suspicious={sus}  clean={cln}", _tag)
        _checkpoint("VT", f"{fname} — result: malicious={mal}  suspicious={sus}  undetected={cln}  verdict={'MALICIOUS' if mal>0 else ('SUSPICIOUS' if sus>0 else 'CLEAN')}")


        _scan_step("PE", fname)
        _checkpoint("PE", f"{fname} — starting PE/ELF structure analysis")
        pe_info   = _analyze_pe(path, lf)
        susp_apis = _suspicious_api_hits(pe_info)
        if pe_info.get("packer_detected"):
            lo("Packer detected!", "WARN")
            _checkpoint("PE", f"{fname} — ⚠ PACKER DETECTED")
        if susp_apis:
            lo(f"Suspicious APIs: {', '.join(susp_apis.keys())}", "WARN")
            _checkpoint("PE", f"{fname} — suspicious API categories: {', '.join(susp_apis.keys())}  (total {sum(len(v) for v in susp_apis.values())} imports)")
        else:
            _checkpoint("PE", f"{fname} — PE analysis done, no suspicious imports detected  sections: {len(pe_info.get('sections',[]))}")


        try:
            if sys.platform == "win32":
                import ctypes
                attrs = ctypes.windll.kernel32.GetFileAttributesW(path)
                if attrs != -1 and (attrs & 0x2 or attrs & 0x4):
                    lo("HIDDEN/SYSTEM file attribute detected", "WARN")
                    _checkpoint("SCAN", f"{fname} — ⚠ HIDDEN or SYSTEM file attribute set")
        except Exception: pass


        parts = fname.split(".")
        if len(parts) >= 3:
            lo(f"Double extension detected: {fname}", "WARN")
            _checkpoint("SCAN", f"{fname} — ⚠ double extension detected: {'.'.join(parts[-2:])}")


        try:
            import ipaddress
            strings_sample = " ".join(pe_info.get("strings", [])[:200])
            for ip_match in re.findall(r"\b(?:\d{1,3}\.){3}\d{1,3}\b", strings_sample):
                try:
                    ip = ipaddress.ip_address(ip_match)
                    if not ip.is_private and not ip.is_loopback:
                        lo(f"External IP in strings: {ip_match}", "WARN")
                        if ip in iocs.get("ips", []): pass
                        else: iocs.setdefault("ips", []).append(ip_match)
                except Exception: pass
        except Exception: pass


        try:
            if sys.platform == "win32":
                result = subprocess.run(
                    ["powershell", "-NoProfile", "-Command",
                     f"Get-Item -Path '{path}' -Stream * | Select-Object Stream"],
                    capture_output=True, text=True, timeout=5)
                streams = [l.strip() for l in result.stdout.splitlines()
                           if l.strip() and l.strip() not in ("Stream","------","")]
                non_default = [s for s in streams if s != ":$DATA"]
                if non_default:
                    lo(f"ALTERNATE DATA STREAMS (ADS): {', '.join(non_default)}", "BAD")
                    _checkpoint("SCAN", f"{fname} — ⚠ ADS found: {', '.join(non_default)}")
        except Exception: pass


        try:
            import socket
            for domain in iocs.get("domains", [])[:5]:
                try:
                    resolved = socket.gethostbyname(domain)
                    import ipaddress as _ipa
                    ip = _ipa.ip_address(resolved)
                    lf(f"Domain {domain} resolves to {resolved}", "DEBUG")
                    if not ip.is_private:
                        iocs.setdefault("ips", [])
                        if resolved not in iocs["ips"]:
                            iocs["ips"].append(resolved)
                except Exception: pass
        except Exception: pass


        _db_save(path, md5, sha1, sha256, vt_stats, yara_hits, pe_info, iocs, ent, ftype)
        _checkpoint("DB", f"{fname} — scan record saved to scan_history.db")

        base_name   = os.path.splitext(fname)[0]
        folder_path = os.path.join(fbase, base_name)
        os.makedirs(folder_path, exist_ok=True)
        _checkpoint("REPORT", f"{fname} — generating HTML+TXT report in {os.path.basename(folder_path)}/")
        try:
            _generate_report(path, vt_stats, pe_info, iocs, ent, ftype, folder_path)
        except Exception as e:
            lf(f"Report: {e}", "ERROR")
            _checkpoint("REPORT", f"{fname} — HTML report ERROR: {e}")
        _capture_traffic(os.path.join(folder_path,"network_capture.pcap"), lf)


        try:
            with open(os.path.join(folder_path,"report.txt"),"w",encoding="utf-8") as rf:
                rf.write(f"{'='*70}\n  {fname}\n  {time.strftime('%Y-%m-%d %H:%M:%S')}\n{'='*70}\n\n")
                rf.write(f"MD5:    {md5}\nSHA1:   {sha1}\nSHA256: {sha256}\n\n")
                rf.write(f"File Type: {ftype}\nEntropy: {ent:.3f}/8.0\n\n")
                rf.write(f"VIRUSTOTAL:\n{json.dumps(vt_stats,indent=2)}\n\n")
                rf.write(f"YARA: {', '.join(yara_hits) if yara_hits else 'None'}\n\n")
                rf.write("IOCs:\n")
                for k,v in iocs.items():
                    if v: rf.write(f"  {k.upper()}: {', '.join(v[:20])}\n")
                rf.write("\nSUSPICIOUS APIs:\n")
                for cat,apis in susp_apis.items():
                    rf.write(f"  {cat}: {', '.join(apis)}\n")
                rf.write("\nPE INFO:\n")
                for k,v in pe_info.items():
                    if k!="strings": rf.write(f"  {k}: {v}\n")
                rf.write("\nSTRINGS (first 50):\n")
                for s in pe_info.get("strings",[])[:50]: rf.write(f"  {s}\n")

                perf = _get_perf()
                if perf:
                    rf.write(f"\n{'-'*70}\nPERFORMANCE\n{'-'*70}\n")
                    rf.write(f"  CPU:    {perf.get('cpu_pct',0):.1f}%\n")
                    rf.write(f"  RAM:    {perf.get('ram_mb',0):.1f} MB (app)\n")
                    rf.write(f"  SysRAM: {perf.get('ram_sys',0):.1f}%\n")
                rf.write(f"\n{'-'*70}\nSESSION LOG\n{'-'*70}\n")
                rf.write("\n".join(_file_log))
        except Exception as e: lf(f"TXT report: {e}", "ERROR")


        try:
            lo("Running Threat Intelligence checks...", "NORM")
            ti_results = _ti_run_all(sha256, iocs.get("ips",[]), lf)
            mb = ti_results.get("mb",{})
            if mb.get("found"):
                lo(f"⚠ MalwareBazaar HIT: {mb.get('signature','?')}  {mb.get('tags',[])}",  "BAD")
            otx = ti_results.get("otx_hash",{})
            if otx.get("pulse_count",0):
                lo(f"⚠ OTX: {otx['pulse_count']} pulses  families={otx.get('malware_families',[])[:3]}", "WARN")
        except Exception as _tie:
            lf(f"TI error: {_tie}", "ERROR")
            ti_results = {}


        extra_findings = []
        _ext = os.path.splitext(fname)[1].lower()
        if _ext in (".eml", ".msg"):
            try:
                with open(path, "rb") as _ef:
                    _msg = _email_lib.message_from_bytes(_ef.read(),
                              policy=email.policy.default)
                _subj = str(_msg.get("Subject",""))
                _frm  = str(_msg.get("From",""))
                _to   = str(_msg.get("To",""))
                lo(f"Email: From={_frm}  To={_to}  Subject={_subj[:80]}", "NORM")

                for part in _msg.walk():
                    cd = part.get_content_disposition()
                    if cd in ("attachment", "inline"):
                        _aname = part.get_filename("unknown")
                        _adata = part.get_payload(decode=True) or b""
                        extra_findings.append(f"Attachment: {_aname}  ({len(_adata)} bytes)")
                        lo(f"Attachment: {_aname}  {len(_adata)} bytes", "WARN")

                        if any(_aname.lower().endswith(x) for x in
                               (".exe",".dll",".bat",".ps1",".vbs",".js",".scr",".com")):
                            lo(f"SUSPICIOUS attachment: {_aname}", "BAD")

                _body = ""
                for part in _msg.walk():
                    if part.get_content_type() in ("text/html","text/plain"):
                        try: _body += part.get_content() or ""
                        except Exception: pass
                _links = re.findall(r'https?://[^\s<>]{6,200}', _body)[:20]
                if _links:
                    lo(f"Email links ({len(_links)}): {_links[:3]}", "WARN")
                    iocs.setdefault("urls",[]).extend(_links)
            except Exception as _ee:
                lf(f"Email parse: {_ee}", "ERROR")

        elif _ext == ".pdf":
            try:
                with open(path, "rb") as _pf: _pdf_raw = _pf.read()

                _js_count = _pdf_raw.count(b"/JavaScript") + _pdf_raw.count(b"/JS")
                _launch   = _pdf_raw.count(b"/Launch")
                _uri_count= _pdf_raw.count(b"/URI")
                if _js_count:  lo(f"PDF: JavaScript actions ({_js_count})", "BAD")
                if _launch:    lo(f"PDF: Launch actions ({_launch})", "BAD")
                if _uri_count: lo(f"PDF: URI links ({_uri_count})", "WARN")

                for m in re.finditer(rb'/URI\s*\(([^)]+)\)', _pdf_raw):
                    try:
                        uri = m.group(1).decode("utf-8","replace").strip()
                        iocs.setdefault("urls",[]).append(uri)
                    except Exception: pass
                extra_findings.append(f"PDF: JS={_js_count} Launch={_launch} URI={_uri_count}")
            except Exception as _pe:
                lf(f"PDF parse: {_pe}", "ERROR")

        elif _ext in (".docx",".xlsx",".pptx",".xlsm",".docm"):
            try:
                import zipfile
                with zipfile.ZipFile(path, "r") as _zf:
                    _names = _zf.namelist()
                    _has_macro = any("vba" in n.lower() or "macros" in n.lower() for n in _names)
                    if _has_macro:
                        lo("OFFICE: VBA macros detected!", "BAD")
                        extra_findings.append("Office: VBA macros present")

                    for n in _names:
                        if "external" in n.lower():
                            try:
                                _data = _zf.read(n).decode("utf-8","replace")
                                _elinks = re.findall(r'https?://[^\s<>]{6,200}', _data)[:10]
                                if _elinks:
                                    lo(f"Office external links: {_elinks[:3]}", "WARN")
                                    iocs.setdefault("urls",[]).extend(_elinks)
                            except Exception: pass
            except Exception as _oe:
                lf(f"Office parse: {_oe}", "ERROR")


        _SANDBOX_EXTS = {".exe", ".bat", ".cmd", ".ps1", ".vbs", ".js",
                         ".hta", ".scr", ".com", ".jar"}
        if _auto_sandbox_var.get() and _ext in _SANDBOX_EXTS:
            try:
                _sb_timeout = int(_sb_timeout_var_cfg.get())
            except ValueError:
                _sb_timeout = 15
            if _sandbox_built_var.get():
                lo(f"Auto-sandbox: monitored launch  ({_sb_timeout}s)", "WARN")
                try:
                    _snap_before = _fs_snapshot(os.path.dirname(path))
                    _net_before  = _net_snapshot()
                    _auto_proc   = subprocess.Popen([path],
                                                    stdout=subprocess.DEVNULL,
                                                    stderr=subprocess.DEVNULL,
                                                    cwd=_sandbox_dir_var.get())
                    lo(f"Auto-sandbox PID {_auto_proc.pid} started", "PROC" if False else "WARN")
                    time.sleep(_sb_timeout)
                    if _sb_kill_after_var.get():
                        try: _auto_proc.terminate()
                        except Exception: pass
                    _snap_after = _fs_snapshot(os.path.dirname(path))
                    _new_files  = _snap_after - _snap_before
                    _new_conns  = _net_snapshot() - _net_before
                    if _new_files:
                        lo(f"Auto-sandbox: {len(_new_files)} nuovi file creati", "BAD" if len(_new_files)>2 else "WARN")
                    if _new_conns:
                        lo(f"Auto-sandbox: {len(_new_conns)} new network connections", "BAD")
                    if not _new_files and not _new_conns:
                        lo("Auto-sandbox: no changes detected", "GOOD")
                except PermissionError:
                    lo("Auto-sandbox: PermissionError — run as admin", "BAD")
                except Exception as _ase:
                    lo(f"Auto-sandbox error: {_ase}", "BAD")
            else:
                lo("Auto-sandbox enabled but sandbox NOT built (go to SANDBOX SETUP tab)", "WARN")

        lo(f"Done  →  {folder_path}", "GOOD")
        _scan_step("REPORT", fname)

        try:
            if vt_stats.get("malicious",0) > 0:
                _notify("MALICIOUS DETECTED", f"{fname} flagged by {vt_stats['malicious']} engines")
            elif vt_stats.get("suspicious",0) > 0:
                _notify("Suspicious file", f"{fname}: {vt_stats['suspicious']} suspicious")
        except Exception: pass

        if fbase != REPORTS_DIR:
            was_last = _folder_record(fbase, fname, vt_stats, yara_hits, ent, ftype)
            if was_last:
                lo(f"Folder report generated: {os.path.basename(fbase)}", "GOOD")

        root.after(0, _refresh_stats)
        root.after(0, _update_charts)
        root.after(0, _rep_refresh)
        root.after(0, _update_timeline)
        root.after(50, lambda f=fname, i=iocs, a=susp_apis: _update_ioc_tab(f,i,a))
        _checkpoint("SCAN", f"DONE — {fname}  verdict: {'MALICIOUS' if vt_stats.get('malicious',0)>0 else ('SUSPICIOUS' if vt_stats.get('suspicious',0)>0 else 'CLEAN')}  YARA: {len(yara_hits)}  IOC: {total_ioc}  report: {os.path.basename(folder_path)}/")
        _sidebar_rem(fname); _set_status("READY", C["green"])
        _scan_step("DONE", fname)
        _q.task_done()
        _auto_gc("scan_worker")

threading.Thread(target=_worker, daemon=True).start()


def _enqueue(path, base=None):
    _q.put((path, base or REPORTS_DIR))


def _vt_scan_url(url_str, log_fn):
    if not API_KEYS:
        log_fn("No API key configured", "ERROR"); return {}
    with _key_lock:
        global _key_index
        key = API_KEYS[_key_index % len(API_KEYS)]
        _key_index += 1
    headers = {"x-apikey": key, "Content-Type": "application/x-www-form-urlencoded"}
    try:

        url_id = base64.urlsafe_b64encode(url_str.encode()).decode().rstrip("=")

        r = requests.get(f"https://www.virustotal.com/api/v3/urls/{url_id}",
                         headers={"x-apikey": key}, timeout=20)
        if r.status_code == 200:
            stats = r.json().get("data",{}).get("attributes",{}).get("last_analysis_stats",{})
            if stats: log_fn("URL found in VT cache", "INFO"); return stats

        r2 = requests.post("https://www.virustotal.com/api/v3/urls",
                           data={"url": url_str}, headers=headers, timeout=30)
        if r2.status_code not in (200,201):
            log_fn(f"VT submit error {r2.status_code}", "ERROR"); return {}
        analysis_id = r2.json().get("data",{}).get("id","")
        log_fn("URL submitted, polling...", "INFO")

        for attempt in range(20):
            time.sleep(15)
            r3 = requests.get(f"https://www.virustotal.com/api/v3/analyses/{analysis_id}",
                              headers={"x-apikey": key}, timeout=20)
            if r3.status_code == 200:
                data = r3.json().get("data",{})
                status = data.get("attributes",{}).get("status","")
                if status == "completed":
                    return data.get("attributes",{}).get("stats",{})
                log_fn(f"VT polling [{attempt+1}/20] status={status}", "DEBUG")
        log_fn("VT URL scan timeout", "WARNING"); return {}
    except Exception as e:
        log_fn(f"VT URL error: {e}", "ERROR"); return {}

def _scan_url_dialog():
    popup = tk.Toplevel(root)
    popup.title("Scan URL"); popup.resizable(False,False)
    popup.configure(bg=C["surface0"]); popup.geometry("500x200")
    popup.transient(root); popup.grab_set()
    root.update_idletasks()
    x = root.winfo_x() + root.winfo_width()//2 - 250
    y = root.winfo_y() + root.winfo_height()//2 - 100
    popup.geometry(f"+{x}+{y}")

    tk.Label(popup, text="Scan URL with VirusTotal", font=FB,
             bg=C["surface0"], fg=C["mauve"], pady=14).pack()
    tk.Label(popup, text="Enter URL to scan:", font=FS,
             bg=C["surface0"], fg=C["overlay0"]).pack(anchor="w", padx=20)
    url_var = tk.StringVar()
    entry = tk.Entry(popup, textvariable=url_var, font=FM,
                     bg=C["mantle"], fg=C["text"], insertbackground=C["text"],
                     relief="flat", bd=4, width=52)
    entry.pack(padx=20, pady=6, fill=tk.X)
    entry.focus_set()
    status_var = tk.StringVar(value="")
    tk.Label(popup, textvariable=status_var, font=FS, bg=C["surface0"], fg=C["teal"]).pack()

    def _do_scan():
        url_str = url_var.get().strip()
        if not url_str: return
        if not url_str.startswith(("http://","https://")):
            url_str = "https://" + url_str
        status_var.set("Scanning... (may take 1-5 min)")
        popup.update()
        _q.put(("URL:" + url_str, REPORTS_DIR))
        popup.destroy()
        _log_ops(f"URL queued: {url_str}", "DIM")

    btns = tk.Frame(popup, bg=C["surface0"]); btns.pack(pady=4)
    tk.Button(btns, text="  Scan URL  ", command=_do_scan,
              bg=C["mauve"], fg=C["base"], font=FB, relief="flat",
              padx=12, cursor="hand2", bd=0).pack(side=tk.LEFT, padx=6)
    tk.Button(btns, text="  Cancel  ", command=popup.destroy,
              bg=C["surface2"], fg=C["text"], font=FS, relief="flat",
              padx=12, cursor="hand2", bd=0).pack(side=tk.LEFT, padx=6)
    popup.bind("<Return>", lambda e: _do_scan())

def _add_file():
    path = filedialog.askopenfilename()
    if path: _log_ops(f"Queued: {path}", "DIM"); _enqueue(path)

def _add_folder():
    folder = filedialog.askdirectory()
    if not folder: return
    out = os.path.join(REPORTS_DIR, os.path.basename(folder))
    os.makedirs(out, exist_ok=True)
    files_to_scan = []
    for rd, _, files in os.walk(folder):
        for fn in files:
            files_to_scan.append(os.path.join(rd, fn))
    if files_to_scan:
        _folder_register(out, len(files_to_scan))
        for fp in files_to_scan:
            _enqueue(fp, out)
    _log_ops(f"Queued {len(files_to_scan)} file(s) from: {folder}", "DIM")

if _DND:
    def _on_drop(event):
        for p in root.tk.splitlist(event.data):
            if os.path.isdir(p):
                out = os.path.join(REPORTS_DIR, os.path.basename(p))
                os.makedirs(out, exist_ok=True)
                files_to_scan = []
                for rd, _, files in os.walk(p):
                    for fn in files:
                        files_to_scan.append(os.path.join(rd, fn))
                if files_to_scan:
                    _folder_register(out, len(files_to_scan))
                    for fp in files_to_scan:
                        _enqueue(fp, out)
                _log_ops("[DnD] Folder: {} files from {}".format(len(files_to_scan), p), "DIM")
            else:
                _enqueue(p); _log_ops(f"[DnD] {p}", "DIM")
    root.drop_target_register("DND_Files"); root.dnd_bind("<<Drop>>", _on_drop)


