def _update_timeline():
    rows = _db_query(
        "SELECT file, malicious, suspicious, undetected, timestamp "
        "FROM scans ORDER BY timestamp ASC LIMIT 100")
    _tl_fig.clear(); _tl_fig.set_facecolor(C["surface0"])
    ax = _tl_fig.add_subplot(111)
    ax.set_facecolor(C["mantle"])
    for sp in ax.spines.values(): sp.set_color(C["surface2"])
    ax.tick_params(colors=C["overlay0"], labelsize=7)
    ax.set_title("Scan Timeline", color=C["subtext"], fontsize=9, pad=6)

    if not rows:
        ax.text(0.5,0.5,"No scans yet", ha="center", va="center",
                color=C["overlay0"], transform=ax.transAxes)
        _tl_canvas.draw_idle(); return

    xs = list(range(len(rows)))
    mal_vals = [r[1] for r in rows]
    sus_vals = [r[2] for r in rows]
    cln_vals = [r[3] for r in rows]
    labels   = [os.path.basename(r[0])[:12] for r in rows]

    ax.bar(xs, cln_vals, color=C["green"],  alpha=0.8, label="Clean",     width=0.7)
    ax.bar(xs, sus_vals, color=C["yellow"], alpha=0.9, label="Suspicious", width=0.7,
           bottom=cln_vals)
    bot2 = [c+s for c,s in zip(cln_vals, sus_vals)]
    ax.bar(xs, mal_vals, color=C["red"],    alpha=0.9, label="Malicious",  width=0.7,
           bottom=bot2)
    ax.set_xticks(xs); ax.set_xticklabels(labels, rotation=45, ha="right", fontsize=6)
    ax.legend(frameon=False, labelcolor=C["text"], fontsize=8, loc="upper left")

    _tl_fig.subplots_adjust(left=0.05, right=0.98, top=0.90, bottom=0.22)
    _tl_canvas.draw_idle()


    _tl_list.config(state="normal"); _tl_list.delete("1.0", tk.END)
    _tl_list.insert(tk.END, f"{'#':<4} {'Timestamp':<22} {'File':<35} {'Mal':>5} {'Sus':>5} {'Cln':>5}\n", "hdr")
    for i, r in enumerate(rows):
        fn = os.path.basename(r[0])[:34]
        tag = "mal" if r[1]>0 else ("sus" if r[2]>0 else "cln")
        _tl_list.insert(tk.END,
            f"{i+1:<4} {r[4]:<22} {fn:<35} {r[1]:>5} {r[2]:>5} {r[3]:>5}\n", tag)
    _tl_list.config(state="disabled")

