def _fa_analyze():
    path = filedialog.askopenfilename(
        title="Analyze file",
        filetypes=[
            ("All supported", "*.eml *.msg *.pdf *.docx *.xlsx *.pptx *.doc *.xls"),
            ("Email",         "*.eml *.msg"),
            ("PDF",           "*.pdf"),
            ("Office",        "*.docx *.xlsx *.pptx *.doc *.xls"),
            ("All",           "*.*"),
        ])
    if not path: return
    _fa_out.config(state="normal"); _fa_out.delete("1.0",tk.END); _fa_out.config(state="disabled")
    def _do():
        ext = os.path.splitext(path)[1].lower()
        if ext in (".eml", ".msg"):
            _analyze_email_file(path)
        elif ext == ".pdf":
            _analyze_pdf_file(path)
        elif ext in (".docx", ".xlsx", ".pptx", ".doc", ".xls"):
            _analyze_office_file(path)
        else:
            _analyze_generic_file(path)
        _auto_gc("fa_analyze")
    threading.Thread(target=_do, daemon=True).start()

_mkbtn(_fa_ctrl, "📂 Open & Analyze", _fa_analyze, C["peach"], C["base"])

