def _sbs_pick_and_run():
    p = filedialog.askopenfilename(
        title="Choose file to run in sandbox",
        filetypes=[("Executables", "*.exe *.bat *.cmd *.ps1 *.vbs *.js *.hta"),
                   ("All Files", "*.*")])
    if not p: return
    _sbs_run_path.set(os.path.basename(p))
    if not _sandbox_built_var.get():
        _sb_log("Sandbox not built! Click 'Build Sandbox' first", "BAD"); return
    try:
        timeout = int(_sb_timeout_var_cfg.get())
    except ValueError:
        timeout = 15

    def _do():
        _sb_log(f"Starting: {os.path.basename(p)}", "WARN")
        snap_b = _fs_snapshot(os.path.dirname(p)); net_b = _net_snapshot()
        try:
            proc = subprocess.Popen([p], stdout=subprocess.DEVNULL,
                                    stderr=subprocess.DEVNULL,
                                    cwd=_sandbox_dir_var.get())
            _sb_log(f"PID {proc.pid}", "OK")
            time.sleep(timeout)
            if _sb_kill_after_var.get():
                try: proc.terminate()
                except Exception: pass
        except PermissionError:
            _sb_log("PermissionError — run as admin", "BAD"); return
        except Exception as e:
            _sb_log(f"Error: {e}", "BAD"); return
        nf = _fs_snapshot(os.path.dirname(p)) - snap_b
        nc = _net_snapshot() - net_b
        _sb_log(f"Files created: {len(nf)}  |  Connections: {len(nc)}",
                "BAD" if nf or nc else "OK")
        for f in list(nf)[:10]: _sb_log(f"  FILE: {f}", "WARN")
        for c in list(nc)[:10]: _sb_log(f"  NET:  {c}", "WARN")
    threading.Thread(target=_do, daemon=True).start()

