def _sk_api_card(parent, title, endpoint, color, key_cfg_name, hint="", multiline=False, rows=4):
    card = tk.Frame(parent, bg=C["surface0"], padx=12, pady=10)
    card.pack(fill=tk.X, pady=6)


    hdr = tk.Frame(card, bg=C["surface0"]); hdr.pack(fill=tk.X)
    tk.Label(hdr, text=title,    font=FB, bg=C["surface0"], fg=color).pack(side=tk.LEFT)
    tk.Label(hdr, text=endpoint, font=FS, bg=C["surface0"], fg=C["overlay0"]).pack(side=tk.LEFT, padx=10)

    dot_sv = tk.StringVar(value="●")
    dot_lbl = tk.Label(hdr, textvariable=dot_sv, font=("Consolas",11,"bold"),
                       bg=C["surface0"], fg=C["overlay0"])
    dot_lbl.pack(side=tk.RIGHT, padx=6)

    tk.Frame(card, bg=color, height=1).pack(fill=tk.X, pady=(4,6))

    if hint:
        tk.Label(card, text=hint, font=("Consolas",7), bg=C["surface0"],
                 fg=C["overlay0"], wraplength=380, justify="left").pack(anchor="w", pady=(0,4))


    status_sv = tk.StringVar(value="")
    if multiline:
        txt_w = tk.Text(card, height=rows, bg=C["mantle"], fg=C["text"], font=("Consolas",8),
                        insertbackground=C["text"], relief="flat", bd=3, padx=6, pady=4)
        txt_w.pack(fill=tk.X, pady=(0,4))
        existing = CONFIG.get(key_cfg_name, [])
        if isinstance(existing, list):
            for k in existing: txt_w.insert(tk.END, k+"\n")
        elif existing:
            txt_w.insert(tk.END, existing)
        entry_widget = txt_w
    else:
        var = tk.StringVar(value=CONFIG.get(key_cfg_name, ""))
        entry_widget = tk.Entry(card, textvariable=var, font=("Consolas",8), show="•",
                                bg=C["mantle"], fg=C["text"], insertbackground=C["text"],
                                relief="flat", bd=3)
        entry_widget.pack(fill=tk.X, pady=(0,4))


    btn_row = tk.Frame(card, bg=C["surface0"]); btn_row.pack(fill=tk.X)
    status_lbl = tk.Label(btn_row, textvariable=status_sv, font=("Consolas",8),
                          bg=C["surface0"], fg=C["teal"], wraplength=320, justify="left")
    status_lbl.pack(side=tk.LEFT, fill=tk.X, expand=True)

    def _set_status(msg, ok=None):
        status_sv.set(msg)
        if ok is True:
            status_lbl.config(fg=C["green"]); dot_sv.set("●"); dot_lbl.config(fg=C["green"])
        elif ok is False:
            status_lbl.config(fg=C["red"]);   dot_sv.set("●"); dot_lbl.config(fg=C["red"])
        else:
            status_lbl.config(fg=C["yellow"]); dot_sv.set("◌"); dot_lbl.config(fg=C["yellow"])


    entry_widget._set_status = _set_status

    def _test_single():
        _set_status("⏳ testing...", None)
        def _run():
            result, ok = _api_probe(key_cfg_name, entry_widget)
            root.after(0, lambda: _set_status(result, ok))
        threading.Thread(target=_run, daemon=True).start()

    tk.Button(btn_row, text="⚡Test", command=_test_single,
              bg=C["surface1"], fg=color, font=("Consolas",8,"bold"),
              relief="flat", padx=8, pady=2, cursor="hand2", bd=0,
              activebackground=C["surface2"], activeforeground=color
              ).pack(side=tk.RIGHT)

    return card, entry_widget, status_sv


def _api_probe(service_key: str, entry_widget) -> tuple:
    def _get_key():
        try:
            if isinstance(entry_widget, tk.Text):
                lines = [l.strip() for l in entry_widget.get("1.0", tk.END).splitlines() if l.strip()]
                return lines[0] if lines else ""
            return entry_widget.get().strip()
        except Exception: return ""

    key = _get_key()


    if service_key == "api_keys":

        try:
            raw = entry_widget.get("1.0", tk.END) if isinstance(entry_widget, tk.Text) else entry_widget.get()
            keys = [l.strip() for l in raw.splitlines() if len(l.strip()) > 20]
        except Exception: keys = []
        if not keys: return ("– no key configured", None)
        ok_count = 0; detail = ""
        for k in keys[:3]:
            try:
                r = requests.get("https://www.virustotal.com/api/v3/users/me",
                                 headers={"x-apikey": k}, timeout=10)
                if r.status_code == 200:
                    data = r.json().get("data", {}).get("attributes", {})
                    quota = data.get("quotas", {})
                    daily = quota.get("api_requests_daily", {})
                    used  = daily.get("used", "?"); total = daily.get("allowed", "?")
                    plan  = data.get("status", "")
                    detail = f"quota {used}/{total}/day  plan:{plan}"
                    ok_count += 1
                elif r.status_code == 401:
                    detail = "invalid key (401)"
                elif r.status_code == 429:
                    detail = "rate limit reached (429)"; ok_count += 1
                else:
                    detail = f"HTTP {r.status_code}"
            except Exception as e: detail = str(e)[:40]
        if ok_count == len(keys): return (f"✓ {ok_count}/{len(keys)} keys OK — {detail}", True)
        if ok_count > 0:          return (f"⚠ {ok_count}/{len(keys)} keys OK — {detail}", None)
        return (f"✗ no valid key — {detail}", False)


    if service_key == "malwarebazaar_key":
        if not key: return ("– not configured", None)
        try:

            r = requests.post("https://mb-api.abuse.ch/api/v1/",
                              data={"query": "get_taginfo", "tag": "RAT", "limit": "1",
                                    "auth_key": key}, timeout=10)
            if r.status_code == 200:
                js = r.json()
                qstatus = js.get("query_status", "")
                if qstatus in ("ok", "is_available"):
                    return (f"✓ authenticated — query_status: {qstatus}", True)
                elif qstatus == "unauthorized":
                    return ("✗ invalid key (unauthorized)", False)
                else:

                    return (f"⚠ HTTP 200 — query_status: {qstatus}", None)
            return (f"✗ HTTP {r.status_code}", False)
        except Exception as e: return (f"✗ {str(e)[:50]}", False)


    if service_key == "abuseipdb_key":
        if not key: return ("– not configured", None)
        try:
            r = requests.get("https://api.abuseipdb.com/api/v2/check",
                             params={"ipAddress": "8.8.8.8", "maxAgeInDays": "90"},
                             headers={"Key": key, "Accept": "application/json"}, timeout=10)
            if r.status_code == 200:
                js = r.json().get("data", {})
                return (f"✓ OK — IP:{js.get('ipAddress','')} abuseScore:{js.get('abuseConfidenceScore','?')}%", True)
            elif r.status_code == 401:
                return ("✗ invalid key (401 Unauthorized)", False)
            elif r.status_code == 422:
                return ("✗ parametri non validi (422)", False)
            elif r.status_code == 429:
                return ("⚠ daily rate limit reached (429)", None)
            return (f"✗ HTTP {r.status_code}", False)
        except Exception as e: return (f"✗ {str(e)[:50]}", False)


    if service_key == "urlscan_key":
        if not key: return ("– not configured", None)
        try:
            r = requests.get("https://urlscan.io/api/v1/user/",
                             headers={"API-Key": key}, timeout=10)
            if r.status_code == 200:
                js = r.json()
                username = js.get("username", "?")
                limits   = js.get("limits", {})
                pub_used = limits.get("public", {}).get("day", {}).get("used", "?")
                pub_tot  = limits.get("public", {}).get("day", {}).get("limit", "?")
                return (f"✓ {username} — public: {pub_used}/{pub_tot}/day", True)
            elif r.status_code == 400:
                return ("✗ invalid key (400)", False)
            elif r.status_code == 401:
                return ("✗ non autorizzato (401)", False)
            return (f"✗ HTTP {r.status_code}", False)
        except Exception as e: return (f"✗ {str(e)[:50]}", False)


    if service_key == "otx_key":
        if not key: return ("– not configured", None)
        try:
            r = requests.get("https://otx.alienvault.com/api/v1/user/me",
                             headers={"X-OTX-API-KEY": key}, timeout=10)
            if r.status_code == 200:
                js   = r.json()
                user = js.get("username", "?")
                subs = js.get("pulse_count", "?")
                return (f"✓ {user} — {subs} pulse(s)", True)
            elif r.status_code == 403:
                return ("✗ invalid key (403 Forbidden)", False)
            return (f"✗ HTTP {r.status_code}", False)
        except Exception as e: return (f"✗ {str(e)[:50]}", False)


    if service_key == "shodan_key":
        if not key: return ("– not configured", None)
        try:
            r = requests.get(f"https://api.shodan.io/api-info?key={key}", timeout=10)
            if r.status_code == 200:
                js      = r.json()
                plan    = js.get("plan", "?")
                credits = js.get("query_credits", "?")
                scan_cr = js.get("scan_credits", "?")
                return (f"✓ plan:{plan} — query:{credits}cr  scan:{scan_cr}cr", True)
            elif r.status_code == 401:
                return ("✗ invalid key (401)", False)
            return (f"✗ HTTP {r.status_code}", False)
        except Exception as e: return (f"✗ {str(e)[:50]}", False)


    if service_key == "greynoise_key":
        if not key: return ("– not configured", None)
        try:

            r = requests.get("https://api.greynoise.io/v3/community/8.8.8.8",
                             headers={"key": key}, timeout=10)
            if r.status_code == 200:
                js   = r.json()
                name = js.get("name", "")
                riot = js.get("riot", False)
                return (f"✓ community OK — name:{name or '?'} riot:{riot}", True)
            elif r.status_code == 401:
                return ("✗ invalid key (401)", False)
            elif r.status_code == 429:
                return ("⚠ rate limit (429)", None)

            r2 = requests.get("https://api.greynoise.io/v2/noise/quick/8.8.8.8",
                              headers={"key": key}, timeout=10)
            if r2.status_code == 200:
                return ("✓ enterprise endpoint OK", True)
            return (f"✗ HTTP {r.status_code}/{r2.status_code}", False)
        except Exception as e: return (f"✗ {str(e)[:50]}", False)


    if service_key == "hybrid_analysis_key":
        if not key: return ("– not configured", None)
        try:
            r = requests.get("https://www.hybrid-analysis.com/api/v2/key/current",
                             headers={"api-key": key,
                                      "User-Agent": "Falcon Sandbox",
                                      "accept": "application/json"}, timeout=10)
            if r.status_code == 200:
                js    = r.json()
                user  = js.get("auth_level_name", "?")
                limit = js.get("api_rate_limit_monthly", "?")
                used  = js.get("used_monthly_quota", "?")
                return (f"✓ {user} — quota {used}/{limit}/mese", True)
            elif r.status_code == 400:
                return ("✗ invalid key (400)", False)
            elif r.status_code == 401:
                return ("✗ non autorizzato (401)", False)
            return (f"✗ HTTP {r.status_code}", False)
        except Exception as e: return (f"✗ {str(e)[:50]}", False)

    return ("– unknown service", None)


