def _sk_save():
    global API_KEYS, CONFIG

    raw_vt = _vt_box.get("1.0", tk.END).strip()
    new_vt  = [l.strip() for l in raw_vt.splitlines() if len(l.strip()) > 20]
    API_KEYS = new_vt

    def _gv(widget):
        if isinstance(widget, tk.Text): return widget.get("1.0", tk.END).strip()
        return widget.get().strip()

    CONFIG["api_keys"]            = new_vt
    CONFIG["malwarebazaar_key"]   = _gv(_mb_entry)
    CONFIG["abuseipdb_key"]       = _gv(_abuse_entry)
    CONFIG["urlscan_key"]         = _gv(_urlscan_entry)
    CONFIG["otx_key"]             = _gv(_otx_entry)
    CONFIG["shodan_key"]          = _gv(_shodan_entry)
    CONFIG["greynoise_key"]       = _gv(_gn_entry)
    CONFIG["hybrid_analysis_key"] = _gv(_ha_entry)
    try:
        with open(CONFIG_PATH, "w", encoding="utf-8") as f: json.dump(CONFIG, f, indent=2)
        _sk_result_sv.set(f"✓ Saved — VT:{len(new_vt)} key(s) | all APIs persisted to config.json")
        _checkpoint("SETTINGS", f"API keys saved — VT: {len(new_vt)} key(s), MB: {'yes' if CONFIG.get('malwarebazaar_key') else 'no'}, OTX: {'yes' if CONFIG.get('otx_key') else 'no'}, Shodan: {'yes' if CONFIG.get('shodan_key') else 'no'}")
        _refresh_stats()
    except Exception as e:
        _sk_result_sv.set(f"✗ Save error: {e}")
        _checkpoint("ERROR", f"API key save FAILED: {e}")

def _sk_test_all():

    pop = tk.Toplevel(root)
    pop.title("🔌 API Analyzer — Connectivity Test")
    pop.configure(bg="#0d0d14"); pop.geometry("780x520")
    pop.resizable(True, True); pop.transient(root); pop.grab_set()
    root.update_idletasks()
    px = root.winfo_x() + root.winfo_width()//2  - 390
    py = root.winfo_y() + root.winfo_height()//2 - 260
    pop.geometry(f"+{px}+{py}")

    _BG  = "#0d0d14"; _FG  = "#cdd6f4"; _DIM = "#6c7086"
    _GRN = "#a6e3a1"; _RED = "#f38ba8"; _YEL = "#f9e2af"
    _BLU = "#89b4fa"; _MAU = "#cba6f7"

    hdr_f = tk.Frame(pop, bg="#11111b", padx=14, pady=10); hdr_f.pack(fill=tk.X)
    tk.Label(hdr_f, text="🔌  API ANALYZER", font=("Consolas",12,"bold"),
             bg="#11111b", fg=_BLU).pack(side=tk.LEFT)
    prog_sv = tk.StringVar(value="ready")
    tk.Label(hdr_f, textvariable=prog_sv, font=("Consolas",9),
             bg="#11111b", fg=_DIM).pack(side=tk.RIGHT)
    tk.Frame(pop, bg=C["blue"], height=1).pack(fill=tk.X)


    sc = tk.Scrollbar(pop, orient="vertical", bg="#1e1e2e",
                      troughcolor="#0d0d14", relief="flat", bd=0, width=8)
    out = tk.Text(pop, bg=_BG, fg=_FG, font=("Consolas",9),
                  insertbackground=_FG, relief="flat", bd=0,
                  padx=14, pady=10, wrap="word",
                  yscrollcommand=sc.set, state="disabled")
    sc.config(command=out.yview)
    sc.pack(side=tk.RIGHT, fill=tk.Y); out.pack(fill=tk.BOTH, expand=True)

    for tag, col in [("OK",_GRN),("ERR",_RED),("WARN",_YEL),
                     ("HEAD",_MAU),("DIM",_DIM),("BLU",_BLU),("FG",_FG)]:
        out.tag_configure(tag, foreground=col)
    out.tag_configure("BOLD", font=("Consolas",9,"bold"))


    bot = tk.Frame(pop, bg="#11111b", padx=12, pady=8); bot.pack(fill=tk.X, side=tk.BOTTOM)
    close_btn = tk.Button(bot, text="  Close  ", command=pop.destroy,
                          bg=C["surface2"], fg=_FG, font=("Consolas",9),
                          relief="flat", padx=12, cursor="hand2", bd=0)
    close_btn.pack(side=tk.RIGHT)
    retest_sv = tk.StringVar(value="  ⟳ Retest  ")
    retest_btn = tk.Button(bot, textvariable=retest_sv, command=lambda: None,
                           bg=C["blue"], fg=_BG, font=("Consolas",9,"bold"),
                           relief="flat", padx=12, cursor="hand2", bd=0)
    retest_btn.pack(side=tk.RIGHT, padx=6)
    summary_sv = tk.StringVar(value="")
    tk.Label(bot, textvariable=summary_sv, font=("Consolas",8),
             bg="#11111b", fg=_DIM).pack(side=tk.LEFT)

    def _log(msg, tag="FG"):
        out.config(state="normal")
        out.insert(tk.END, msg + "\n", tag)
        out.see(tk.END)
        out.config(state="disabled")
        pop.update_idletasks()


    _api_map = [
        ("api_keys",             "VirusTotal v3",    _vt_box),
        ("malwarebazaar_key",    "MalwareBazaar",    _mb_entry),
        ("abuseipdb_key",        "AbuseIPDB v2",     _abuse_entry),
        ("urlscan_key",          "URLScan.io",       _urlscan_entry),
        ("otx_key",              "AlienVault OTX",   _otx_entry),
        ("shodan_key",           "Shodan",           _shodan_entry),
        ("greynoise_key",        "GreyNoise",        _gn_entry),
        ("hybrid_analysis_key",  "Hybrid Analysis",  _ha_entry),
    ]

    def _run_tests():
        close_btn.config(state="disabled")
        retest_btn.config(state="disabled")
        out.config(state="normal"); out.delete("1.0", tk.END); out.config(state="disabled")

        _log("╔══════════════════════════════════════════════════════════════╗", "HEAD")
        _log("║   API ANALYZER — Key Validation & Connectivity              ║", "HEAD")
        _log("╚══════════════════════════════════════════════════════════════╝\n", "HEAD")

        ok_c = 0; warn_c = 0; err_c = 0; skip_c = 0
        for i, (svc, label, widget) in enumerate(_api_map):
            prog_sv.set(f"{i+1}/{len(_api_map)} — {label}")
            _log(f"  ┌─ {label}", "BLU")

            msg, ok = _api_probe(svc, widget)

            try:
                fn = getattr(widget, "_set_status", None)
                if fn: root.after(0, lambda m=msg, o=ok: fn(m, o))
            except Exception: pass

            if ok is True:
                _log(f"  │  {msg}", "OK"); ok_c += 1
                _log(f"  └─ ✓ PASSED\n", "OK")
            elif ok is False:
                _log(f"  │  {msg}", "ERR"); err_c += 1
                _log(f"  └─ ✗ FAILED\n", "ERR")
            else:
                _log(f"  │  {msg}", "WARN")
                if msg.startswith("–"):
                    _log(f"  └─ ○ SKIP (not configured)\n", "DIM"); skip_c += 1
                else:
                    _log(f"  └─ ⚠ WARNING\n", "WARN"); warn_c += 1

            import time as _tapi; _tapi.sleep(0.25)


        _log("─" * 62, "DIM")
        _log(f"  RESULTS: ✓ {ok_c} OK   ⚠ {warn_c} WARN   ✗ {err_c} FAILED   ○ {skip_c} SKIP", "HEAD")
        _log("─" * 62 + "\n", "DIM")

        if err_c == 0 and ok_c > 0:
            _log("  All configured keys are valid. ✓", "OK")
        elif err_c > 0:
            _log(f"  {err_c} invalid key(s) — check the fields highlighted in red.", "ERR")
        if skip_c == len(_api_map):
            _log("  No keys entered — add your API keys in the cards above.", "WARN")

        root.after(0, lambda: summary_sv.set(
            f"✓ {ok_c}  ⚠ {warn_c}  ✗ {err_c}  ○ {skip_c}"
        ))
        prog_sv.set(f"completed — {ok_c} OK  {err_c} ERR  {warn_c} WARN")
        close_btn.config(state="normal")
        retest_btn.config(state="normal")

    retest_btn.config(command=lambda: threading.Thread(target=_run_tests, daemon=True).start())
    threading.Thread(target=_run_tests, daemon=True).start()

