def _sk_save_cfg():
    try:
        CONFIG["request_delay"]     = int(_sk_delay_var.get())
        CONFIG["tshark_path"]       = _sk_tshark_var.get().strip()
        CONFIG["vt_timeout"]        = int(_sk_timeout_var.get())
        CONFIG["max_file_mb"]       = int(_sk_maxfile_var.get())
        CONFIG["auto_vt_upload"]    = _sk_autovt_var.get()
        CONFIG["auto_yara_compile"] = _sk_autoyr_var.get()
        proxy = _sk_proxy_var.get().strip()
        if proxy: CONFIG["proxy"] = proxy
        else: CONFIG.pop("proxy", None)
        with open(CONFIG_PATH, "w") as f: json.dump(CONFIG, f, indent=2)
        _cfg_result_sv.set("✓ Config saved to config.json")
    except Exception as e: _cfg_result_sv.set(f"✗ {e}")

