def _lq_log(msg, tag="DIM"):
    _lq_out.config(state="normal"); _lq_out.insert(tk.END, msg+"\n", tag)
    _lq_out.see(tk.END); _lq_out.config(state="disabled")

def _lq_lookup():
    h = _lq_hash_var.get().strip()
    if not h: return
    _lq_out.config(state="normal"); _lq_out.delete("1.0",tk.END); _lq_out.config(state="disabled")
    def _do():
        root.after(0, lambda: _lq_log(f"Lookup: {h}", "HEAD"))
        if API_KEYS:
            try:
                r = requests.get(f"https://www.virustotal.com/api/v3/files/{h}",
                                  headers={"x-apikey": API_KEYS[0]}, timeout=15)
                if r.status_code == 200:
                    attr = r.json().get("data",{}).get("attributes",{})
                    stats = attr.get("last_analysis_stats",{})
                    mal = stats.get("malicious",0); sus = stats.get("suspicious",0)
                    tag = "BAD" if mal>0 else ("WARN" if sus>0 else "OK")
                    root.after(0, lambda: _lq_log(f"[VT] mal={mal}  sus={sus}  clean={stats.get('undetected',0)}", tag))
                    names = attr.get("names",[]); ftype = attr.get("type_description","?")
                    root.after(0, lambda: _lq_log(f"[VT] type={ftype}  names={names[:3]}", "DIM"))
                elif r.status_code == 404:
                    root.after(0, lambda: _lq_log("[VT] Hash not found", "WARN"))
                else:
                    root.after(0, lambda: _lq_log(f"[VT] HTTP {r.status_code}", "WARN"))
            except Exception as e: root.after(0, lambda: _lq_log(f"[VT] error: {e}", "BAD"))
        else:
            root.after(0, lambda: _lq_log("[VT] No API key configured", "WARN"))
        try:
            r2 = requests.post("https://mb-api.abuse.ch/api/v1/",
                               data={"query":"get_info","hash":h}, timeout=12)
            if r2.status_code == 200:
                d = r2.json()
                if d.get("query_status") == "ok":
                    info = d.get("data",[{}])[0]
                    root.after(0, lambda: _lq_log(f"[MB] TROVATO  sig={info.get('signature','?')}  tags={info.get('tags','?')}", "BAD"))
                else:
                    root.after(0, lambda: _lq_log("[MB] Hash not found in MalwareBazaar", "OK"))
        except Exception as e: root.after(0, lambda: _lq_log(f"[MB] error: {e}", "WARN"))
        root.after(0, lambda: _lq_log("─"*60, "DIM"))
    threading.Thread(target=_do, daemon=True).start()

_lq_entry_row.bind("<Return>", lambda e: _lq_lookup())
