for _t,_c in [("BAD",C["red"]),("WARN",C["yellow"]),("OK",C["green"]),("DIM",C["overlay0"])]:
    _lb_out.tag_configure(_t, foreground=_c)
_lb_running = threading.Event()
def _lb_run():
    if _lb_running.is_set(): return
    if not API_KEYS: messagebox.showwarning("Bulk","Configure at least one VT key"); return
    hashes = [l.strip() for l in _lb_in.get("1.0",tk.END).splitlines() if len(l.strip()) >= 32]
    if not hashes: return
    _lb_out.config(state="normal"); _lb_out.delete("1.0",tk.END); _lb_out.config(state="disabled")
    _lb_running.set()
    def _do():
        delay = CONFIG.get("request_delay", 15)
        for i, h in enumerate(hashes):
            root.after(0, lambda i=i,n=len(hashes): _lb_prog_sv.set(f"{i+1}/{n}…"))
            try:
                r = requests.get(f"https://www.virustotal.com/api/v3/files/{h}",
                                  headers={"x-apikey": API_KEYS[i % len(API_KEYS)]}, timeout=15)
                if r.status_code == 200:
                    s = r.json().get("data",{}).get("attributes",{}).get("last_analysis_stats",{})
                    mal = s.get("malicious",0)
                    tag = "BAD" if mal>0 else ("WARN" if s.get("suspicious",0)>0 else "OK")
                    line = f"{h[:20]}…  mal={mal}  sus={s.get('suspicious',0)}  clean={s.get('undetected',0)}"
                elif r.status_code == 404: tag="DIM"; line=f"{h[:20]}...  not found"
                else: tag="WARN"; line=f"{h[:20]}…  HTTP {r.status_code}"
            except Exception as e: tag="BAD"; line=f"{h[:20]}…  error: {e}"
            root.after(0, lambda l=line, t=tag: [
                _lb_out.config(state="normal"),
                _lb_out.insert(tk.END, l+"\n", t),
                _lb_out.see(tk.END),
                _lb_out.config(state="disabled"),
            ])
            if i < len(hashes)-1: time.sleep(delay)
        root.after(0, lambda: _lb_prog_sv.set(f"✓ {len(hashes)} hashes completed"))
        _lb_running.clear()
    threading.Thread(target=_do, daemon=True).start()
_mkbtn(_lb_btn_f, "▶ Bulk Check", _lb_run, C["mauve"])
_mkbtn(_lb_btn_f, "■ Stop", lambda: _lb_running.clear(), C["red"])


