def _ls_extract():
    path = _ls_path_sv.get().strip()
    if not path or not os.path.isfile(path):
        messagebox.showwarning("Strings", "Select a valid file first."); return
    minlen  = _ls_minlen.get()
    pattern = _ls_pattern.get().strip()
    enc     = _ls_encoding.get()
    def _worker():
        root.after(0, lambda: _ls_count_sv.set("⏳ Extracting..."))
        try:
            with open(path, "rb") as f: data = f.read()
        except Exception as e:
            root.after(0, lambda: _ls_count_sv.set(f"✗ Error: {e}")); return

        strings = []

        if enc in ("ASCII+Unicode", "ASCII only"):
            import re as _re
            for m in _re.finditer(rb"[\x20-\x7e]{%d,}" % minlen, data):
                strings.append(("A", m.start(), m.group().decode("ascii", errors="replace")))

        if enc in ("ASCII+Unicode", "Unicode only"):
            import re as _re
            for m in _re.finditer(rb"(?:[\x20-\x7e]\x00){%d,}" % minlen, data):
                try:
                    s = m.group().decode("utf-16-le", errors="replace")
                    if len(s) >= minlen:
                        strings.append(("U", m.start(), s))
                except Exception:
                    pass


        if pattern:
            import re as _re
            try:
                patt = _re.compile(pattern, _re.IGNORECASE)
                strings = [(t, o, s) for t, o, s in strings if patt.search(s)]
            except Exception as _pe:
                root.after(0, lambda: _ls_count_sv.set(f"✗ Regex error: {_pe}")); return

        total = len(strings)
        import re as _re

        def _update():
            _ls_txt.config(state="normal")
            _ls_txt.delete("1.0", tk.END)
            for typ, offset, s in strings[:5000]:
                prefix = f"[{typ}] 0x{offset:08X}  "

                tag = ""
                if _re.search(r"https?://|ftp://", s, _re.I):
                    tag = "url"
                elif _re.match(r"\b(?:\d{1,3}\.){3}\d{1,3}\b", s.strip()):
                    tag = "ip"
                elif any(k in s.upper() for k in ["PASSWORD","PASSWD","SECRET","TOKEN","APIKEY","API_KEY"]):
                    tag = "key"
                _ls_txt.insert(tk.END, prefix, "")
                _ls_txt.insert(tk.END, s + "\n", tag if tag else "")
            _ls_txt.config(state="disabled")
            over = f"  (showing first 5000)" if total > 5000 else ""
            _ls_count_sv.set(f"✓ {total} strings found{over}  ·  file: {os.path.basename(path)}")
        root.after(0, _update)
    threading.Thread(target=_worker, daemon=True).start()

def _ls_export():
    path = _ls_path_sv.get().strip()
    if not path: return
    save = filedialog.asksaveasfilename(
        title="Save strings as...", defaultextension=".txt",
        initialfile=os.path.basename(path) + "_strings.txt",
        filetypes=[("Text", "*.txt"), ("All", "*.*")])
    if save:
        content = _ls_txt.get("1.0", tk.END)
        with open(save, "w", encoding="utf-8") as f: f.write(content)
        messagebox.showinfo("Saved", f"Strings exported to:\n{save}")

