def _pr_scan():
    if not _psutil: messagebox.showwarning("Processes","psutil not installed\npip install psutil"); return
    filt = _pr_filter_var.get().strip().lower(); susp_only = _pr_susp_only.get()
    _pr_out.config(state="normal"); _pr_out.delete("1.0",tk.END); _pr_out.config(state="disabled")
    _pr_status_sv.set("Scanning…")
    def _do():
        susp_count = total = 0
        header = f"{'PID':>7}  {'CPU%':>5}  {'MEM MB':>7}  {'THREADS':>7}  {'NAME':<26}  PATH"
        root.after(0, lambda: [
            _pr_out.config(state="normal"),
            _pr_out.insert(tk.END, header+"\n","HEAD"),
            _pr_out.insert(tk.END,"─"*110+"\n","DIM"),
            _pr_out.config(state="disabled"),
        ])
        try: procs = sorted(_psutil.process_iter(["pid","name","exe","cpu_percent","memory_info","num_threads"]), key=lambda p: p.info["pid"])
        except Exception: procs = []
        for p in procs:
            try:
                info = p.info; name = (info.get("name") or "?").lower()
                exe  = (info.get("exe") or "").lower(); pid = info.get("pid",0)
                cpu  = info.get("cpu_percent",0) or 0
                mem  = (info.get("memory_info") or type("x",(),{"rss":0})()).rss / 1048576
                threads = info.get("num_threads", 0) or 0
                if filt and filt not in name and filt not in exe: continue
                score = 0; reasons = []
                if name.replace(".exe","") in _SUSP_PROC_NAMES: score+=3; reasons.append("susp_name")
                if any(sp in exe for sp in _SUSP_PATHS):        score+=2; reasons.append("susp_path")
                if not exe and pid > 4:                          score+=1; reasons.append("no_path")
                if cpu > 80:                                     score+=1; reasons.append(f"cpu={cpu:.0f}%")
                if mem > 500:                                    score+=1; reasons.append(f"mem={mem:.0f}MB")
                if susp_only and score == 0: continue
                total += 1; tag = "BAD" if score>=3 else ("WARN" if score>=1 else "OK")
                if score>0: susp_count += 1
                line = f"{pid:>7}  {cpu:>5.1f}  {mem:>7.1f}  {threads:>7}  {name[:26]:<26}  {exe[:80] or '(no path)'}"
                if reasons: line += f"  ← {', '.join(reasons)}"
                if not _APP_DYING[0]:
                    try:
                        root.after(0, lambda l=line, t=tag: [
                            _pr_out.config(state="normal"), _pr_out.insert(tk.END, l+"\n", t),
                            _pr_out.see(tk.END), _pr_out.config(state="disabled"),
                        ] if not _APP_DYING[0] else None)
                    except Exception: pass
            except (_psutil.NoSuchProcess, _psutil.AccessDenied): continue
        root.after(0, lambda: _pr_status_sv.set(f"✓ {total} processes  ({susp_count} suspicious)") if not _APP_DYING[0] else None)
        if _pr_auto_var.get() and not _APP_DYING[0]:
            try: root.after(10000, _pr_scan)
            except Exception: pass
    threading.Thread(target=_do, daemon=True).start()

def _pr_enqueue_sel():
    if not _psutil: return
    try:
        sel = _pr_out.get("sel.first","sel.last").strip()
        pid = int(sel.split()[0])
        exe = _psutil.Process(pid).exe()
        if exe and os.path.exists(exe): _enqueue(exe); messagebox.showinfo("Queued", f"Added:\n{exe}")
    except Exception: messagebox.showwarning("Selection","Select a process row and try again")

def _pr_kill_sel():
    if not _psutil: messagebox.showwarning("Kill","psutil not installed"); return
    try:

        try:
            sel = _pr_out.get("sel.first","sel.last").strip()
        except tk.TclError:
            sel = ""
        if not sel:
            messagebox.showinfo("Kill Process","Select a row in the process list first."); return


        pid = None
        for line in sel.splitlines():
            tok = line.strip().split()
            if tok:
                try: pid = int(tok[0]); break
                except ValueError: continue
        if pid is None:
            messagebox.showwarning("Kill","Could not parse PID from selection."); return

        proc = _psutil.Process(pid)
        name = proc.name()
        if not messagebox.askyesno("Kill Process",
                f"Kill process?\n\nPID: {pid}\nName: {name}\n\nThis cannot be undone."): return


        import sys as _sys_kill
        if _sys_kill.platform == "win32":
            try:
                proc.terminate()
                import time as _t_kill; _t_kill.sleep(0.3)
                if proc.is_running():
                    proc.kill()
            except _psutil.NoSuchProcess:
                pass
            except _psutil.AccessDenied:
                messagebox.showerror("Kill",
                    f"Access denied killing PID {pid} ({name}).\nTry running as Administrator.")
                return
        else:
            try:
                import os as _os_kill, signal as _sig_kill
                _os_kill.kill(pid, _sig_kill.SIGKILL)
            except PermissionError:
                messagebox.showerror("Kill",
                    f"Permission denied killing PID {pid} ({name}).\nTry running as root.")
                return
        _pr_status_sv.set(f"✓ Killed PID {pid} ({name})")
        root.after(600, _pr_scan)
    except _psutil.NoSuchProcess:
        messagebox.showinfo("Kill","Process already terminated.")
        root.after(300, _pr_scan)
    except Exception as e:
        messagebox.showwarning("Kill", f"Could not kill process: {e}")

def _pr_copy_sel():
    try:
        sel = _pr_out.get("sel.first","sel.last").strip()
        root.clipboard_clear(); root.clipboard_append(sel)
    except Exception: pass

def _pr_export_csv():
    path = filedialog.asksaveasfilename(defaultextension=".csv", filetypes=[("CSV","*.csv")])
    if not path: return
    try:
        with open(path, "w", encoding="utf-8") as f:
            f.write(_pr_out.get("1.0", tk.END))
        messagebox.showinfo("Export", f"Saved: {path}")
    except Exception as e:
        messagebox.showerror("Export", str(e))

