def _nu_log(msg, tag="DIM"):
    _nu_out.config(state="normal"); _nu_out.insert(tk.END, msg+"\n", tag)
    _nu_out.see(tk.END); _nu_out.config(state="disabled")
def _nu_expand():
    url = _nu_url_var.get().strip()
    if not url: return
    if not url.startswith("http"): url = "https://" + url
    _nu_out.config(state="normal"); _nu_out.delete("1.0",tk.END); _nu_out.config(state="disabled")
    def _do():
        root.after(0, lambda: _nu_log(f"Redirect chain: {url}", "HEAD"))
        try:
            sess = requests.Session()
            resp = sess.get(url, allow_redirects=True, timeout=12,
                            headers={"User-Agent":"Mozilla/5.0 (compatible)"})
            chain = resp.history + [resp]
            for i, r in enumerate(chain):
                loc = r.headers.get("Location", r.url)
                tag = "WARN" if r.status_code in (301,302,307,308) else "OK"
                root.after(0, lambda i=i,s=r.status_code,l=loc,t=tag:
                           _nu_log(f"  {i+1}. [{s}] {l}", t))
            final = chain[-1].url
            root.after(0, lambda: _nu_log(f"\n→ Final: {final}",
                        "BAD" if any(x in final.lower() for x in [".tk",".ml","bit.ly","tinyurl"]) else "OK"))
            if API_KEYS:
                import base64 as _b64
                uid = _b64.urlsafe_b64encode(final.encode()).decode().rstrip("=")
                r2 = requests.get(f"https://www.virustotal.com/api/v3/urls/{uid}",
                                   headers={"x-apikey": API_KEYS[0]}, timeout=12)
                if r2.status_code == 200:
                    s2 = r2.json().get("data",{}).get("attributes",{}).get("last_analysis_stats",{})
                    mal = s2.get("malicious",0)
                    root.after(0, lambda m=mal: _nu_log(
                        f"[VT] mal={m}  sus={s2.get('suspicious',0)}",
                        "BAD" if m>0 else "OK"))
        except Exception as e:
            root.after(0, lambda: _nu_log(f"Error: {e}", "BAD"))
    threading.Thread(target=_do, daemon=True).start()
_mkbtn(_nu_ctrl, "🔗 Expand", _nu_expand, C["mauve"])


