def _nr_log(msg, tag="DIM"):
    _nr_out.config(state="normal"); _nr_out.insert(tk.END, msg+"\n", tag)
    _nr_out.see(tk.END); _nr_out.config(state="disabled")

def _nr_lookup():
    import re as _re2
    targets = [t.strip() for t in _nr_entry_sv.get().split(",") if t.strip()]
    if not targets: return
    _nr_out.config(state="normal"); _nr_out.delete("1.0",tk.END); _nr_out.config(state="disabled")
    def _worker():
        for target in targets[:10]:
            root.after(0, lambda t=target: _nr_log(f"\n{'─'*60}\n🔎  {t}", "SECT"))

            is_ip = bool(_re2.match(r'^\d{1,3}(?:\.\d{1,3}){3}$', target))

            try:
                r = requests.get(f"https://ipinfo.io/{target}/json", timeout=8)
                if r.status_code == 200:
                    d = r.json()
                    root.after(0, lambda d=d: [
                        _nr_log(f"[ipinfo]  org={d.get('org','?')}  country={d.get('country','?')}  city={d.get('city','?')}", "INFO"),
                        _nr_log(f"[ipinfo]  hostname={d.get('hostname','?')}  region={d.get('region','?')}", "DIM"),
                    ])
            except Exception as e: root.after(0, lambda e=e: _nr_log(f"[ipinfo] {e}", "WARN"))

            if is_ip:
                ab_key = globals().get("_ABUSEIPDB_KEY","")
                if ab_key:
                    try:
                        r2 = requests.get("https://api.abuseipdb.com/api/v2/check",
                                          params={"ipAddress":target,"maxAgeInDays":90},
                                          headers={"Key":ab_key,"Accept":"application/json"}, timeout=10)
                        if r2.status_code == 200:
                            d2 = r2.json().get("data",{})
                            score = d2.get("abuseConfidenceScore",0)
                            tag2 = "BAD" if score>60 else ("WARN" if score>20 else "OK")
                            root.after(0, lambda d2=d2,tag2=tag2,score=score: _nr_log(
                                f"[AbuseIPDB]  score={score}%  reports={d2.get('totalReports',0)}  usage={d2.get('usageType','?')}", tag2))
                    except Exception as e: root.after(0, lambda e=e: _nr_log(f"[AbuseIPDB] {e}", "WARN"))
                else:
                    root.after(0, lambda: _nr_log("[AbuseIPDB] No key — add ABUSEIPDB_KEY in config.json", "DIM"))

            if API_KEYS:
                try:
                    endpoint = "ip_addresses" if is_ip else "domains"
                    r3 = requests.get(f"https://www.virustotal.com/api/v3/{endpoint}/{target}",
                                      headers={"x-apikey": API_KEYS[0]}, timeout=12)
                    if r3.status_code == 200:
                        a3 = r3.json().get("data",{}).get("attributes",{})
                        st = a3.get("last_analysis_stats",{})
                        mal3 = st.get("malicious",0); sus3 = st.get("suspicious",0)
                        tag3 = "BAD" if mal3>0 else ("WARN" if sus3>0 else "OK")
                        net3 = a3.get("network",""); asn3 = a3.get("asn","")
                        root.after(0, lambda mal3=mal3,sus3=sus3,tag3=tag3: _nr_log(
                            f"[VT]  mal={mal3}  sus={sus3}  clean={st.get('undetected',0)}", tag3))
                        if net3 or asn3:
                            root.after(0, lambda net3=net3,asn3=asn3: _nr_log(
                                f"[VT]  network={net3}  ASN={asn3}", "DIM"))
                    elif r3.status_code == 404:
                        root.after(0, lambda: _nr_log("[VT] Not found", "DIM"))
                    else:
                        root.after(0, lambda c=r3.status_code: _nr_log(f"[VT] HTTP {c}", "WARN"))
                except Exception as e: root.after(0, lambda e=e: _nr_log(f"[VT] {e}", "WARN"))
            else:
                root.after(0, lambda: _nr_log("[VT] No API key", "DIM"))
            root.after(0, lambda: _nr_log("", "DIM"))
    threading.Thread(target=_worker, daemon=True).start()

