import base64 as _b64, struct as _struct

QUARANTINE_DIR = os.path.join(BASE_DIR, "quarantine")
os.makedirs(QUARANTINE_DIR, exist_ok=True)

def _quar_encrypt(data: bytes) -> bytes:
    key = b"V0RTEXQuar0xDEAD"
    return bytes(b ^ key[i % len(key)] for i, b in enumerate(data))

def _quar_store(orig_path: str, reason: str = "manual") -> str | None:
    try:
        import hashlib as _hl, datetime as _dtt
        qid = _dtt.datetime.now().strftime("%Y%m%d_%H%M%S_%f")
        fname = os.path.basename(orig_path)
        qfile = os.path.join(QUARANTINE_DIR, f"{qid}.quar")
        qmeta = os.path.join(QUARANTINE_DIR, f"{qid}.json")
        with open(orig_path, "rb") as f: raw = f.read()
        md5 = _hl.md5(raw).hexdigest()
        sha256 = _hl.sha256(raw).hexdigest()
        enc = _quar_encrypt(raw)
        with open(qfile, "wb") as f: f.write(enc)
        meta = {"qid": qid, "orig_path": orig_path, "filename": fname,
                "size": len(raw), "md5": md5, "sha256": sha256,
                "reason": reason, "timestamp": _dtt.datetime.now().isoformat()}
        with open(qmeta, "w", encoding="utf-8") as f: json.dump(meta, f, indent=2)
        os.remove(orig_path)
        _session_log(f"[QUARANTINE] Stored: {fname} → {qfile}", "WARN")
        return qid
    except Exception as e:
        _session_log(f"[QUARANTINE] Error storing {orig_path}: {e}", "ERROR")
        return None

def _quar_restore(qid: str) -> bool:
    try:
        qfile = os.path.join(QUARANTINE_DIR, f"{qid}.quar")
        qmeta = os.path.join(QUARANTINE_DIR, f"{qid}.json")
        with open(qmeta, "r", encoding="utf-8") as f: meta = json.load(f)
        with open(qfile, "rb") as f: enc = f.read()
        raw = _quar_encrypt(enc)
        dest = meta["orig_path"]
        os.makedirs(os.path.dirname(dest), exist_ok=True)
        with open(dest, "wb") as f: f.write(raw)
        os.remove(qfile); os.remove(qmeta)
        _session_log(f"[QUARANTINE] Restored: {meta['filename']} → {dest}", "INFO")
        return True
    except Exception as e:
        _session_log(f"[QUARANTINE] Error restoring {qid}: {e}", "ERROR")
        return False

def _quar_delete(qid: str) -> bool:
    try:
        for ext in (".quar", ".json"):
            p = os.path.join(QUARANTINE_DIR, f"{qid}{ext}")
            if os.path.exists(p): os.remove(p)
        _session_log(f"[QUARANTINE] Deleted permanently: {qid}", "WARN")
        return True
    except Exception as e:
        _session_log(f"[QUARANTINE] Error deleting {qid}: {e}", "ERROR")
        return False

def _quar_list() -> list:
    items = []
    for fn in os.listdir(QUARANTINE_DIR):
        if fn.endswith(".json"):
            try:
                with open(os.path.join(QUARANTINE_DIR, fn), "r", encoding="utf-8") as f:
                    items.append(json.load(f))
            except Exception: pass
    items.sort(key=lambda x: x.get("timestamp",""), reverse=True)
    return items


