def _def_save_settings():
    try:
        _DEF_SETTINGS["action_on_detect"]             = _def_action_var.get()
        _DEF_SETTINGS["auto_quarantine_threshold"]    = int(_def_thr_var.get())
        _DEF_SETTINGS["entropy_threshold"]            = float(_def_ent_var.get())
        _DEF_SETTINGS["monitor_interval"]             = int(_def_intvl_var.get())
        _DEF_SETTINGS["check_entropy"]                = _def_chk_entropy.get()
        _DEF_SETTINGS["check_pe"]                     = _def_chk_pe.get()
        _DEF_SETTINGS["check_yara"]                   = _def_chk_yara.get()
        _DEF_SETTINGS["check_vt"]                     = _def_chk_vt.get()
        _DEF_SETTINGS["check_strings"]                = _def_chk_strings.get()
        _DEF_SETTINGS["check_size"]                   = _def_chk_size.get()
        _DEF_SETTINGS["deep_scan_imports"]            = _def_chk_imports.get()
        _DEF_SETTINGS["scan_extensions"]              = _def_ext_var.get().split()

        CONFIG["defense_settings"] = dict(_DEF_SETTINGS)
        with open(CONFIG_PATH, "w") as f: json.dump(CONFIG, f, indent=2)
        _def_stg_result_sv.set("✓ Defense settings saved")
    except Exception as e:
        _def_stg_result_sv.set(f"✗ {e}")

