_AP_BUILT_FLAG = os.path.join(BASE_DIR, ".app_protection_built")

def _ap_build_defense():
    def _worker():
        root.after(0, lambda: _ap_bd_write(">_ BUILD App Defense — starting...", "HEAD"))
        protected = []


        if _ap_bd_prot_cfg.get():
            protected.append(("config.json", CONFIG_PATH))
        if _ap_bd_prot_rules.get():
            protected.append(("rules/ dir", RULES_DIR))
            protected.append(("rules/external/ dir", RULES_EXTERN_DIR))
        if _ap_bd_prot_db.get():
            db_path = os.path.join(BASE_DIR, "scan_history.db")
            protected.append(("scan_history.db", db_path))
        if _ap_bd_prot_mods.get():
            mods_dir = os.path.join(BASE_DIR, "modules")
            if os.path.isdir(mods_dir):
                protected.append(("modules/ dir", mods_dir))
        if _ap_bd_prot_logs.get():
            log_dir = os.path.join(BASE_DIR, "debug_log")
            if os.path.isdir(log_dir):
                protected.append(("debug_log/ dir", log_dir))


        added_to_def = 0
        try:
            if "scan_folder" in _DEF_SETTINGS:
                _DEF_SETTINGS.setdefault("protected_paths", [])
                for name, path in protected:
                    folder = path if os.path.isdir(path) else os.path.dirname(path)
                    if folder and folder not in _DEF_SETTINGS.get("protected_paths", []):
                        _DEF_SETTINGS.setdefault("protected_paths", []).append(folder)
                        added_to_def += 1
        except Exception as e:
            root.after(0, lambda ex=e: _ap_bd_write(f"  DEF register warning: {ex}", "WARN"))


        import hashlib as _hl_bd, json as _jbd
        baseline = {}
        for name, path in protected:
            if os.path.isfile(path):
                try:
                    with open(path, "rb") as _f: data = _f.read()
                    rel = os.path.relpath(path, BASE_DIR)
                    baseline[rel] = {"sha256": _hl_bd.sha256(data).hexdigest(), "size": len(data)}
                    root.after(0, lambda n=name, r=rel: _ap_bd_write(f"  ✓ {n}  →  hash OK", "OK"))
                except Exception as e:
                    root.after(0, lambda n=name, ex=e: _ap_bd_write(f"  ✗ {n}: {ex}", "FAIL"))
            elif os.path.isdir(path):
                count = 0
                for fn in os.listdir(path):
                    fp = os.path.join(path, fn)
                    if os.path.isfile(fp):
                        try:
                            with open(fp, "rb") as _f: data = _f.read()
                            rel = os.path.relpath(fp, BASE_DIR)
                            baseline[rel] = {"sha256": _hl_bd.sha256(data).hexdigest(), "size": len(data)}
                            count += 1
                        except Exception: pass
                root.after(0, lambda n=name, ct=count: _ap_bd_write(f"  ✓ {n}  →  {ct} file(s) indicizzati", "OK"))


        bp = os.path.join(BASE_DIR, "app_integrity_baseline.json")
        try:
            with open(bp, "w", encoding="utf-8") as _f:
                _jbd.dump({"timestamp": __import__("datetime").datetime.now().isoformat(),
                            "files": baseline, "built_by": "BUILD App Defense"}, _f, indent=2)
            root.after(0, lambda n=len(baseline): _ap_bd_write(f">_ Baseline saved: {n} file → {bp}", "OK"))
        except Exception as e:
            root.after(0, lambda ex=e: _ap_bd_write(f">_ Baseline save failed: {ex}", "FAIL"))


        try:
            with open(_AP_BUILT_FLAG, "w") as _f:
                _f.write(__import__("datetime").datetime.now().isoformat())
        except Exception: pass

        root.after(0, lambda n=len(protected): _ap_bd_write(
            f"\n>_ BUILD COMPLETE — {n} elements protected, {added_to_def} folders added to Defense Mode", "HEAD"))
        root.after(0, lambda: _notify("App Protection", f"Build completed: {len(protected)} elements protected"))
    threading.Thread(target=_worker, daemon=True).start()

def _ap_destroy_defense():
    if not messagebox.askyesno("DESTROY App Defense",
        "⚠ Remove all protection rules built for this app?\n\n"
        "The following will be deleted:\n"
        " • app_integrity_baseline.json\n"
        " • .app_protection_built\n\n"
        "Lab files will NOT be modified.",
        icon="warning"): return

    _ap_bd_write(">_ DESTROY App Defense — removing protection...", "WARN")
    removed = []
    for p in [os.path.join(BASE_DIR, "app_integrity_baseline.json"), _AP_BUILT_FLAG]:
        if os.path.exists(p):
            try: os.remove(p); removed.append(os.path.basename(p))
            except Exception as e: _ap_bd_write(f"  ✗ {p}: {e}", "FAIL")
    if removed:
        _ap_bd_write(f">_ Rimossi: {', '.join(removed)}", "OK")
        _ap_bd_write(">_ Protection DESTROYED — the lab is no longer monitored", "WARN")
    else:
        _ap_bd_write(">_ No protection files found (already removed?)", "DIM")

