_AP_BASELINE_PATH = os.path.join(BASE_DIR, "app_integrity_baseline.json")

def _ap_build_baseline():
    def _worker():
        import hashlib as _hl3, json as _j3
        root.after(0, lambda: _ap_int_write(">_ Building integrity baseline...", "HEAD"))
        baseline = {}
        py_files = []
        for root_d, dirs, files in os.walk(BASE_DIR):
            dirs[:] = [d for d in dirs if d not in ("__pycache__", ".git", "quarantine")]
            for fn in files:
                if fn.endswith((".py", ".yar", ".yara", ".json")):
                    py_files.append(os.path.join(root_d, fn))
        for fp in py_files:
            try:
                with open(fp, "rb") as _f: data = _f.read()
                h = _hl3.sha256(data).hexdigest()
                rel = os.path.relpath(fp, BASE_DIR)
                baseline[rel] = {"sha256": h, "size": len(data)}
                root.after(0, lambda r=rel, hx=h[:16]: _ap_int_write(f"  {r}  →  {hx}...", "DIM"))
            except Exception as e:
                root.after(0, lambda r=fp, ex=e: _ap_int_write(f"  SKIP {r}: {ex}", "WARN"))
        try:
            with open(_AP_BASELINE_PATH, "w", encoding="utf-8") as _f:
                _j3.dump({"timestamp": __import__("datetime").datetime.now().isoformat(),
                           "files": baseline}, _f, indent=2)
            root.after(0, lambda n=len(baseline): _ap_int_write(
                f">_ Baseline saved: {n} file → {_AP_BASELINE_PATH}", "OK"))
        except Exception as e:
            root.after(0, lambda ex=e: _ap_int_write(f">_ Save failed: {ex}", "FAIL"))
    threading.Thread(target=_worker, daemon=True).start()

def _ap_verify_integrity():
    if not os.path.exists(_AP_BASELINE_PATH):
        messagebox.showwarning("Integrity", "No baseline found.\nRun 'Build Baseline' first."); return
    def _worker():
        import hashlib as _hl3, json as _j3
        root.after(0, lambda: _ap_int_write(">_ Verifying app integrity...", "HEAD"))
        try:
            with open(_AP_BASELINE_PATH, "r", encoding="utf-8") as _f:
                saved = _j3.load(_f)
        except Exception as e:
            root.after(0, lambda ex=e: _ap_int_write(f"Cannot read baseline: {ex}", "FAIL")); return
        baseline = saved.get("files", {})
        ok = changed = missing = 0
        for rel, info in baseline.items():
            fp = os.path.join(BASE_DIR, rel)
            if not os.path.exists(fp):
                missing += 1
                root.after(0, lambda r=rel: _ap_int_write(f"  ✗ MANCANTE: {r}", "FAIL"))
                continue
            try:
                with open(fp, "rb") as _f: data = _f.read()
                h = __import__("hashlib").sha256(data).hexdigest()
                if h != info["sha256"]:
                    changed += 1
                    root.after(0, lambda r=rel: _ap_int_write(f"  ⚠ MODIFICATO: {r}", "WARN"))
                else:
                    ok += 1
                    root.after(0, lambda r=rel: _ap_int_write(f"  ✓ OK: {r}", "OK"))
            except Exception as e:
                root.after(0, lambda r=rel, ex=e: _ap_int_write(f"  ERROR {r}: {ex}", "FAIL"))
        root.after(0, lambda o=ok,c=changed,m=missing: _ap_int_write(
            f"\n>_ Risultato: {o} OK  |  {c} MODIFICATI  |  {m} MANCANTI", "HEAD"))
        if changed > 0 or missing > 0:
            root.after(0, lambda: _notify("⚠ Integrity Check",
                       f"{changed} modified, {missing} missing", urgent=True))
    threading.Thread(target=_worker, daemon=True).start()

