def _pd_quar_refresh():
    _pd_qtree.delete(*_pd_qtree.get_children())
    import time as _qt
    try:
        for fn in sorted(os.listdir(QUARANTINE_DIR)):
            fp = os.path.join(QUARANTINE_DIR, fn)
            ts = _qt.strftime("%Y-%m-%d %H:%M", _qt.localtime(os.path.getmtime(fp)))
            _pd_qtree.insert("", "end", values=(fn, ts, "—", "quarantined"))
    except Exception: pass

root.after(1200, _pd_quar_refresh)

