def _pd_restore_sel():
    sel = _pd_qtree.selection()
    if not sel: messagebox.showinfo("Quarantine","Select a file first."); return
    fn = _pd_qtree.item(sel[0])["values"][0]
    try:
        from tkinter import filedialog as _pfd
        dest = _pfd.askdirectory(title="Restore destination?")
        if not dest: return
        import shutil
        src = os.path.join(QUARANTINE_DIR, fn)
        dst = os.path.join(dest, fn)
        shutil.copy2(src, dst)
        messagebox.showinfo("Restore",f"File copied to:\n{dst}")
    except Exception as e: messagebox.showerror("Error", str(e))

def _pd_delete_sel():
    sel = _pd_qtree.selection()
    if not sel: return
    fn = _pd_qtree.item(sel[0])["values"][0]
    if not messagebox.askyesno("Delete","Permanently delete this file?"): return
    try:
        os.remove(os.path.join(QUARANTINE_DIR, fn))
        _pd_quar_refresh(); _quarantine_refresh()
    except Exception as e: messagebox.showerror("Error", str(e))

