def _ap_apply_protection():
    actions = []
    if _ap_lock_config.get():
        try:
            if sys.platform == "win32":
                subprocess.run(["attrib", "+R", CONFIG_PATH], capture_output=True)
            else:
                import stat as _stat
                current = os.stat(CONFIG_PATH).st_mode
                os.chmod(CONFIG_PATH, current & ~(_stat.S_IWRITE | _stat.S_IWGRP | _stat.S_IWOTH))
            actions.append("config.json locked")
        except Exception as e:
            actions.append(f"lock failed: {e}")
    if _ap_protect_cfg.get():   actions.append("config.json monitored")
    if _ap_protect_rules.get(): actions.append("YARA rules monitored")
    if _ap_protect_db.get():    actions.append("Database monitored")
    if actions:
        _ap_sd_result_sv.set("✓ Protection applied: " + " | ".join(actions[:2]))
        _notify("App Protection", f"Applied: {len(actions)} protection(s)")
    else:
        _ap_sd_result_sv.set("No option selected.")

def _ap_unlock_config():
    try:
        if sys.platform == "win32":
            subprocess.run(["attrib", "-R", CONFIG_PATH], capture_output=True)
        else:
            import stat as _stat2
            os.chmod(CONFIG_PATH, _stat2.S_IRUSR | _stat2.S_IWUSR | _stat2.S_IRGRP | _stat2.S_IROTH)
        _ap_sd_result_sv.set("✓ config.json unlocked.")
    except Exception as e:
        _ap_sd_result_sv.set(f"✗ Unlock failed: {e}")

