def _reset_db():
    if not messagebox.askyesno("Reset DB","Delete ALL scan history?"): return
    try:
        with _db_lock: _conn.execute("DELETE FROM scans"); _conn.commit()
        _refresh_stats(); _update_charts(); messagebox.showinfo("Done","Database cleared.")
    except Exception as e: messagebox.showerror("Error", str(e))
def _reset_reports():
    import shutil
    if not messagebox.askyesno("Delete Reports","Delete ALL report folders?"): return
    try:
        for d in os.listdir(REPORTS_DIR):
            full = os.path.join(REPORTS_DIR, d)
            if os.path.isdir(full): shutil.rmtree(full)
        _rep_refresh(); messagebox.showinfo("Done","All reports deleted.")
    except Exception as e: messagebox.showerror("Error", str(e))
def _reset_logs():
    for f in os.listdir(DEBUG_DIR):
        try: os.remove(os.path.join(DEBUG_DIR, f))
        except Exception: pass
    _clear_logs(); messagebox.showinfo("Done","Logs cleared.")
def _dz_vacuum_db():
    try:
        with _db_lock: _conn.execute("VACUUM"); _conn.commit()
        size = os.path.getsize(DB_PATH)/1024
        messagebox.showinfo("VACUUM", f"DB compacted — {size:.1f} KB")
    except Exception as e: messagebox.showerror("Error", str(e))
