def _dz_full_backup():
    import shutil, zipfile
    from tkinter import filedialog as _fd7
    dest = _fd7.asksaveasfilename(defaultextension=".zip",
        filetypes=[("ZIP","*.zip")], initialfile="soc_full_backup.zip")
    if not dest: return
    _checkpoint("BACKUP", f"Full backup started → {os.path.basename(dest)}")
    try:
        files_saved = []
        with zipfile.ZipFile(dest, "w", zipfile.ZIP_DEFLATED) as zf:
            for fn in ["config.json","scan_history.db","whitelist.txt","notes.txt"]:
                fp = os.path.join(BASE_DIR, fn)
                if os.path.exists(fp): zf.write(fp, fn); files_saved.append(fn)

            rsp = os.path.join(BASE_DIR, "rules", "rules_state.json")
            if os.path.exists(rsp): zf.write(rsp, "rules/rules_state.json"); files_saved.append("rules_state.json")
        _checkpoint("BACKUP", f"Full backup OK — {len(files_saved)} file(s) archived: {', '.join(files_saved)}  dest: {dest}")
        messagebox.showinfo("Backup", f"Backup saved:\n{dest}")
    except Exception as e:
        _checkpoint("BACKUP", f"Full backup FAILED: {e}")
        messagebox.showerror("Error", str(e))

def _dz_restore_backup():
    import zipfile, shutil
    from tkinter import filedialog as _fd8
    src = _fd8.askopenfilename(filetypes=[("ZIP","*.zip")])
    if not src: return
    if not messagebox.askyesno("Restore", f"Restore from:\n{src}\n\nExisting files will be overwritten."): return
    _checkpoint("RESTORE", f"Restore started from {os.path.basename(src)}")
    try:
        with zipfile.ZipFile(src, "r") as zf:
            names = zf.namelist()
            zf.extractall(BASE_DIR)
        _checkpoint("RESTORE", f"Restore OK — {len(names)} file(s) extracted from {os.path.basename(src)} — restart required")
        messagebox.showinfo("Restore", "Backup restored. Restart the app.")
    except Exception as e:
        _checkpoint("RESTORE", f"Restore FAILED: {e}")
        messagebox.showerror("Error", str(e))

