def _dz_clear_session_logs():
    try:
        logs = sorted([f for f in os.listdir(DEBUG_DIR) if f.startswith("log_")
                       and f.endswith(".txt")], reverse=True)
        to_del = logs[3:]
        for fn in to_del:
            try: os.remove(os.path.join(DEBUG_DIR, fn))
            except Exception: pass
        messagebox.showinfo("Session Logs", f"Kept {min(3,len(logs))} recent logs, deleted {len(to_del)}.")
    except Exception as e: messagebox.showerror("Error", str(e))

def _dz_trim_db():
    from tkinter.simpledialog import askinteger
    n = askinteger("Trim DB", "How many records to keep? (0 = keep all)", initialvalue=1000, minvalue=0)
    if n is None: return
    if n == 0: messagebox.showinfo("Trim","Nothing to trim."); return
    try:
        with _db_lock:
            total = _conn.execute("SELECT COUNT(*) FROM scans").fetchone()[0]
            if total <= n:
                messagebox.showinfo("Trim", f"DB already has only {total} records (< {n}). Nothing to trim.")
                return
            _conn.execute(f"""DELETE FROM scans WHERE rowid NOT IN
                (SELECT rowid FROM scans ORDER BY timestamp DESC LIMIT {n})""")
            _conn.execute("VACUUM"); _conn.commit()
        _refresh_stats(); _update_charts()
        messagebox.showinfo("Trim", f"Removed {total-n} records — DB now has {n} entries.")
    except Exception as e: messagebox.showerror("Error", str(e))

def _dz_thread_report():
    threads = threading.enumerate()
    lines = [f"Thread attivi: {len(threads)}", "─"*50]
    for t in threads:
        lines.append(f"  {'[DAEMON]' if t.daemon else '[MAIN]  '} {t.name}")
    messagebox.showinfo("Thread Report", "\n".join(lines))

def _dz_memory_report():
    if not _psutil:
        messagebox.showwarning("RAM","psutil not available."); return
    try:
        proc = _psutil.Process(os.getpid())
        mi = proc.memory_info()
        vm = _psutil.virtual_memory()
        messagebox.showinfo("Memory",
            f"App RSS:   {mi.rss/1048576:.1f} MB\n"
            f"App VMS:   {mi.vms/1048576:.1f} MB\n"
            f"Sistema:   {vm.percent:.1f}% usato\n"
            f"Available: {vm.available/1048576:.0f} MB")
    except Exception as e: messagebox.showerror("Error", str(e))

