def _sim_crash(code, reason):
    try:
        class _FakeCrashError(Exception):
            pass
        try:
            raise _FakeCrashError(f"[SIMULATED CRASH {code}] {reason}")
        except _FakeCrashError as _fe:
            exc_type = type(_fe); exc_val = _fe; exc_tb = _fe.__traceback__

        theater_fn = globals().get("_crash_theater_fn")
        if theater_fn:


            root.after(0, lambda: theater_fn(exc_type, exc_val, exc_tb,
                                             _existing_root=root))
        else:
            import traceback as _stb
            tb_s = "".join(_stb.format_exception(exc_type, exc_val, exc_tb))
            root.after(0, lambda: _crash_popup(code, reason, tb_s))
    except Exception as _ex:
        root.after(0, lambda: _crash_popup(code, reason, str(_ex)))

