def _sig_log(msg, tag="DIM"):
    _sig_out.config(state="normal"); _sig_out.insert(tk.END, msg+"\n", tag)
    _sig_out.see(tk.END); _sig_out.config(state="disabled")

def _sig_set_verdict(icon, text, color):
    _sig_icon_lbl.config(text=f"  {icon}", fg=color)
    _sig_verdict_sv.set(text); _sig_verdict_lbl.config(fg=color)

def _sig_browse():
    p=filedialog.askopenfilename(title="Select PE file",
        filetypes=[("Executables","*.exe *.dll *.sys *.drv *.ocx *.msi"),("All","*.*")])
    if p: _sig_path_var.set(p)

def _sig_verify():
    p=_sig_path_var.get().strip()
    if not p or not os.path.isfile(p): messagebox.showwarning("Signature","Select a valid file."); return
    _checkpoint("SIG", f"Signature verification started — file: {os.path.basename(p)}  size: {os.path.getsize(p):,} bytes")
    _sig_out.config(state="normal"); _sig_out.delete("1.0",tk.END); _sig_out.config(state="disabled")
    _sig_set_verdict("⟳","Verifying...",C["yellow"])
    def _do():
        root.after(0,lambda: _sig_log(f"\n  File: {os.path.basename(p)}","HEAD"))
        root.after(0,lambda: _sig_log(f"  Size: {os.path.getsize(p):,} bytes","DIM"))
        if sys.platform=="win32":
            try:
                cmd=["powershell","-NoProfile","-NonInteractive","-WindowStyle","Hidden","-Command",
                     f"$s=Get-AuthenticodeSignature '{p}'; $s|Select Status,SignerCertificate|Format-List; "
                     "$s.SignerCertificate|Select Subject,Issuer,NotBefore,NotAfter,Thumbprint|Format-List"]
                r=subprocess.run(cmd,capture_output=True,text=True,timeout=15)
                out=r.stdout.strip()
                if not out: raise RuntimeError("No output")
                sm=re.search(r"Status\s*:\s*(\S+)",out)
                status=sm.group(1) if sm else "Unknown"
                if status=="Valid":
                    root.after(0,lambda: _sig_set_verdict("✓","SIGNED — Signature Valid",C["green"]))
                    root.after(0,lambda: _sig_log("  ✓ Signature: VALID (Authenticode)","OK"))
                    _checkpoint("SIG", f"{os.path.basename(p)} — VALID Authenticode signature")
                elif status=="NotSigned":
                    root.after(0,lambda: _sig_set_verdict("✗","NOT SIGNED",C["red"]))
                    root.after(0,lambda: _sig_log("  ✗ File is NOT signed","BAD"))
                    _checkpoint("SIG", f"{os.path.basename(p)} — NOT SIGNED")
                elif status=="HashMismatch":
                    root.after(0,lambda: _sig_set_verdict("⚠","TAMPERED — Hash Mismatch",C["red"]))
                    root.after(0,lambda: _sig_log("  ⚠ SIGNATURE TAMPERED — hash mismatch!","BAD"))
                    _checkpoint("SIG", f"{os.path.basename(p)} — ⚠ TAMPERED — hash mismatch")
                else:
                    root.after(0,lambda s=status: _sig_set_verdict("~",f"Status: {s}",C["yellow"]))
                    root.after(0,lambda s=status: _sig_log(f"  ~ Status: {s}","WARN"))
                    _checkpoint("SIG", f"{os.path.basename(p)} — status: {status}")
                root.after(0,lambda o=out: _sig_log("\n  Certificate Details:\n"+o,"INFO"))
                return
            except Exception as e:
                root.after(0,lambda err=str(e): _sig_log(f"  PowerShell: {err}","WARN"))

        try:
            import pefile as _pe3
            pe3=_pe3.PE(p,fast_load=False)
            if not hasattr(pe3,"DIRECTORY_ENTRY_SECURITY"):
                root.after(0,lambda: _sig_set_verdict("✗","NOT SIGNED — No security directory",C["red"]))
                root.after(0,lambda: _sig_log("  ✗ No Authenticode signature (no security directory)","BAD"))
                return
            for entry in pe3.DIRECTORY_ENTRY_SECURITY:
                cert_data=entry.struct.__pack__(); pkcs7=cert_data[8:]
                try:
                    from cryptography.hazmat.primitives.serialization import pkcs7 as _cp7
                    from cryptography import x509
                    certs=_cp7.load_der_pkcs7_certificates(pkcs7)
                    root.after(0,lambda n=len(certs): _sig_set_verdict("✓",f"SIGNED — {n} cert(s) found",C["teal"]))
                    root.after(0,lambda n=len(certs): _sig_log(f"  ✓ PKCS#7 parsed — {n} certificate(s)","OK"))
                    import datetime as _dta
                    for cert in certs:
                        try:
                            subj=cert.subject.rfc4514_string()
                            iss=cert.issuer.rfc4514_string()
                            na=getattr(cert,"not_valid_after_utc",None) or cert.not_valid_after
                            nb=getattr(cert,"not_valid_before_utc",None) or cert.not_valid_before
                            root.after(0,lambda s=subj: _sig_log(f"\n  Subject : {s[:90]}","INFO"))
                            root.after(0,lambda i=iss:  _sig_log(f"  Issuer  : {i[:90]}","DIM"))
                            root.after(0,lambda nb2=str(nb): _sig_log(f"  Valid   : {nb2}  →","DIM"))
                            root.after(0,lambda na2=str(na): _sig_log(f"           {na2}","DIM"))
                            now=_dta.datetime.now(_dta.timezone.utc)
                            expired=now>na.replace(tzinfo=_dta.timezone.utc) if na.tzinfo is None else now>na
                            if expired: root.after(0,lambda: _sig_log("  ⚠  Certificate EXPIRED","BAD"))
                            if cert.subject==cert.issuer: root.after(0,lambda: _sig_log("  ⚠  Self-signed","WARN"))
                        except Exception: pass
                except ImportError:
                    root.after(0,lambda: _sig_set_verdict("~","SIGNED (install cryptography for details)",C["teal"]))
                    root.after(0,lambda: _sig_log("  ✓ Security directory present — pip install cryptography for details","WARN"))
                except Exception as e:
                    root.after(0,lambda err=str(e): _sig_set_verdict("~",f"Cert parse error",C["yellow"]))
                    root.after(0,lambda err=str(e): _sig_log(f"  Certificate parse: {err}","WARN"))
                break
        except ImportError:
            root.after(0,lambda: _sig_set_verdict("~","pefile not installed",C["overlay0"]))
            root.after(0,lambda: _sig_log("  Install pefile: pip install pefile","WARN"))
        except Exception as e:
            root.after(0,lambda err=str(e): _sig_set_verdict("✗","Error",C["red"]))
            root.after(0,lambda err=str(e): _sig_log(f"  Error: {err}","WARN"))
    threading.Thread(target=_do,daemon=True).start()


_tab_reg = tk.Frame(_proc_nb, bg=C["base"]); _proc_nb.add(_tab_reg, text="🗝Registry")
_reg_head = tk.Frame(_tab_reg, bg=C["surface0"], padx=16, pady=10); _reg_head.pack(fill=tk.X)
tk.Label(_reg_head, text="REGISTRY SCANNER", font=FB, bg=C["surface0"], fg=C["yellow"]).pack(anchor="w")
tk.Label(_reg_head, text="Scan Run keys, services, Winlogon and persistence mechanisms for suspicious entries",
         font=FS, bg=C["surface0"], fg=C["overlay0"]).pack(anchor="w")
tk.Frame(_tab_reg, bg=C["yellow"], height=1).pack(fill=tk.X)

if sys.platform != "win32":
    _reg_na = tk.Frame(_tab_reg, bg=C["base"]); _reg_na.pack(fill=tk.BOTH, expand=True)
    tk.Label(_reg_na,
             text="\n\n  🗝  Registry Scanner — Windows only\n\n"
                  "  Uses winreg to scan HKLM/HKCU startup and persistence keys.\n"
                  "  Run V0RTEX on Windows to use this feature.",
             font=("Consolas",10), bg=C["base"], fg=C["overlay0"], justify="left").pack(anchor="w", padx=30, pady=40)
else:
    _reg_ctrl = tk.Frame(_tab_reg, bg=C["surface0"], padx=12, pady=8); _reg_ctrl.pack(fill=tk.X)
    _reg_deep_var = tk.BooleanVar(value=False)
    tk.Checkbutton(_reg_ctrl, text="Deep scan (Services ImagePath)", variable=_reg_deep_var,
                   font=FS, bg=C["surface0"], fg=C["text"], activebackground=C["surface0"],
                   selectcolor=C["mantle"], relief="flat").pack(side=tk.LEFT, padx=(0,10))
    _mkbtn(_reg_ctrl, "🔍 Scan Persistence Keys", lambda: _reg_scan(), C["yellow"])
    _mkbtn(_reg_ctrl, "Export CSV", lambda: _reg_export(), C["teal"])
    tk.Label(_reg_ctrl, text="Filter:", font=FS, bg=C["surface0"], fg=C["text"]).pack(side=tk.LEFT, padx=(10,4))
    _reg_filter_var = tk.StringVar()
    tk.Entry(_reg_ctrl, textvariable=_reg_filter_var, font=("Consolas",9),
             bg=C["mantle"], fg=C["text"], insertbackground=C["text"],
             relief="flat", bd=4, width=18).pack(side=tk.LEFT)
    _mkbtn(_reg_ctrl, "Apply", lambda: _reg_apply_filter(), C["surface2"])
    tk.Frame(_tab_reg, bg=C["surface2"], height=1).pack(fill=tk.X)
    _reg_wrap = tk.Frame(_tab_reg, bg=C["base"]); _reg_wrap.pack(fill=tk.BOTH, expand=True, padx=4, pady=4)
    _reg_sc_v2 = tk.Scrollbar(_reg_wrap, orient="vertical", bg=C["surface1"],
                               troughcolor=C["base"], relief="flat", bd=0, width=7)
    _reg_sc_h2 = tk.Scrollbar(_reg_wrap, orient="horizontal", bg=C["surface1"],
                               troughcolor=C["base"], relief="flat", bd=0, width=7)
    _reg_tree = ttk.Treeview(_reg_wrap, columns=("hive","key","value","data","risk"),
                              show="headings", yscrollcommand=_reg_sc_v2.set,
                              xscrollcommand=_reg_sc_h2.set)
    _reg_sc_v2.config(command=_reg_tree.yview); _reg_sc_h2.config(command=_reg_tree.xview)
    _reg_sc_v2.pack(side=tk.RIGHT, fill=tk.Y); _reg_sc_h2.pack(side=tk.BOTTOM, fill=tk.X)
    _reg_tree.pack(fill=tk.BOTH, expand=True)
    for _rcol, _rw in [("hive",70),("key",270),("value",130),("data",330),("risk",60)]:
        _reg_tree.heading(_rcol, text=_rcol.upper())
        _reg_tree.column(_rcol, width=_rw, stretch=(_rcol in ("key","data")))
    _reg_tree.tag_configure("HIGH", foreground=C["red"])
    _reg_tree.tag_configure("MED",  foreground=C["yellow"])
    _reg_tree.tag_configure("LOW",  foreground=C["text"])
    _reg_status_sv = tk.StringVar(value="Ready. Press Scan.")
    tk.Label(_tab_reg, textvariable=_reg_status_sv, font=FS, bg=C["surface0"],
             fg=C["overlay0"], padx=12, pady=4).pack(fill=tk.X)
    _reg_all_rows = []
    _REG_KEYS = [
        ("HKLM","SOFTWARE\\Microsoft\\Windows\\CurrentVersion\\Run","Run HKLM"),
        ("HKLM","SOFTWARE\\Microsoft\\Windows\\CurrentVersion\\RunOnce","RunOnce HKLM"),
        ("HKCU","SOFTWARE\\Microsoft\\Windows\\CurrentVersion\\Run","Run HKCU"),
        ("HKCU","SOFTWARE\\Microsoft\\Windows\\CurrentVersion\\RunOnce","RunOnce HKCU"),
        ("HKLM","SOFTWARE\\Microsoft\\Windows NT\\CurrentVersion\\Winlogon","Winlogon"),
        ("HKLM","SYSTEM\\CurrentControlSet\\Services","Services"),
        ("HKLM","SOFTWARE\\Microsoft\\Windows NT\\CurrentVersion\\Image File Execution Options","IFEO"),
        ("HKLM","SYSTEM\\CurrentControlSet\\Control\\Session Manager\\AppCertDlls","AppCertDlls"),
    ]
    _REG_SUSP = [(r"\.vbs$","HIGH"),(r"\.js$","HIGH"),(r"\.bat$","MED"),
                 (r"powershell","HIGH"),(r"cmd\.exe","MED"),(r"wscript","HIGH"),
                 (r"cscript","HIGH"),(r"mshta","HIGH"),(r"rundll32","MED"),
                 (r"certutil","HIGH"),(r"bitsadmin","HIGH"),
                 (r"appdata\\local\\temp","HIGH"),(r"%temp%","HIGH"),
                 (r"base64","HIGH"),(r"\\users\\.*\\appdata","MED")]
    def _reg_risk(data_str):
        ds=data_str.lower()
        for pat,risk in _REG_SUSP:
            if re.search(pat,ds,re.IGNORECASE): return risk
        return "LOW"
    def _reg_scan():
        import winreg as _wr
        _reg_all_rows.clear()
        for item in _reg_tree.get_children(): _reg_tree.delete(item)
        _reg_status_sv.set("Scanning…")
        def _do():
            found=0
            for hive_str,subkey,desc in _REG_KEYS:
                hive=_wr.HKEY_LOCAL_MACHINE if hive_str=="HKLM" else _wr.HKEY_CURRENT_USER
                try:
                    key=_wr.OpenKey(hive,subkey,0,_wr.KEY_READ); idx3=0
                    while True:
                        try:
                            name,data,_=_wr.EnumValue(key,idx3)
                            ds=str(data); risk=_reg_risk(ds)
                            row=(hive_str,subkey,name,ds[:120],risk)
                            _reg_all_rows.append(row); found+=1
                            root.after(0,lambda r=row,rk=risk: _reg_tree.insert("",tk.END,values=r,tags=(rk,)))
                            idx3+=1
                        except OSError: break
                    if _reg_deep_var.get() and "Services" in subkey:
                        sidx2=0
                        while True:
                            try:
                                sname=_wr.EnumKey(key,sidx2)
                                try:
                                    sk3=_wr.OpenKey(key,sname,0,_wr.KEY_READ)
                                    try:
                                        img,_,_=_wr.QueryValueEx(sk3,"ImagePath"); risk=_reg_risk(str(img))
                                        if risk!="LOW":
                                            row=(hive_str,f"{subkey}\\{sname}","ImagePath",str(img)[:120],risk)
                                            _reg_all_rows.append(row); found+=1
                                            root.after(0,lambda r=row,rk=risk: _reg_tree.insert("",tk.END,values=r,tags=(rk,)))
                                    except OSError: pass
                                    _wr.CloseKey(sk3)
                                except OSError: pass
                                sidx2+=1
                            except OSError: break
                    _wr.CloseKey(key)
                except PermissionError: pass
                except Exception: pass
            susp=sum(1 for r in _reg_all_rows if r[4]!="LOW")
            root.after(0,lambda n=found,s=susp: _reg_status_sv.set(f"Done — {n} entries, {s} suspicious"))
        threading.Thread(target=_do,daemon=True).start()
    def _reg_apply_filter():
        filt=_reg_filter_var.get().lower()
        for item in _reg_tree.get_children(): _reg_tree.delete(item)
        for row in _reg_all_rows:
            if not filt or any(filt in str(c).lower() for c in row):
                _reg_tree.insert("",tk.END,values=row,tags=(row[4],))
    def _reg_export():
        dest=filedialog.asksaveasfilename(defaultextension=".csv",filetypes=[("CSV","*.csv")],initialfile="registry_scan.csv")
        if not dest: return
        import csv
        with open(dest,"w",newline="",encoding="utf-8") as f:
            w=csv.writer(f); w.writerow(["hive","key","value","data","risk"])
            w.writerows(_reg_all_rows)
        messagebox.showinfo("Export",f"Exported {len(_reg_all_rows)} entries.")


