    def _t():
        try:
            import requests as _rq
            r = _rq.get(f"{url}/cuckoo/status", timeout=5)
            if r.ok:
                d = r.json()
                ver = d.get("version","?")
                tasks = d.get("tasks",{})
                root.after(0, lambda: _ck_status_sv.set(f"✅  Connected — Cuckoo {ver} | pending: {tasks.get('pending',0)}"))
                root.after(0, lambda: _ck_save_cfg())
            else:
                root.after(0, lambda: _ck_status_sv.set(f"❌  HTTP {r.status_code}"))
        except Exception as e:
            root.after(0, lambda: _ck_status_sv.set(f"❌  {e}"))
    threading.Thread(target=_t, daemon=True).start()

