def _ck_log(msg, tag="INFO"):
    colors = {"INFO": C["text"], "OK": C["green"], "ERR": C["red"], "WARN": C["yellow"]}
    _ck_rep_text.config(state="normal")
    _ck_rep_text.tag_configure(tag, foreground=colors.get(tag, C["text"]))
    _ck_rep_text.insert("end", f"[{tag}] {msg}\n", tag)
    _ck_rep_text.see("end")
    _ck_rep_text.config(state="disabled")

def _ck_submit():
    fpath = _ck_file_var.get().strip()
    if not fpath or not os.path.isfile(fpath):
        messagebox.showerror("Cuckoo","No valid file selected."); return
    url = _ck_url_var.get().strip()
    timeout = _ck_timeout_var.get()
    _ck_rep_text.config(state="normal"); _ck_rep_text.delete("1.0","end"); _ck_rep_text.config(state="disabled")
    def _do():
        try:
            import requests as _rq
            root.after(0,lambda: _ck_log(f"Submitting: {os.path.basename(fpath)}"))
            files = {"file":(os.path.basename(fpath), open(fpath,"rb"))}
            data  = {"timeout": timeout, "enforce_timeout": False}
            r = _rq.post(f"{url}/tasks/create/file", files=files, data=data, timeout=15)
            if r.status_code != 200:
                root.after(0,lambda: _ck_log(f"Submit failed: {r.status_code} — {r.text[:200]}", "ERR")); return
            task_id = r.json().get("task_id")
            root.after(0,lambda: _ck_log(f"Task ID: {task_id} — waiting for analysis…", "OK"))
            waited = 0
            while waited < timeout + 60:
                import time as _t2; _t2.sleep(10); waited += 10
                rs = _rq.get(f"{url}/tasks/view/{task_id}", timeout=10)
                if not rs.ok: continue
                status = rs.json().get("task",{}).get("status","?")
                root.after(0,lambda s=status,w=waited: _ck_log(f"  {w}s — status: {s}"))
                if status == "reported":
                    rep = _rq.get(f"{url}/tasks/report/{task_id}", timeout=30).json()
                    score = rep.get("info",{}).get("score",0)
                    sigs  = rep.get("signatures",[])
                    root.after(0,lambda sc=score: _ck_log(f"━━ REPORT: score={sc}/10", "OK" if sc<5 else "ERR"))
                    for s in sigs[:20]:
                        root.after(0,lambda nm=s.get("name","?"),sv=s.get("severity",0): _ck_log(f"  ⚑ [{sv}] {nm}", "WARN"))
                    break
            else:
                root.after(0,lambda: _ck_log("Timed out waiting for report","WARN"))
        except Exception as ex:
            root.after(0,lambda: _ck_log(f"Error: {ex}","ERR"))
    threading.Thread(target=_do,daemon=True).start()

