_mt_results = []
def _mt_load():
    p = filedialog.askopenfilename(); 
    if p: _mt_in.delete("1.0","end"); _mt_in.insert("end", open(p,"r",errors="ignore").read(200000))
def _mt_paste():
    try: _mt_in.delete("1.0","end"); _mt_in.insert("end", root.clipboard_get())
    except: pass
def _mt_map():
    global _mt_results; _mt_results = []
    text = _mt_in.get("1.0","end").lower()
    for item in _mt_tree.get_children(): _mt_tree.delete(item)
    for tid,name,tactic,kws in _MITRE_DB:
        hits = [k for k in kws if k.lower() in text]
        if hits:
            _mt_results.append((tid,name,tactic,", ".join(hits)))
            _mt_tree.insert("","end", values=(tid,name,tactic,", ".join(hits)), tags=("HIT",))
    if not _mt_results:
        _mt_tree.insert("","end", values=("—","No matches","—","Try adding more context"))
def _mt_export():
    if not _mt_results: return
    p = filedialog.asksaveasfilename(defaultextension=".csv",filetypes=[("CSV","*.csv")])
    if not p: return
    import csv
    with open(p,"w",newline="",encoding="utf-8") as f:
        w=csv.writer(f); w.writerow(["TechID","Name","Tactic","Matched Keywords"])
        w.writerows(_mt_results)
    messagebox.showinfo("ATT&CK","Exported.")


