def _bh_browse():
    p = filedialog.askopenfilename(title="Select hash list (CSV/TXT)",
                                   filetypes=[("CSV/TXT","*.csv *.txt"),("All","*.*")])
    if p: _bh_file_var.set(p)

_mkbtn(_bh_ctrl, "📂 Open Hash List", _bh_browse, C["surface2"])
_bh_running = [False]
_bh_stop    = [False]

def _bh_start():
    fpath = _bh_file_var.get().strip()
    if not fpath or not os.path.isfile(fpath):
        messagebox.showerror("Batch","Select a valid hash list file."); return
    keys = CONFIG.get("api_keys",[])
    if not keys:
        messagebox.showerror("Batch","No VirusTotal API key configured in Settings."); return
    hashes = []
    try:
        with open(fpath,"r",encoding="utf-8",errors="ignore") as f:
            for line in f:
                line = line.strip().strip(",").split(",")[0].strip()
                if re.fullmatch(r'[a-fA-F0-9]{32}|[a-fA-F0-9]{40}|[a-fA-F0-9]{64}', line):
                    hashes.append(line)
    except Exception as e:
        messagebox.showerror("Batch",str(e)); return
    if not hashes:
        messagebox.showinfo("Batch","No valid hashes found."); return
    _bh_stop[0] = False
    _bh_running[0] = True
    _bh_tree.delete(*_bh_tree.get_children())
    _bh_prog_sv.set(f"0 / {len(hashes)}")
    import requests as _rq, time as _t3
    key_idx = [0]
    def _do():
        for i,h in enumerate(hashes):
            if _bh_stop[0]: break
            key = keys[key_idx[0] % len(keys)]
            try:
                r = _rq.get(f"https://www.virustotal.com/api/v3/files/{h}",
                            headers={"x-apikey":key}, timeout=20)
                if r.status_code == 200:
                    attrs = r.json()["data"]["attributes"]
                    stats = attrs.get("last_analysis_stats",{})
                    det   = stats.get("malicious",0)
                    total = sum(stats.values())
                    name  = attrs.get("meaningful_name","?")[:30]
                    tag   = "MAL" if det>0 else "CLN"
                    root.after(0,lambda h2=h,n=name,d=det,t=total,tg=tag:
                               _bh_tree.insert("","end",values=(h2[:16]+"…",n,f"{d}/{t}"),tags=(tg,)))
                elif r.status_code == 404:
                    root.after(0,lambda h2=h: _bh_tree.insert("","end",
                               values=(h2[:16]+"…","NOT FOUND","—"),tags=("UNK",)))
                key_idx[0] += 1
            except Exception as ex:
                root.after(0,lambda h2=h,e=str(ex): _bh_tree.insert("","end",
                           values=(h2[:16]+"…","ERROR",e[:40]),tags=("ERR",)))
            root.after(0,lambda n=i+1,t=len(hashes): _bh_prog_sv.set(f"{n} / {t}"))
            delay = CONFIG.get("request_delay",15)
            _t3.sleep(delay)
        _bh_running[0] = False
    threading.Thread(target=_do,daemon=True).start()

