_df_html_diff = [None]
def _df_run():
    import difflib
    f1,f2 = _df_f1.get().strip(), _df_f2.get().strip()
    if not f1 or not f2 or not os.path.isfile(f1) or not os.path.isfile(f2):
        messagebox.showerror("Diff","Select two valid files."); return
    try:
        lines_a = open(f1,"r",errors="replace").readlines()
        lines_b = open(f2,"r",errors="replace").readlines()
    except Exception as e:
        messagebox.showerror("Diff",str(e)); return
    d = list(difflib.unified_diff(lines_a, lines_b,
             fromfile=os.path.basename(f1), tofile=os.path.basename(f2), lineterm=""))
    adds = sum(1 for l in d if l.startswith("+") and not l.startswith("+++"))
    dels = sum(1 for l in d if l.startswith("-") and not l.startswith("---"))
    _df_stats.set(f"  +{adds} lines added   -{dels} lines removed   {len(d)} diff lines total")
    _df_out.config(state="normal"); _df_out.delete("1.0","end")
    for line in d:
        if line.startswith("@@"):   _df_out.insert("end",line+"\n","HDR")
        elif line.startswith("+"): _df_out.insert("end",line+"\n","ADD")
        elif line.startswith("-"): _df_out.insert("end",line+"\n","DEL")
        else:                       _df_out.insert("end",line+"\n","INF")
    _df_out.config(state="disabled")
    _df_html_diff[0] = difflib.HtmlDiff().make_file(lines_a, lines_b,
                           fromdesc=os.path.basename(f1), todesc=os.path.basename(f2))

def _df_export_html():
    if not _df_html_diff[0]:
        messagebox.showinfo("Diff","Run a comparison first."); return
    p = filedialog.asksaveasfilename(defaultextension=".html",filetypes=[("HTML","*.html")])
    if not p: return
    with open(p,"w",encoding="utf-8") as f: f.write(_df_html_diff[0])
    messagebox.showinfo("Diff","HTML report saved.")


