_ps_status_sv = tk.StringVar(value="Ready.")

def _ps_parse_ports(s):
    ports = []
    for part in s.split(","):
        part = part.strip()
        if "-" in part:
            a,b = part.split("-",1)
            ports.extend(range(int(a),int(b)+1))
        else:
            ports.append(int(part))
    return sorted(set(ports))

def _ps_start():
    import socket as _sk
    host = _ps_host_var.get().strip()
    try: ports = _ps_parse_ports(_ps_range_var.get())
    except: messagebox.showerror("PortScan","Invalid port range."); return
    _ps_tree.delete(*_ps_tree.get_children())
    _ps_stop_flag[0] = False
    _ps_status_sv.set(f"Scanning {host} — {len(ports)} ports…")
    timeout = CONFIG.get("port_scan_timeout", 1.0)
    def _do():
        open_count = 0
        for p in ports:
            if _ps_stop_flag[0]: break
            try:
                s = _sk.socket(_sk.AF_INET, _sk.SOCK_STREAM)
                s.settimeout(timeout)
                res = s.connect_ex((host, p))
                s.close()
                if res == 0:
                    open_count += 1
                    try:
                        svc = _sk.getservbyport(p)
                    except Exception:
                        svc = "unknown"
                    risk = "HIGH" if p in (21,22,23,3389,5900,445,139,1433,3306,6379) else "MED" if p<1024 else "LOW"
                    root.after(0,lambda pp=p,sv=svc,rk=risk:
                               _ps_tree.insert("","end",values=(pp,"OPEN",sv,rk),tags=(rk,)))
            except Exception: pass
        root.after(0, lambda n=open_count: _ps_status_sv.set(f"Done — {n} open ports found"))
    threading.Thread(target=_do, daemon=True).start()

