def _tf_fetch_feeds():
    import requests as _rq
    selected = [f for f in _FREE_FEEDS if _tf_feed_vars[f[0]].get()]
    if not selected: messagebox.showinfo("Feeds","Select at least one feed."); return
    _tf_status_sv.set(f"Fetching {len(selected)} feed(s)…")
    def _do():
        total = 0
        for fname, furl, ftype in selected:
            try:
                r = _rq.get(furl, timeout=20, headers={"User-Agent":"V0RTEX/1.0"})
                if r.ok:
                    entries = set()
                    for line in r.text.splitlines():
                        line = line.strip()
                        if not line or line.startswith("#"): continue
                        entries.add(line.split()[0].lower())
                    _tf_cache[fname] = entries
                    total += len(entries)
                    root.after(0,lambda fn=fname,n=len(entries): _tf_log(f"[OK] {fn}: {n} entries","OK"))
                else:
                    root.after(0,lambda fn=fname,s=r.status_code: _tf_log(f"[FAIL] {fn}: HTTP {s}","ERR"))
            except Exception as ex:
                root.after(0,lambda fn=fname,e=str(ex): _tf_log(f"[ERR] {fn}: {e}","ERR"))
        root.after(0,lambda t=total: _tf_status_sv.set(f"Feeds loaded — {t} total entries cached"))
    threading.Thread(target=_do,daemon=True).start()

def _tf_check_ioc():
    ioc = _tf_ioc_var.get().strip().lower()
    if not ioc: return
    if not _tf_cache:
        messagebox.showinfo("Feeds","Fetch feeds first."); return
    hits = []
    for fname, entries in _tf_cache.items():
        if ioc in entries:
            hits.append(fname)
        else:
            for e in entries:
                if ioc in e or e in ioc:
                    hits.append(f"{fname} (partial: {e})")
                    break
    if hits:
        _tf_log(f"⚑ MATCH for '{ioc}': {', '.join(hits)}", "ERR")
    else:
        _tf_log(f"✓ '{ioc}' not found in cached feeds.", "OK")

_mkbtn(_tf_query_bar,"⬇ Fetch Feeds", _tf_fetch_feeds, C["sapphire"])
