_bcv_vars = {}
def _bcv_update(src_base):
    try:
        v = _bcv_vars[src_base].get().strip()
        if not v: return
        n = int(v, src_base)
        for b, var in _bcv_vars.items():
            if b != src_base:
                if b == 10: var.set(str(n))
                elif b == 16: var.set(hex(n)[2:].upper())
                elif b == 2: var.set(bin(n)[2:])
                elif b == 8: var.set(oct(n)[2:])
    except: pass
for _bval, _blbl, _bfg in [
    (2,"BINARY  (bin 0b)",C["green"]),
    (8,"OCTAL   (oct 0o)",C["teal"]),
    (10,"DECIMAL (dec)   ",C["blue"]),
    (16,"HEX     (hex 0x)",C["yellow"])
]:
    _brow = tk.Frame(_bcv_rows, bg=C["base"]); _brow.pack(fill=tk.X, pady=4)
    tk.Label(_brow, text=_blbl, width=20, font=FS, bg=C["base"], fg=_bfg, anchor="w").pack(side=tk.LEFT)
