def _jwt_decode():
    import base64 as _bm, json as _j, time as _jwt_t
    raw = _jwt_inp.get("1.0", tk.END).strip()
    _jwt_out.config(state="normal"); _jwt_out.delete("1.0",tk.END)
    def _b64url_dec(s):
        s += "=" * ((4 - len(s) % 4) % 4)
        return _bm.urlsafe_b64decode(s)
    try:
        parts = raw.split(".")
        if len(parts) < 2: raise ValueError("Not a valid JWT (need at least 2 parts)")
        header = _j.loads(_b64url_dec(parts[0]))
        payload = _j.loads(_b64url_dec(parts[1]))
        _jwt_out.tag_configure("HDR", foreground=C["sky"])
        _jwt_out.tag_configure("VAL", foreground=C["text"])
        _jwt_out.tag_configure("WARN", foreground=C["red"])
        _jwt_out.insert(tk.END, "── HEADER ──────────────────────────────\n","HDR")
        _jwt_out.insert(tk.END, _j.dumps(header, indent=2)+"\n\n","VAL")
        _jwt_out.insert(tk.END, "── PAYLOAD ─────────────────────────────\n","HDR")
        _jwt_out.insert(tk.END, _j.dumps(payload, indent=2)+"\n\n","VAL")
        if "exp" in payload:
            exp = payload["exp"]
            exp_str = _jwt_t.strftime("%Y-%m-%d %H:%M:%S UTC", _jwt_t.gmtime(exp))
            expired = _jwt_t.time() > exp
            tag = "WARN" if expired else "HDR"
            _jwt_out.insert(tk.END, f"── EXPIRY: {exp_str}  {'[EXPIRED]' if expired else '[VALID]'}\n", tag)
        if len(parts) >= 3:
            _jwt_out.insert(tk.END, "\n── SIGNATURE ────────────────────────────\n","HDR")
            _jwt_out.insert(tk.END, parts[2]+"\n","VAL")
    except Exception as e:
        _jwt_out.insert(tk.END, f"Error: {e}")
    _jwt_out.config(state="disabled")
_mkbtn(_jwt_btnrow,"🔍 Decode",_jwt_decode,C["sky"])
_mkbtn(_jwt_btnrow,"🗑 Clear",lambda:(_jwt_inp.delete("1.0",tk.END),
    _jwt_out.config(state="normal"),_jwt_out.delete("1.0",tk.END),
    _jwt_out.config(state="disabled")),C["surface1"],C["text"])
