def _peh_make_tab(title):
    f = tk.Frame(_peh_nb2, bg=C["base"]); _peh_nb2.add(f, text=title)
    sc = tk.Scrollbar(f, orient="vertical", bg=C["surface1"],
                      troughcolor=C["base"], relief="flat", width=7)
    t = tk.Text(f, bg=C["mantle"], fg=C["text"], font=("Consolas",8),
                relief="flat", bd=0, padx=8, pady=6, state="disabled",
                wrap="none", yscrollcommand=sc.set)
    sc.config(command=t.yview); sc.pack(side=tk.RIGHT, fill=tk.Y)
    t.pack(fill=tk.BOTH, expand=True); return t
_peh_info = _peh_make_tab(" INFO ")
_peh_secs = _peh_make_tab(" SECTIONS ")
_peh_imps = _peh_make_tab(" IMPORTS ")
_peh_exps = _peh_make_tab(" EXPORTS ")
def _peh_write(widget, text):
    widget.config(state="normal"); widget.insert(tk.END, text); widget.config(state="disabled")
def _peh_run():
    p = _peh_path_v.get().strip()
    if not p or not os.path.isfile(p):
        messagebox.showwarning("PE","No file selected."); return
    for w in [_peh_info,_peh_secs,_peh_imps,_peh_exps]:
        w.config(state="normal"); w.delete("1.0",tk.END); w.config(state="disabled")
    def _do():
        if pefile is None:
            root.after(0, lambda: _peh_write(_peh_info,"pefile not installed.\npip install pefile\n")); return
        try:
            pe = pefile.PE(p)
            lines = [
                f"  File:          {os.path.basename(p)}\n",
                f"  Size:          {os.path.getsize(p):,} bytes\n",
                f"  Machine:       {hex(pe.FILE_HEADER.Machine)}\n",
                f"  TimeDateStamp: {pe.FILE_HEADER.TimeDateStamp}\n",
                f"  Sections:      {pe.FILE_HEADER.NumberOfSections}\n",
                f"  Entry Point:   {hex(pe.OPTIONAL_HEADER.AddressOfEntryPoint)}\n",
                f"  ImageBase:     {hex(pe.OPTIONAL_HEADER.ImageBase)}\n",
            ]
            root.after(0, lambda: _peh_write(_peh_info,"".join(lines)))
            sl = []
            for s in pe.sections:
                n = s.Name.decode("utf-8","replace").rstrip("\x00")
                sl.append(f"  {n:<12}  VA={hex(s.VirtualAddress)}"
                          f"  RawSize={s.SizeOfRawData:>8,}  Entropy={s.get_entropy():.2f}\n")
            root.after(0, lambda: _peh_write(_peh_secs,"".join(sl) if sl else "No sections.\n"))
            il = []
            if hasattr(pe,'DIRECTORY_ENTRY_IMPORT'):
                for entry in pe.DIRECTORY_ENTRY_IMPORT:
                    dll = entry.dll.decode("utf-8","replace")
                    il.append(f"\n  [{dll}]\n")
                    for imp in entry.imports:
                        n2 = imp.name.decode("utf-8","replace") if imp.name else f"ord.{imp.ordinal}"
                        il.append(f"    {n2}\n")
            root.after(0, lambda: _peh_write(_peh_imps,"".join(il) if il else "No imports.\n"))
            el = []
            if hasattr(pe,'DIRECTORY_ENTRY_EXPORT'):
                for exp in pe.DIRECTORY_ENTRY_EXPORT.symbols:
                    n3 = exp.name.decode("utf-8","replace") if exp.name else "(no name)"
                    el.append(f"  ord.{exp.ordinal:<6} {n3}\n")
            root.after(0, lambda: _peh_write(_peh_exps,"".join(el) if el else "No exports.\n"))
        except Exception as e:
            root.after(0, lambda: _peh_write(_peh_info, f"Error: {e}\n"))
    threading.Thread(target=_do, daemon=True).start()

