_http_out.tag_configure("KEY",  foreground=C["blue"])
_http_out.tag_configure("OK",   foreground=C["green"])
_http_out.tag_configure("MISS", foreground=C["red"])
_http_out.tag_configure("VAL",  foreground=C["text"])
_SEC_HEADERS = ["Strict-Transport-Security","Content-Security-Policy",
                "X-Frame-Options","X-Content-Type-Options","Referrer-Policy",
                "Permissions-Policy","X-XSS-Protection"]
def _http_run():
    url = _http_url_v.get().strip()
    if not url.startswith(("http://","https://")): url = "https://"+url
    if requests is None:
        messagebox.showwarning("HTTP","requests not installed."); return
    _http_out.config(state="normal"); _http_out.delete("1.0",tk.END)
    _http_out.insert(tk.END, f"  Fetching: {url}\n")
    _http_out.config(state="disabled")
    def _do():
        try:
            r = requests.head(url, allow_redirects=_http_follow_v.get(), timeout=10,
                              headers={"User-Agent":"V0RTEX/1.0"})
        except Exception as e:
            root.after(0, lambda: (_http_out.config(state="normal"),
                                   _http_out.insert(tk.END,f"\n  Error: {e}\n"),
                                   _http_out.config(state="disabled"))); return
        def _show():
            _http_out.config(state="normal")
            _http_out.insert(tk.END, f"\n  HTTP {r.status_code}  {r.url}\n\n","HEAD")
            _http_out.insert(tk.END, "  ── RESPONSE HEADERS ──────────────────\n","HEAD")
            for k,v in r.headers.items():
                _http_out.insert(tk.END, f"  {k:<40}","KEY")
                _http_out.insert(tk.END, v+"\n","VAL")
            _http_out.insert(tk.END, "\n  ── SECURITY HEADERS ──────────────────\n","HEAD")
            for sh in _SEC_HEADERS:
                present = any(sh.lower()==kk.lower() for kk in r.headers)
                if present:
                    _http_out.insert(tk.END, f"  ✓  {sh}\n","OK")
                else:
                    _http_out.insert(tk.END, f"  ✗  {sh}  [MISSING]\n","MISS")
            _http_out.config(state="disabled")
        root.after(0, _show)
    threading.Thread(target=_do, daemon=True).start()

