_ssl_out.tag_configure("OK",   foreground=C["green"])
_ssl_out.tag_configure("WARN", foreground=C["yellow"])
_ssl_out.tag_configure("ERR",  foreground=C["red"])
def _ssl_run():
    host = _ssl_host_v.get().strip()
    if not host: return
    port = _ssl_port_v.get()
    _ssl_out.config(state="normal"); _ssl_out.delete("1.0",tk.END)
    _ssl_out.insert(tk.END, f"  Connecting to {host}:{port} ...\n")
    _ssl_out.config(state="disabled")
    def _do():
        import ssl as _ssl, socket as _sock
        cert = None; ver = "?"; cipher = ("?","?","?")
        try:
            ctx = _ssl.create_default_context()
            with _sock.create_connection((host,port), timeout=10) as s:
                with ctx.wrap_socket(s, server_hostname=host) as ss:
                    cert = ss.getpeercert(); cipher = ss.cipher(); ver = ss.version()
        except Exception as e:
            try:
                ctx2 = _ssl.create_default_context()
                ctx2.check_hostname = False; ctx2.verify_mode = _ssl.CERT_NONE
                with _sock.create_connection((host,port), timeout=10) as s:
                    with ctx2.wrap_socket(s, server_hostname=host) as ss:
                        cert = ss.getpeercert(); cipher = ss.cipher(); ver = ss.version()
                root.after(0, lambda: (_ssl_out.config(state="normal"),
                                       _ssl_out.insert(tk.END,"  WARNING: Certificate verification FAILED\n","WARN"),
                                       _ssl_out.config(state="disabled")))
            except Exception as e2:
                root.after(0, lambda: (_ssl_out.config(state="normal"),
                                       _ssl_out.insert(tk.END,f"  Error: {e2}\n","ERR"),
                                       _ssl_out.config(state="disabled"))); return
        def _show():
            _ssl_out.config(state="normal")
            _ssl_out.insert(tk.END, f"\n  TLS Version:  {ver}\n","HEAD")
            _ssl_out.insert(tk.END, f"  Cipher Suite: {cipher[0]}\n","HEAD")
            if cert and isinstance(cert, dict):
                for field in ["subject","issuer"]:
                    val = cert.get(field,"")
                    _ssl_out.insert(tk.END, f"\n  {field.upper()}\n","KEY")
                    if isinstance(val, tuple):
                        for item in val:
                            for k,v in item:
                                _ssl_out.insert(tk.END, f"    {k}: {v}\n","VAL")
                for nb_key in ["notBefore","notAfter"]:
                    _ssl_out.insert(tk.END, f"  {nb_key:<14} {cert.get(nb_key,'')}\n","VAL")
                sans = cert.get("subjectAltName",())
                if sans:
                    _ssl_out.insert(tk.END, "\n  SAN:\n","KEY")
                    for t,v in sans:
                        _ssl_out.insert(tk.END, f"    {t}: {v}\n","VAL")
            _ssl_out.config(state="disabled")
        root.after(0, _show)
    threading.Thread(target=_do, daemon=True).start()

