def _ios_refresh():
    import re as _re_ios
    _ios_out.config(state="normal"); _ios_out.delete("1.0",tk.END)
    try:
        c2 = sqlite3.connect(DB_PATH, timeout=5)
        cur2 = c2.cursor()
        cur2.execute("SELECT COUNT(*) FROM scans")
        total = cur2.fetchone()[0]
        _ios_out.insert(tk.END, "  Total scan records:  ","HEAD")
        _ios_out.insert(tk.END, f"{total}\n","NUM")
        cur2.execute("SELECT DISTINCT file FROM scans ORDER BY id DESC LIMIT 20")
        _ios_out.insert(tk.END, "\n  Last 20 scanned files:\n","HEAD")
        for r in cur2.fetchall():
            _ios_out.insert(tk.END, f"    {r[0]}\n","VAL")
        c2.close()
    except Exception as e:
        _ios_out.insert(tk.END, f"  DB not available: {e}\n","VAL")
    try:
        ioc_types = {"IP":0,"Domains":0,"URL":0,"Email":0,"Hash":0}
        logs_dir = os.path.join(BASE_DIR,"logs")
        if os.path.isdir(logs_dir):
            for fn in list(os.listdir(logs_dir))[-20:]:
                fp = os.path.join(logs_dir, fn)
                if not os.path.isfile(fp): continue
                try:
                    with open(fp,"r",encoding="utf-8",errors="replace") as f: content = f.read()
                    ioc_types["IP"] += len(_re_ios.findall(r'\b(?:\d{1,3}\.){3}\d{1,3}\b',content))
                    ioc_types["Domains"] += len(_re_ios.findall(r'\b[a-zA-Z0-9.-]+\.[a-zA-Z]{2,}\b',content))
                    ioc_types["Email"] += len(_re_ios.findall(r'[a-zA-Z0-9_.+-]+@[a-zA-Z0-9-]+\.[a-zA-Z]{2,}',content))
                    ioc_types["Hash"] += len(_re_ios.findall(r'\b[0-9a-fA-F]{32,64}\b',content))
                    ioc_types["URL"] += len(_re_ios.findall(r'https?://[^\s"\']+',content))
                except: pass
        _ios_out.insert(tk.END, "\n  IOC pattern counts (last 20 log files):\n","HEAD")
        for k,v in ioc_types.items():
            _ios_out.insert(tk.END, f"    {k:<12}","VAL")
            _ios_out.insert(tk.END, f"{v}\n","NUM")
    except: pass
    _ios_out.config(state="disabled")
_mkbtn(_ios_btnrow,"🔄 Refresh",_ios_refresh,C["yellow"])
_ios_refresh()

