def _stup_refresh():
    for row in _stup_tree.get_children(): _stup_tree.delete(row)
    def _do():
        rows = []
        if sys.platform == "win32":
            try:
                import winreg
                _reg_keys = [
                    (winreg.HKEY_LOCAL_MACHINE,
                     r"SOFTWARE\Microsoft\Windows\CurrentVersion\Run","HKLM Run"),
                    (winreg.HKEY_LOCAL_MACHINE,
                     r"SOFTWARE\Microsoft\Windows\CurrentVersion\RunOnce","HKLM RunOnce"),
                    (winreg.HKEY_CURRENT_USER,
                     r"SOFTWARE\Microsoft\Windows\CurrentVersion\Run","HKCU Run"),
                    (winreg.HKEY_CURRENT_USER,
                     r"SOFTWARE\Microsoft\Windows\CurrentVersion\RunOnce","HKCU RunOnce"),
                ]
                for hive, subkey, label in _reg_keys:
                    try:
                        k = winreg.OpenKey(hive, subkey); i = 0
                        while True:
                            try:
                                nm, val, _ = winreg.EnumValue(k, i)
                                rows.append((label, nm, val)); i += 1
                            except OSError: break
                        winreg.CloseKey(k)
                    except Exception: pass
            except ImportError:
                rows.append(("winreg","Not available",""))
        else:
            rows.append(("Linux/Mac","Check /etc/rc.local, crontab, systemd",""))
        import glob
        if sys.platform == "win32":
            startup_dir = os.path.expanduser(
                r"~\AppData\Roaming\Microsoft\Windows\Start Menu\Programs\Startup")
            if os.path.isdir(startup_dir):
                for f in glob.glob(os.path.join(startup_dir,"*")):
                    rows.append(("Startup Folder", os.path.basename(f), f))
        root.after(0, lambda: [_stup_tree.insert("","end",values=r) for r in rows])
    threading.Thread(target=_do, daemon=True).start()
_mkbtn(_stup_ctrl,"🔄 Refresh",_stup_refresh,C["red"])

