_hm_fig_frame = tk.Frame(_tab_heatmap, bg=C["base"]); _hm_fig_frame.pack(fill=tk.BOTH, expand=True, padx=8, pady=4)
def _hm_draw():
    for w in _hm_fig_frame.winfo_children(): w.destroy()
    try:
        import numpy as _np_hm
        categories   = ["EXE","DLL","Script","PDF","Office","Archive","Other"]
        threat_types = ["Clean","Suspicious","Malicious","Unknown"]
        data = [[0]*len(categories) for _ in threat_types]
        has_data = False
        try:
            db_conn = sqlite3.connect(DB_PATH, timeout=3)
            cur_hm  = db_conn.cursor()
            cur_hm.execute(
                "SELECT file, malicious, suspicious, filetype FROM scans LIMIT 2000")
            for fn, mal, sus, ftype in cur_hm.fetchall():
                ext = os.path.splitext(fn or "")[1].lower()
                ft  = (ftype or "").lower()
                if   ".exe" in ext or "exe" in ft:                          ci = 0
                elif ".dll" in ext or "dll" in ft:                          ci = 1
                elif ext in (".js",".py",".vbs",".ps1",".bat",".cmd"):      ci = 2
                elif ".pdf" in ext or "pdf" in ft:                          ci = 3
                elif ext in (".doc",".docx",".xls",".xlsx",".ppt",".pptx"): ci = 4
                elif ext in (".zip",".rar",".7z",".tar",".gz"):             ci = 5
                else:                                                        ci = 6
                mal_i = int(mal or 0); sus_i = int(sus or 0)
                if   mal_i > 0: ti = 2
                elif sus_i > 0: ti = 1
                else:           ti = 0
                data[ti][ci] += 1
                has_data = True
            db_conn.close()
        except Exception as _dbe:
            tk.Label(_hm_fig_frame, text=f"DB error: {_dbe}",
                     font=FS, bg=C["base"], fg=C["red"]).pack(pady=20)
            return
        if not has_data:
            tk.Label(_hm_fig_frame,
                     text="No scan data yet.\nRun some scans first, then click Refresh.",
                     font=(FM[0], 11), bg=C["base"], fg=C["overlay0"]).pack(expand=True)
            return
        fig, ax = plt.subplots(figsize=(7,3.5), facecolor=C["base"])
        ax.set_facecolor(C["mantle"])
        arr = _np_hm.array(data, dtype=float)
        im = ax.imshow(arr, cmap="YlOrRd", aspect="auto")
        ax.set_xticks(range(len(categories)))
        ax.set_xticklabels(categories, fontsize=8, color=C["text"])
        ax.set_yticks(range(len(threat_types)))
        ax.set_yticklabels(threat_types, fontsize=8, color=C["text"])
        for i in range(len(threat_types)):
            for j in range(len(categories)):
                ax.text(j, i, str(int(arr[i,j])), ha="center", va="center",
                        fontsize=9, color="white" if arr[i,j] > 5 else C["overlay0"])
        ax.set_title("Threat Category \u00d7 File Type", color=C["text"], fontsize=9)
        fig.colorbar(im, ax=ax); fig.tight_layout(pad=0.5)
        canvas_hm = FigureCanvasTkAgg(fig, master=_hm_fig_frame)
        canvas_hm.draw(); canvas_hm.get_tk_widget().pack(fill=tk.BOTH, expand=True)
    except Exception as e:
        tk.Label(_hm_fig_frame, text=f"Error rendering heatmap:\n{e}",
                 font=FS, bg=C["base"], fg=C["red"]).pack(pady=20)
_mkbtn(_hm_ctrl,"🔄 Refresh",_hm_draw,C["peach"])
_hm_draw()

