def _shist_refresh():
    for r in _shist_tree.get_children(): _shist_tree.delete(r)
    flt = _shist_flt_v.get().strip().lower(); lim = _shist_lim_v.get()
    def _do():
        rows = []
        try:
            c3 = sqlite3.connect(DB_PATH, timeout=5)
            cur3 = c3.cursor()
            cur3.execute(
                "SELECT timestamp, file, sha256, malicious FROM scans ORDER BY id DESC LIMIT ?",
                (lim,))
            for row in cur3.fetchall():
                if flt and flt not in " ".join(str(x) for x in row).lower(): continue
                rows.append(row)
            c3.close()
        except Exception as e:
            rows.append(("","Error","",str(e)))
        def _show():
            for r in rows:
                v = int(r[3] or 0)
                tag = "MAL" if v > 0 else "CLN"
                _shist_tree.insert("","end",values=r,tags=(tag,) if tag else ())
        root.after(0, _show)
    threading.Thread(target=_do, daemon=True).start()
_mkbtn(_shistctrl,"🔄 Refresh",_shist_refresh,C["green"])
