    def _fchlog(msg, tag="DIM"):
        try:
            fch_txt.config(state="normal")
            fch_txt.insert(_rtk.END, msg+"\n", tag)
            fch_txt.see(_rtk.END)
            fch_txt.config(state="disabled")
        except Exception: pass

    _fchbtn_f = _rtk.Frame(t_check, bg=_PNL2, pady=6, padx=8)
    _fchbtn_f.pack(fill=_rtk.X, side=_rtk.BOTTOM)
    _rtk.Frame(t_check, bg=_BRD, height=1).pack(fill=_rtk.X, side=_rtk.BOTTOM)

    def _run_file_check():
        fch_txt.config(state="normal"); fch_txt.delete("1.0",_rtk.END); fch_txt.config(state="disabled")
        bd = _tcwd[0]
        SCAN_LIST = [
            ("v0rtex.py", "Main script"),
            ("config.json",              "Configuration"),
            ("scan_history.db",          "Scan database"),
            ("whitelist.txt",            "Whitelist"),
            ("notes.txt",                "Notes"),
        ]
        _fchlog("╔─ FILE INTEGRITY SCAN ─────────────────────────────────────╗", "PROMPT")
        ok_c = 0; miss_c = 0
        for fn, desc in SCAN_LIST:
            fp = _ros.path.join(bd, fn)
            if _ros.path.exists(fp):
                sz = _ros.path.getsize(fp)
                _fchlog(f"  ✓  {fn:<32} {sz:>8} B   [{desc}]", "OK")
                ok_c += 1
            else:
                _fchlog(f"  ✗  {fn:<32} MISSING          [{desc}]", "ERR")
                miss_c += 1
        _fchlog("╠─────────────────────────────────────────────────────────────╣", "PROMPT")
        _fchlog(f"  {ok_c} present  ·  {miss_c} missing", "OK" if miss_c==0 else "WARN")
        _fchlog("╚─────────────────────────────────────────────────────────────╝", "PROMPT")
        _sts("file check done", miss_c==0)

    for _bt, _bc, _cmd in [("🔍  Run File Check", _BLU, _run_file_check)]:
        _rtk.Button(_fchbtn_f, text=_bt, command=_cmd, bg=_BRD2, fg=_bc,
                    font=("Consolas",9), relief="flat", padx=10, pady=5,
                    cursor="hand2", bd=0).pack(side=_rtk.LEFT, padx=4)

    rr.after(600, _run_file_check)


