    def _clean_temp_v0rtex():
        try:
            import tempfile as _rtmp, glob as _rgl
            tmp = _rtmp.gettempdir()
            patterns = [
                "v0rtex_fresh_install*.py",
                "v0rtex_trampoline*.py",
                "v0rtex_uninstall_trampoline*.py",
                "v0rtex_reinstall_trampoline*.py",
                "vs_buildtools_setup*.exe",
                "get-pip*.py",
            ]
            removed = 0; errors = []
            for pat in patterns:
                for fp in _rgl.glob(_ros.path.join(tmp, pat)):
                    try: _ros.remove(fp); removed += 1
                    except Exception as _te: errors.append(_ros.path.basename(fp))
            if removed:
                _replog(f">_ Cleaned {removed} V0RTEX file(s) from TEMP.", "OK")
            else:
                _replog(">_ TEMP is already clean — no V0RTEX files found.", "DIM")
            if errors:
                _replog(f"   Could not remove: {', '.join(errors)}", "WARN")
            _sts(f"temp: {removed} removed")
        except Exception as e: _replog(f">_ Error: {e}", "ERR")

    def _reset_scan_db():
        try:
            import sqlite3 as _rsq; bd = _tcwd[0]
            db = _ros.path.join(bd, "scan_history.db")
            if _ros.path.exists(db):

                try:
                    import __main__ as _mm
                    _gc = getattr(_mm, "_conn", None)
                    if _gc is not None:
                        try: _gc.close()
                        except Exception: pass
                        _mm._conn = None
                except Exception: pass

                try:
                    _gc2 = globals().get("_conn")
                    if _gc2 is not None:
                        try: _gc2.close()
                        except Exception: pass
                except Exception: pass
                import time as _rwt; _rwt.sleep(0.15)
                try:
                    _ros.remove(db)
                except OSError as _oe:

                    _tmp = db + ".old"
                    try: _ros.rename(db, _tmp)
                    except Exception: raise _oe
            conn = _rsq.connect(db)
            conn.execute("""CREATE TABLE IF NOT EXISTS scans (
                file TEXT, md5 TEXT, sha1 TEXT, sha256 TEXT,
                malicious INTEGER DEFAULT 0, suspicious INTEGER DEFAULT 0,
                undetected INTEGER DEFAULT 0,
                yara_hits TEXT DEFAULT '[]', pe_info TEXT DEFAULT '{}',
                iocs TEXT DEFAULT '{}', entropy REAL DEFAULT 0.0,
                filetype TEXT DEFAULT 'Unknown', timestamp TEXT DEFAULT '')""")
            conn.commit(); conn.close()

            try:
                import __main__ as _mm2, sqlite3 as _rsq2
                _mm2._conn = _rsq2.connect(db, check_same_thread=False)
                _mm2._conn.execute("PRAGMA journal_mode=WAL")
            except Exception: pass
            _replog(">_ scan_history.db reset — schema recreated.", "OK")
            _sts("db reset")
        except Exception as e: _replog(f">_ DB error: {e}", "ERR")

