    _rtk.Label(_test_row, text="Entry point:", font=("Consolas",8),
               bg=_PNL2, fg=_DIM2).pack(side=_rtk.LEFT, padx=(4,2))
    _test_entry_menu = _rtk.OptionMenu(_test_row, _test_entry_var, *_TEST_ENTRIES)
    _test_entry_menu.config(bg=_BRD2, fg=_MAU, font=("Consolas",8),
                            relief="flat", bd=0, activebackground=_BRD2,
                            highlightthickness=0, cursor="hand2")
    _test_entry_menu["menu"].config(bg=_BRD2, fg=_MAU, font=("Consolas",8))
