    def _launch_test_application():
        import threading as _ttest, subprocess as _sptest
        import datetime as _dttest
        entry = _test_entry_var.get()
        log_dir = _ros.path.join(_ros.path.dirname(_ros.path.abspath(_rsys.argv[0])), "debug_log")
        _ros.makedirs(log_dir, exist_ok=True)
        ts = _dttest.datetime.now().strftime("%Y%m%d_%H%M%S")
        log_path = _ros.path.join(log_dir, f"TEST_APPLICATION_{entry}_{ts}.txt")

        script = _ros.path.abspath(_rsys.argv[0])
        if entry == "main":
            args = [_rsys.executable, script]
        elif entry == "setup":
            args = [_rsys.executable, script, "--setup"]
        elif entry == "recovery":
            args = [_rsys.executable, script, "--v0rtex-recovery-direct"]
        else:
            args = [_rsys.executable, script]

        _rec_log_admin(f"TEST_APPLICATION launched — entry={entry} — log={log_path}")
        _replog(f">_ TEST_APPLICATION: entry={entry}", "INFO")
        _replog(f">_ Logging to: {log_path}", "DIM")

        _tw = _rtk.Toplevel(rr)
        _tw.title(f"TEST_APPLICATION  [{entry}]  — {ts}")
        _tw.configure(bg="#06060f")
        _tw.geometry("860x540")
        try: _tw.attributes("-topmost", True)
        except Exception: pass

        _tw_hdr = _rtk.Frame(_tw, bg="#080816", pady=5, padx=12); _tw_hdr.pack(fill=_rtk.X)
        _rtk.Label(_tw_hdr, text=f"  🧪  TEST_APPLICATION  ›  entry: {entry}",
                   font=("Consolas",10,"bold"), bg="#080816", fg=_MAU).pack(side=_rtk.LEFT)
        _tw_sts_sv = _rtk.StringVar(value="● RUNNING")
        _rtk.Label(_tw_hdr, textvariable=_tw_sts_sv,
                   font=("Consolas",8,"bold"), bg="#080816", fg=_GRN2).pack(side=_rtk.RIGHT, padx=8)
        _rtk.Frame(_tw, bg=_MAU, height=1).pack(fill=_rtk.X)

        _tw_sc = _rtk.Scrollbar(_tw, orient="vertical", bg="#16162a",
                                 troughcolor="#06060f", relief="flat", bd=0, width=6)
        _tw_sc.pack(side=_rtk.RIGHT, fill=_rtk.Y)
        _tw_txt = _rtk.Text(_tw, bg="#0b0b1a", fg="#cdd6f4", font=("Consolas",9),
                             relief="flat", bd=0, padx=12, pady=8,
                             wrap="word", state="disabled",
                             yscrollcommand=_tw_sc.set)
        _tw_sc.config(command=_tw_txt.yview)
        _tw_txt.pack(fill=_rtk.BOTH, expand=True)
        for _tg, _cl in [("OK","#00ff88"),("ERR","#f38ba8"),("WARN","#f9e2af"),
                          ("INFO","#89b4fa"),("DIM","#45475a")]:
            _tw_txt.tag_configure(_tg, foreground=_cl)

        _rtk.Frame(_tw, bg="#16162a", height=1).pack(fill=_rtk.X, side=_rtk.BOTTOM)
        _tw_bot = _rtk.Frame(_tw, bg="#080816", pady=6, padx=12); _tw_bot.pack(fill=_rtk.X, side=_rtk.BOTTOM)
        _tw_logpath_sv = _rtk.StringVar(value=f"log: {_ros.path.basename(log_path)}")
        _rtk.Label(_tw_bot, textvariable=_tw_logpath_sv,
                   font=("Consolas",7), bg="#080816", fg="#363653").pack(side=_rtk.LEFT)

        def _tw_copy():
            try:
                _tw.clipboard_clear()
                _tw.clipboard_append(_tw_txt.get("1.0", _rtk.END).strip())
                _tw_sts_sv.set("✓ COPIED")
                _tw.after(1200, lambda: _tw_sts_sv.set("● DONE"))
            except Exception: pass

        _rtk.Button(_tw_bot, text="⎘  Copy Output",
                    command=_tw_copy, bg="#16162a", fg=_MAU,
                    font=("Consolas",9), relief="flat", padx=10, pady=4,
                    cursor="hand2", bd=0).pack(side=_rtk.RIGHT, padx=4)
        _rtk.Button(_tw_bot, text="📁  Open Log",
                    command=lambda: _ros.startfile(log_path) if _rsys.platform=="win32" else None,
                    bg="#16162a", fg=_DIM2,
                    font=("Consolas",9), relief="flat", padx=10, pady=4,
                    cursor="hand2", bd=0).pack(side=_rtk.RIGHT, padx=2)

        def _tw_write(msg, tag="DIM"):
            try:
                _tw_txt.config(state="normal")
                _tw_txt.insert(_rtk.END, msg+"\n", tag)
                _tw_txt.see(_rtk.END)
                _tw_txt.config(state="disabled")
            except Exception: pass

        _proc_ref = [None]

        def _kill_proc():
            p = _proc_ref[0]
            if p and p.poll() is None:
                try: p.kill()
                except Exception: pass
                _tw_sts_sv.set("✗ KILLED")
        _rtk.Button(_tw_bot, text="⛔  Kill",
                    command=_kill_proc, bg="#1a0612", fg=_RED,
                    font=("Consolas",9,"bold"), relief="flat", padx=10, pady=4,
                    cursor="hand2", bd=0).pack(side=_rtk.RIGHT, padx=4)

        def _runner():
            import datetime as _dtrun
            header = (
                f"V0RTEX TEST_APPLICATION\n"
                f"Entry point : {entry}\n"
                f"Script      : {script}\n"
                f"Started     : {_dtrun.datetime.now().isoformat()}\n"
                f"Command     : {' '.join(args)}\n"
                f"{'='*72}\n\n"
            )
            with open(log_path, "w", encoding="utf-8", errors="replace") as _lf:
                _lf.write(header)

            rr.after(0, lambda: _tw_write(header.strip(), "INFO"))

            try:
                import subprocess as _sprun
                proc = _sprun.Popen(
                    args,
                    stdout=_sprun.PIPE, stderr=_sprun.STDOUT,
                    text=True, encoding="utf-8", errors="replace",
                    bufsize=1
                )
                _proc_ref[0] = proc
                with open(log_path, "a", encoding="utf-8", errors="replace") as _lf2:
                    for line in proc.stdout:
                        line = line.rstrip("\n")
                        _lf2.write(line + "\n")
                        _lf2.flush()
                        tag = ("ERR" if any(k in line.upper() for k in
                               ["ERROR","CRASH","EXCEPT","TRACEBACK","FATAL"])
                               else "WARN" if any(k in line.upper() for k in
                               ["WARN","MISSING","FAIL"])
                               else "OK" if any(k in line.upper() for k in
                               ["OK","READY","DONE","SUCCESS"])
                               else "DIM")
                        rr.after(0, (lambda l=line, t=tag: _tw_write(l, t)))
                rc = proc.wait()
                footer = f"\n{'='*72}\nProcess exited — return code: {rc}\n"
                with open(log_path, "a", encoding="utf-8", errors="replace") as _lf3:
                    _lf3.write(footer)
                rr.after(0, lambda: _tw_write(footer.strip(),
                                              "OK" if rc == 0 else "WARN"))
                rr.after(0, lambda: _tw_sts_sv.set(
                    f"● EXIT {rc}" if rc != 0 else "✓ EXIT 0"))
                _rec_log_admin(f"TEST_APPLICATION finished — entry={entry} rc={rc}")
                _replog(f">_ TEST_APPLICATION [{entry}] finished — rc={rc}",
                        "OK" if rc == 0 else "WARN")
            except Exception as _te:
                msg = f"TEST_APPLICATION error: {_te}"
                rr.after(0, lambda: _tw_write(msg, "ERR"))
                rr.after(0, lambda: _tw_sts_sv.set("✗ ERROR"))
                with open(log_path, "a", encoding="utf-8", errors="replace") as _lfe:
                    _lfe.write(f"\nERROR: {_te}\n")

        import threading as _ttest2
        _ttest2.Thread(target=_runner, daemon=True).start()

