    def _diag_sysinfo():
        import platform as _pl, shutil as _sh
        _dglog("", "DIM")
        _dglog("╔─ SYSTEM INFO ──────────────────────────────────────────────╗", "PROMPT")
        _dglog(f"  OS        : {_pl.system()} {_pl.release()} ({_pl.machine()})", "INFO")
        _dglog(f"  Python    : {_rsys.version.split()[0]}  [{_rsys.executable}]", "INFO")
        _dglog(f"  App dir   : {_tcwd[0]}", "INFO")
        _dglog(f"  PID       : {_ros.getpid()}", "INFO")
        try:
            disk = _sh.disk_usage(_tcwd[0])
            used_pct = disk.used / disk.total * 100
            color = "ERR" if used_pct > 90 else "WARN" if used_pct > 75 else "OK"
            _dglog(f"  Disk      : {disk.free//1024//1024} MB free / "
                   f"{disk.total//1024//1024} MB total  ({used_pct:.1f}% used)", color)
        except Exception as _de: _dglog(f"  Disk      : error — {_de}", "WARN")
        try:
            import psutil as _dps
            proc  = _dps.Process()
            ram_mb = proc.memory_info().rss / 1024 / 1024
            cpu_pct = _dps.cpu_percent(interval=0.3)
            ram_sys = _dps.virtual_memory()
            _dglog(f"  CPU       : {cpu_pct:.1f}%", "INFO")
            _dglog(f"  App RAM   : {ram_mb:.1f} MB", "INFO")
            _dglog(f"  Sys RAM   : {ram_sys.percent:.1f}% used  ({ram_sys.available//1024//1024} MB free)", "INFO")
        except Exception: _dglog("  RAM/CPU   : psutil not available", "WARN")
        _dglog("╚─────────────────────────────────────────────────────────────╝", "PROMPT")
        _sts("sysinfo ok")

    def _diag_deps():
        _dglog("", "DIM")
        _dglog("╔─ DEPENDENCY CHECK ─────────────────────────────────────────╗", "PROMPT")
        DEPS = [
            ("tkinter",       "tkinter"),
            ("requests",      "requests"),
            ("psutil",        "psutil"),
            ("yara",          "yara-python"),
            ("pefile",        "pefile"),
            ("sqlite3",       "built-in"),
            ("zipfile",       "built-in"),
            ("cryptography",  "cryptography"),
            ("PIL",           "Pillow"),
            ("matplotlib",    "matplotlib"),
            ("tkinterdnd2",   "tkinterdnd2"),
            ("reportlab",     "reportlab"),
            ("fpdf",          "fpdf2"),
        ]
        ok_c = 0; miss_c = 0
        for mod, pkg in DEPS:
            try:
                __import__(mod)
                _dglog(f"  ✓  {mod:<20} [{pkg}]", "OK"); ok_c += 1
            except ImportError:
                _dglog(f"  ✗  {mod:<20} [{pkg}]  ← pip install {pkg}", "ERR"); miss_c += 1
        _dglog(f"  ─  {ok_c} ok  ·  {miss_c} missing", "OK" if miss_c == 0 else "WARN")
        _dglog("╚─────────────────────────────────────────────────────────────╝", "PROMPT")
        _sts(f"deps: {miss_c} missing", miss_c == 0)

    def _diag_db():
        _dglog("", "DIM")
        _dglog("╔─ DATABASE CHECK ───────────────────────────────────────────╗", "PROMPT")
        db = _ros.path.join(_tcwd[0], "scan_history.db")
        if not _ros.path.exists(db):
            _dglog("  ✗  scan_history.db not found.", "ERR")
            _dglog("╚─────────────────────────────────────────────────────────────╝", "PROMPT")
            return
        try:
            import sqlite3 as _sq
            sz = _ros.path.getsize(db)
            _dglog(f"  ·  File size : {sz//1024} KB", "DIM")
            conn = _sq.connect(db, timeout=5)
            ic = conn.execute("PRAGMA integrity_check").fetchone()[0]
            _dglog(f"  ·  Integrity : {ic}", "OK" if ic == "ok" else "ERR")
            tables = [r[0] for r in conn.execute("SELECT name FROM sqlite_master WHERE type='table'").fetchall()]
            _dglog(f"  ·  Tables    : {', '.join(tables) if tables else 'none'}", "INFO")
            for tbl in tables:
                try:
                    cnt = conn.execute(f"SELECT COUNT(*) FROM [{tbl}]").fetchone()[0]
                    _dglog(f"       {tbl}: {cnt} rows", "DIM")
                except Exception: pass
            conn.close()
        except Exception as _dbe: _dglog(f"  ✗  DB error: {_dbe}", "ERR")
        _dglog("╚─────────────────────────────────────────────────────────────╝", "PROMPT")
        _sts("db check done")

    def _diag_rules():
        _dglog("", "DIM")
        _dglog("╔─ YARA RULES ───────────────────────────────────────────────╗", "PROMPT")
        import glob as _gl3
        rules_dir = _ros.path.join(_tcwd[0], "rules")
        ext_dir   = _ros.path.join(rules_dir, "external")
        for d, label in [(rules_dir, "rules/"), (ext_dir, "rules/external/")]:
            if _ros.path.isdir(d):
                yar = _gl3.glob(_ros.path.join(d, "*.yar")) + _gl3.glob(_ros.path.join(d, "*.yara"))
                _dglog(f"  ·  {label:<22} {len(yar)} file(s)", "OK" if yar else "WARN")
                for f in yar[:6]:
                    sz = _ros.path.getsize(f)
                    _dglog(f"       {_ros.path.basename(f):<36} {sz} B", "DIM")
                if len(yar) > 6: _dglog(f"       ... and {len(yar)-6} more", "DIM")
            else:
                _dglog(f"  ✗  {label} directory missing", "ERR")
        rs = _ros.path.join(rules_dir, "rules_state.json")
        _dglog(f"  ·  rules_state.json : {'present' if _ros.path.exists(rs) else 'MISSING'}", 
               "OK" if _ros.path.exists(rs) else "ERR")
        _dglog("╚─────────────────────────────────────────────────────────────╝", "PROMPT")
        _sts("rules check done")

    def _diag_apikeys():
        _dglog("", "DIM")
        _dglog("╔─ API KEYS ─────────────────────────────────────────────────╗", "PROMPT")
        try:
            import json as _rj2
            cfg_p = _ros.path.join(_tcwd[0], "config.json")
            if not _ros.path.exists(cfg_p):
                _dglog("  ✗  config.json not found", "ERR")
            else:
                cfg = _rj2.loads(open(cfg_p, encoding="utf-8").read())
                keys = cfg.get("api_keys", [])
                _dglog(f"  ·  API keys in config : {len(keys)}", "OK" if keys else "WARN")
                for i, k in enumerate(keys):
                    masked = str(k)[:6] + "****" + str(k)[-4:] if len(str(k)) > 10 else "****"
                    _dglog(f"       [{i+1}] {masked}", "DIM")
                proxy = cfg.get("proxy","")
                _dglog(f"  ·  Proxy             : {proxy if proxy else '(none)'}", "DIM")
                theme = cfg.get("theme","?")
                _dglog(f"  ·  Theme             : {theme}", "DIM")
        except Exception as _ae: _dglog(f"  ✗  Error: {_ae}", "ERR")
        _dglog("╚─────────────────────────────────────────────────────────────╝", "PROMPT")
        _sts("api key check done")

    def _diag_processes():
        _dglog("", "DIM")
        _dglog("╔─ RUNNING PROCESSES (python) ───────────────────────────────╗", "PROMPT")
        try:
            import psutil as _dps2
            found = []
            for p in _dps2.process_iter(["pid","name","exe","cmdline"]):
                try:
                    nm = (p.info.get("name") or "").lower()
                    cmd = " ".join(p.info.get("cmdline") or []).lower()
                    if "python" in nm or "malware_lab" in cmd:
                        found.append(p)
                except Exception: pass
            if found:
                for p in found:
                    try:
                        tag = "WARN" if p.pid == _ros.getpid() else "DIM"
                        _dglog(f"  PID {p.pid:>6}  {(p.info.get('name') or ''):<20}"
                               f"  {'← THIS PROCESS' if p.pid == _ros.getpid() else ''}", tag)
                    except Exception: pass
            else:
                _dglog("  (no matching processes found)", "DIM")
        except ImportError:
            _dglog("  ✗  psutil not installed — cannot list processes", "ERR")
        except Exception as _pe: _dglog(f"  ✗  Error: {_pe}", "ERR")
        _dglog("╚─────────────────────────────────────────────────────────────╝", "PROMPT")

    def _diag_all():
        diag_txt.config(state="normal"); diag_txt.delete("1.0",_rtk.END)
        diag_txt.config(state="disabled")
        _diag_sysinfo(); _diag_deps(); _diag_db(); _diag_rules()
        _diag_apikeys(); _diag_processes()
        _sts("full diagnostics done")

    def _diag_pip_install():
        """Install all requirements with real-time output and multiple fallback strategies."""
        req = None
        for _rname in ("requirements.txt", "requirments.txt"):
            _rp = _ros.path.join(_tcwd[0], _rname)
            if _ros.path.exists(_rp):
                req = _rp
                break
        if req is None:
            _dglog(">_ requirements.txt not found in app directory.", "ERR")
            return

        import threading as _dth, subprocess as _dsp

        _RTRSTED = [
            "--trusted-host", "pypi.org",
            "--trusted-host", "files.pythonhosted.org",
            "--trusted-host", "pypi.python.org",
        ]

        def _rlog(msg, tag="DIM"):
            try: rr.after(0, lambda m=msg, t=tag: _dglog(m, t))
            except Exception: pass

        def _stream_pip(cmd, label):
            """Run a pip command and stream output line-by-line. Returns returncode."""
            _rlog(f">_ {label}: {' '.join(cmd[2:5])}…", "PROMPT")
            try:
                proc = _dsp.Popen(cmd, stdout=_dsp.PIPE, stderr=_dsp.STDOUT,
                                  text=True, bufsize=1)
                for line in iter(proc.stdout.readline, ""):
                    line = line.rstrip()
                    if not line:
                        continue
                    if "Successfully installed" in line:
                        _rlog(f"  ✓ {line}", "OK")
                    elif "Requirement already satisfied" in line:
                        pkg = line.split(":")[1].strip().split()[0] if ":" in line else ""
                        _rlog(f"  · already ok: {pkg}", "DIM")
                    elif line.startswith("Collecting"):
                        _rlog(f"  ↓ {line}", "INFO")
                    elif "error" in line.lower() or line.startswith("ERROR"):
                        _rlog(f"  ✗ {line}", "ERR")
                    elif line.startswith("WARNING"):
                        _rlog(f"  ⚠ {line}", "WARN")
                    else:
                        _rlog(f"  {line}", "DIM")
                proc.wait()
                return proc.returncode
            except FileNotFoundError:
                _rlog(f"  ✗ {cmd[0]!r} not found", "ERR")
                return 127
            except Exception as _se:
                _rlog(f"  ✗ stream error: {_se}", "ERR")
                return 1

        def _pip_one_pkg(pkg):
            """Try multiple strategies for a single package. Returns True on success."""
            pname = pkg.split(">=")[0].split("==")[0].split("[")[0].strip()
            strategies = [
                ([_rsys.executable, "-m", "pip", "install", pkg,
                  "--prefer-binary", "--no-cache-dir", "-q"] + _RTRSTED,
                 f"binary wheel"),
                ([_rsys.executable, "-m", "pip", "install", pkg,
                  "--user", "--prefer-binary", "--no-cache-dir", "-q"] + _RTRSTED,
                 f"--user"),
                ([_rsys.executable, "-m", "pip", "install", pkg,
                  "--no-cache-dir", "-q"] + _RTRSTED,
                 f"plain"),
            ]
            for cmd, label in strategies:
                try:
                    r = _dsp.run(cmd, capture_output=True, text=True, timeout=180)
                    if r.returncode == 0:
                        _rlog(f"  ✓ {pname} ({label})", "OK")
                        return True
                except Exception:
                    pass
            _rlog(f"  ✗ {pname} — all strategies failed", "ERR")
            return False

        def _bootstrap_pip_diag():
            ck = _dsp.run([_rsys.executable, "-m", "pip", "--version"],
                          capture_output=True, text=True)
            if ck.returncode == 0 and "No module named pip" not in (ck.stderr + ck.stdout):
                return True
            _rlog("  ~ pip not found — bootstrapping…", "WARN")
            try:
                import ensurepip as _ep3; _ep3.bootstrap(upgrade=True)
                if _dsp.run([_rsys.executable, "-m", "pip", "--version"],
                            capture_output=True, text=True).returncode == 0:
                    _rlog("  ✓ pip ready (ensurepip)", "OK"); return True
            except Exception: pass
            _dsp.run([_rsys.executable, "-m", "ensurepip", "--upgrade"],
                     capture_output=True, text=True)
            if _dsp.run([_rsys.executable, "-m", "pip", "--version"],
                        capture_output=True, text=True).returncode == 0:
                _rlog("  ✓ pip ready (ensurepip subprocess)", "OK"); return True
            import tempfile as _tmp3, os as _tos3
            _gp2 = _tos3.path.join(_tmp3.gettempdir(), "get-pip.py")
            for _url2 in ["https://bootstrap.pypa.io/get-pip.py",
                          "https://bootstrap.pypa.io/pip/get-pip.py"]:
                try:
                    import urllib.request as _ur3
                    _ur3.urlretrieve(_url2, _gp2)
                    if _tos3.path.getsize(_gp2) > 1000:
                        _dsp.run([_rsys.executable, _gp2, "--quiet"] + _RTRSTED,
                                 capture_output=True, text=True)
                        if _dsp.run([_rsys.executable, "-m", "pip", "--version"],
                                    capture_output=True, text=True).returncode == 0:
                            _rlog("  ✓ pip installed (get-pip.py)", "OK"); return True
                        break
                except Exception: pass
            _rlog("  ✗ pip bootstrap failed.", "ERR"); return False

        def _w():
            _rlog("", "DIM")
            _rlog("╔─ PIP INSTALL ───────────────────────────────────────────────╗", "PROMPT")
            _rlog(f"  requirements: {req}", "DIM")

            if not _bootstrap_pip_diag():
                _rlog("╚─────────────────────────────────────────────────────────────╝", "PROMPT")
                return

            cmd_bulk = [_rsys.executable, "-m", "pip", "install", "-r", req,
                        "--prefer-binary", "--no-cache-dir", "-q",
                        "--progress-bar", "off"] + _RTRSTED
            rc = _stream_pip(cmd_bulk, "bulk install")

            if rc == 0:
                _rlog("  ✓ All packages installed successfully.", "OK")
                _sts("pip install ok")
            else:
                _rlog("  ~ Bulk install incomplete — switching to per-package mode…", "WARN")

                try:
                    with open(req, encoding="utf-8", errors="replace") as _rf:
                        pkgs = [l.strip() for l in _rf if l.strip()
                                and not l.strip().startswith("#")]
                except Exception as _re:
                    _rlog(f"  ✗ Cannot read requirements: {_re}", "ERR")
                    pkgs = []

                failed = []
                for pkg in pkgs:
                    ok = _pip_one_pkg(pkg)
                    if not ok:
                        pname = pkg.split(">=")[0].split("==")[0].strip()
                        failed.append(pname)

                if failed:
                    _rlog(f"  ⚠ Still missing after all attempts: {', '.join(failed)}", "WARN")
                    _rlog("  → Try running the app as Administrator, or check your network.", "DIM")
                    _sts(f"pip: {len(failed)} failed", ok=False)
                else:
                    _rlog("  ✓ All packages installed via per-package fallback.", "OK")
                    _sts("pip install ok")

            _rlog("╚─────────────────────────────────────────────────────────────╝", "PROMPT")

        _dth.Thread(target=_w, daemon=True).start()

