    def _cln_scan_history():
        from tkinter import messagebox as _mb4
        ok = _mb4.askyesno("Confirm",
            "WIPE all scan history records from scan_history.db?\n"
            "The database file itself will be kept with its schema.", parent=rr)
        if not ok: return
        try:
            import sqlite3 as _sq2
            db = _ros.path.join(_tcwd[0], "scan_history.db")
            if not _ros.path.exists(db):
                _clnlog(">_ scan_history.db not found.", "WARN"); return
            conn = _sq2.connect(db, timeout=5)
            tables = [r[0] for r in conn.execute(
                "SELECT name FROM sqlite_master WHERE type='table'").fetchall()]
            deleted = 0
            for t in tables:
                try:
                    cnt = conn.execute(f"SELECT COUNT(*) FROM [{t}]").fetchone()[0]
                    conn.execute(f"DELETE FROM [{t}]")
                    deleted += cnt
                except Exception: pass
            conn.execute("VACUUM")
            conn.commit(); conn.close()
            _clnlog(f">_ Scan history wiped: {deleted} record(s) removed.", "OK")
            _sts("scan history wiped")
        except Exception as _se: _clnlog(f">_ Error: {_se}", "ERR")

