    def _restart():
        _sts("restarting...")
        _rec_log_admin(f"Restart requested — admin={_REC_IS_ADMIN[0]}")
        _keep = False
        try:
            import json as _rjson
            _cfg_path = _ros.path.join(
                _ros.path.dirname(_ros.path.abspath(_rsys.argv[0])), "config.json")
            with open(_cfg_path, encoding="utf-8") as _rcf:
                _keep = _rjson.load(_rcf).get("restart_keep_admin", False)
        except Exception:
            pass
        if _REC_IS_ADMIN[0] and not _keep:
            _rec_log_admin("Admin active but restart_keep_admin=False — restarting WITHOUT admin")
            _restart_without_admin()
            return
        try:
            rr.after(600, lambda: (
                rr.destroy(),
                _ros.execv(_rsys.executable, [_rsys.executable] + _rsys.argv)
            ))
        except Exception:
            try: rr.destroy()
            except Exception: pass
            try: _ros.execv(_rsys.executable, [_rsys.executable] + _rsys.argv)
            except Exception: _rsys.exit(0)

    def _restart_as_admin():
        if _rec_is_admin():
            _sts("already admin"); return
        _rec_log_admin("ADMIN REQUESTED — User clicked Run as Administrator in Recovery UI")
        _sts("writing sentinel + requesting UAC...")
        import re as _rere
        _UUID_RE = _rere.compile(r';[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$', _rere.IGNORECASE)
        _raw_file = _ros.path.abspath(__file__)
        _script_clean = _UUID_RE.sub('', _raw_file)
        _sent_dir = _ros.path.dirname(_script_clean)
        _sent_path = _ros.path.join(_sent_dir, "Recovery_As_Admin")
        _rec_log_admin(f"__file__={_raw_file}  script_clean={_script_clean}  sentinel={_sent_path}")
        try:
            import json as _rjsent, datetime as _dtsen
            _crash_ctx = {}
            if exc_type is not None:
                _crash_ctx["exc_type_name"] = exc_type.__name__ if hasattr(exc_type, "__name__") else str(exc_type)
                _crash_ctx["exc_val"] = str(exc_val)
                _crash_ctx["tb_str"] = tb_str or ""
            if missing_files:
                _crash_ctx["missing_files"] = list(missing_files)
            with open(_sent_path, "w", encoding="utf-8") as _sf:
                _rjsent.dump({
                    "requested_at": _dtsen.datetime.now().isoformat(),
                    "pid": _ros.getpid(),
                    "script": _script_clean,
                    "reason": "admin relaunch from Recovery UI",
                    "crash_ctx": _crash_ctx
                }, _sf, indent=2)
            _rec_log_admin(f"Sentinel written OK: {_sent_path}")
        except Exception as _we:
            _sts(f"sentinel error: {_we}", ok=False)
            _rec_log_admin(f"Sentinel write FAILED: {_we}")
            return
        try:
            if _rsys.platform == "win32":
                import ctypes as _rct2
                ret = _rct2.windll.shell32.ShellExecuteW(
                    None, "runas", _rsys.executable, f'"{_script_clean}"', None, 1)
                _rec_log_admin(f"ShellExecuteW returned {ret} (>32 = success)")
                if ret > 32:
                    rr.after(800, _exit_clean)
                else:
                    try: _ros.remove(_sent_path)
                    except Exception: pass
                    _sts("UAC denied", ok=False)
                    _rec_log_admin(f"UAC denied — sentinel removed — ret={ret}")
            else:
                import subprocess as _rsp3
                _rsp3.Popen(["sudo", _rsys.executable, _script_clean])
                rr.after(800, _exit_clean)
        except Exception as _ae:
            try: _ros.remove(_sent_path)
            except Exception: pass
            _sts(f"admin error: {_ae}", ok=False)
            _rec_log_admin(f"Admin relaunch error: {_ae}")

    def _restart_without_admin():
        _rec_log_admin("RESTART APPLICATION requested (no admin)")
        _sts("restarting application...")
        import re as _rere3
        _UUID_RE3 = _rere3.compile(r';[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$', _rere3.IGNORECASE)
        _script = _UUID_RE3.sub('', _ros.path.abspath(__file__))
        try:
            if _rsys.platform == "win32":
                import subprocess as _rsp4
                _rsp4.Popen([_rsys.executable, _script])
                rr.after(400, _exit_clean)
            else:
                rr.after(400, lambda: (
                    rr.destroy(),
                    _ros.execv(_rsys.executable, [_rsys.executable, _script])
                ))
        except Exception as _re2:
            _sts(f"restart error: {_re2}", ok=False)
            _rec_log_admin(f"Restart without admin error: {_re2}")

    def _exit_clean():
        try: _WATCHDOG_SUPPRESS.clear()
        except Exception: pass
        _rec_log_admin("Recovery UI — EXIT APPLICATION")
        try: rr.after(200, lambda: _rsys.exit(0))
        except Exception: _rsys.exit(0)



