    def _build_defender_tab(frame):
        import subprocess as _rspdef, threading as _tdef
        _df, dlog = _make_log(frame)
        _df.pack(fill=_rtk.BOTH, expand=True)
        _dbf = _rtk.Frame(frame, bg=_PNL2, pady=6, padx=8)
        _dbf.pack(fill=_rtk.X, side=_rtk.BOTTOM)
        _rtk.Frame(frame, bg="#ff3366", height=1).pack(fill=_rtk.X, side=_rtk.BOTTOM)
        _rtk.Label(_dbf, text="  ⚠ DANGER_ADMIN_PERMISSION_GRANTED — changes affect Windows Defender system-wide",
                   font=("Consolas",8,"bold"), bg=_PNL2, fg="#ff3366").pack(anchor="w", pady=(0,4))

        def _dlog_w(msg, tag="DIM"):
            try:
                dlog.config(state="normal")
                dlog.insert(_rtk.END, msg+"\n", tag)
                dlog.see(_rtk.END)
                dlog.config(state="disabled")
            except Exception: pass

        def _ps_run(cmd):
            try:
                r = _rspdef.run(["powershell","-NoProfile","-NonInteractive",
                                  "-WindowStyle","Hidden","-Command", cmd],
                                 capture_output=True, text=True, timeout=30)
                return r.stdout.strip(), r.stderr.strip(), r.returncode
            except Exception as e:
                return "", str(e), -1

        def _add_exclusion():
            from tkinter import filedialog as _fddef
            p = _fddef.askdirectory(title="Select folder to exclude from Defender", parent=rr)
            if not p: return
            def _w():
                _dlog_w(f">_ Adding Defender exclusion: {p}", "INFO")
                out, err, rc = _ps_run(f'Add-MpPreference -ExclusionPath "{p}"')
                if rc == 0:
                    _dlog_w(f"  ✓ Exclusion added: {p}", "OK")
                    _rec_log_admin(f"Defender exclusion added: {p}")
                else:
                    _dlog_w(f"  ✗ Failed (rc={rc}): {err}", "ERR")
            _tdef.Thread(target=_w, daemon=True).start()

        def _remove_exclusion():
            from tkinter import simpledialog as _sddef
            p = _sddef.askstring("Remove Exclusion", "Path to remove:", parent=rr)
            if not p: return
            def _w():
                out, err, rc = _ps_run(f'Remove-MpPreference -ExclusionPath "{p}"')
                if rc == 0:
                    _dlog_w(f"  ✓ Exclusion removed: {p}", "OK")
                    _rec_log_admin(f"Defender exclusion removed: {p}")
                else:
                    _dlog_w(f"  ✗ Failed: {err}", "ERR")
            _tdef.Thread(target=_w, daemon=True).start()

        def _list_exclusions():
            def _w():
                _dlog_w(">_ Listing Defender exclusions...", "INFO")
                out, err, rc = _ps_run("(Get-MpPreference).ExclusionPath")
                if rc == 0:
                    lines = [l for l in out.splitlines() if l.strip()]
                    _dlog_w(f"  Found {len(lines)} path exclusion(s):", "OK")
                    for l in lines: _dlog_w(f"    • {l}", "DIM")
                    _rec_log_admin(f"Defender exclusions listed: {len(lines)} found")
                else:
                    _dlog_w(f"  ✗ {err}", "ERR")
            _tdef.Thread(target=_w, daemon=True).start()

        def _disable_realtime():
            if not _rtk.messagebox.askyesno("Confirm", "Disable Defender Real-Time Protection?\n\nThis reduces system security.", parent=rr): return
            def _w():
                out, err, rc = _ps_run("Set-MpPreference -DisableRealtimeMonitoring $true")
                if rc == 0:
                    _dlog_w("  ✓ Real-time protection DISABLED", "WARN")
                    _rec_log_admin("Defender real-time protection disabled")
                else:
                    _dlog_w(f"  ✗ Failed: {err}", "ERR")
            _tdef.Thread(target=_w, daemon=True).start()

        def _enable_realtime():
            def _w():
                out, err, rc = _ps_run("Set-MpPreference -DisableRealtimeMonitoring $false")
                if rc == 0:
                    _dlog_w("  ✓ Real-time protection RE-ENABLED", "OK")
                    _rec_log_admin("Defender real-time protection re-enabled")
                else:
                    _dlog_w(f"  ✗ Failed: {err}", "ERR")
            _tdef.Thread(target=_w, daemon=True).start()

        def _scan_status():
            def _w():
                _dlog_w(">_ Defender status...", "INFO")
                out, err, rc = _ps_run("Get-MpComputerStatus | Select-Object -Property RealTimeProtectionEnabled,AntivirusEnabled,AntispywareEnabled,NISEnabled | Format-List")
                if rc == 0:
                    for l in out.splitlines(): _dlog_w(f"  {l}", "DIM")
                else:
                    _dlog_w(f"  ✗ {err}", "ERR")
            _tdef.Thread(target=_w, daemon=True).start()

        _row_d = _rtk.Frame(_dbf, bg=_PNL2); _row_d.pack(fill=_rtk.X, pady=2)
        for _bt, _bc, _cmd in [
            ("📋  List Exclusions",       _BLU,  _list_exclusions),
            ("➕  Add Folder Exclusion",   _GRN2, _add_exclusion),
            ("➖  Remove Exclusion",       _YEL,  _remove_exclusion),
            ("📊  Defender Status",        _TEA,  _scan_status),
            ("⏸  Disable Real-Time",      _RED,  _disable_realtime),
            ("▶  Re-enable Real-Time",     _GRN2, _enable_realtime),
        ]:
            _rtk.Button(_row_d, text=_bt, command=_cmd, bg=_BRD2, fg=_bc,
                        font=("Consolas",9), relief="flat", padx=10, pady=5,
                        cursor="hand2", bd=0).pack(side=_rtk.LEFT, padx=3)
        _dlog_w("╔─ DEFENDER & EXCLUSIONS (ADMIN) ─────────────────────────────╗", "PROMPT")
        _dlog_w("║  Manage Windows Defender exclusions and real-time protection. ║", "DIM")
        _dlog_w("║  ⚠  DANGER_ADMIN_PERMISSION_GRANTED — all changes are live.  ║", "ERR")
        _dlog_w("╚─────────────────────────────────────────────────────────────╝", "PROMPT")

    def _build_permissions_tab(frame):
        import subprocess as _rspperm, threading as _tperm
        _pf, plog = _make_log(frame)
        _pf.pack(fill=_rtk.BOTH, expand=True)
        _pbf = _rtk.Frame(frame, bg=_PNL2, pady=6, padx=8)
